export enum Role {
  ADMIN = 'admin',
  USER = 'user',
}

export interface User {
  id: string;
  email: string;
  password: string;
  role: Role;
}

export enum GameStatus {
  RUNNING = 'Running',
  FINISHED = 'Finished',
}

export enum PaymentStatus {
  UNPAID = 'Unpaid',
  PAID = 'Paid',
  LOAN = 'Loan',
}

export interface Game {
  id: string;
  date: string; // YYYY-MM-DD
  tableName: string; 
  hourlyRate: number;
  startTime: string; // ISO string
  endTime: string | null; // ISO string
  player1: string;
  player2: string | null;
  winner: string | null; // Name of the winner, or null for draw/not applicable
  status: GameStatus;
  durationSeconds: number | null;
  priceMAD: number | null;
  discountMAD: number;
  finalPriceMAD: number | null;
  paymentStatus: PaymentStatus;
  notes: string | null;
  createdBy: string; // user ID
  modifiedBy: string | null; // user ID
  createdAt: string; // ISO string
  updatedAt: string; // ISO string
}

export interface DailySummary {
  date: string;
  totalPaid: number;
  totalLoan: number;
  totalDiscount: number;
  gameCount: number;
  archivedAt: string;
}

import React, { createContext, useState, ReactNode, useCallback, useEffect } from 'react';
import { Game, GameStatus, DailySummary } from '../types';
import { SEED_GAMES, DEFAULT_HOURLY_RATE } from '../constants';

type SyncStatus = 'idle' | 'syncing' | 'synced' | 'error';

interface GameContextType {
  games: Game[];
  addGame: (newGame: Omit<Game, 'id' | 'createdAt' | 'updatedAt'>) => void;
  updateGame: (gameId: string, updates: Partial<Game>) => void;
  deleteGame: (gameId: string) => void;
  saveDailySummary: (summary: DailySummary) => Promise<void>;
  isLoading: boolean;
  error: string | null;
  syncStatus: SyncStatus;
  sheetUrl: string | null;
  saveSheetUrl: (url: string) => void;
  clearSheetUrl: () => void;
  refetchGames: () => void;
}

export const GameContext = createContext<GameContextType | undefined>(undefined);

const STORAGE_KEY = 'googleSheetWebAppUrl';

export const GameProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [games, setGames] = useState<Game[]>([]);
  const [sheetUrl, setSheetUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  const saveSheetUrl = (url: string) => {
    localStorage.setItem(STORAGE_KEY, url);
    setSheetUrl(url);
  };

  const clearSheetUrl = () => {
    localStorage.removeItem(STORAGE_KEY);
    setSheetUrl(null);
    setGames(SEED_GAMES);
    setError(null);
  };

  const syncToSheet = useCallback(async (action: 'ADD_GAME' | 'UPDATE_GAME' | 'DELETE_GAME' | 'SAVE_SUMMARY', payload: any) => {
    const url = localStorage.getItem(STORAGE_KEY);
    if (!url) return;

    setSyncStatus('syncing');
    try {
      await fetch(url, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action, payload }),
      });
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
    } catch (err) {
      console.error('Sync error:', err);
      setSyncStatus('error');
      setError('Failed to sync data with Google Sheets.');
    }
  }, []);

  const saveDailySummary = useCallback(async (summary: DailySummary) => {
    await syncToSheet('SAVE_SUMMARY', summary);
  }, [syncToSheet]);

  const fetchGamesFromSheet = useCallback(async (url: string) => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await fetch(url);
      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }
      const result = await response.json();
      if (result.success) {
        const typedData = result.data.map((game: any) => ({
          ...game,
          tableName: game.tableName || (game.tableNo ? String(game.tableNo) : 'Unknown'),
          hourlyRate: game.hourlyRate ? Number(game.hourlyRate) : DEFAULT_HOURLY_RATE,
          durationSeconds: game.durationSeconds ? Number(game.durationSeconds) : null,
          priceMAD: game.priceMAD ? Number(game.priceMAD) : null,
          discountMAD: game.discountMAD ? Number(game.discountMAD) : 0,
          finalPriceMAD: game.finalPriceMAD ? Number(game.finalPriceMAD) : null,
          player2: game.player2 || null,
          winner: game.winner || null,
          notes: game.notes || null,
          endTime: game.endTime || null,
          modifiedBy: game.modifiedBy || null,
        }));
        setGames(typedData.sort((a: Game, b: Game) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime()));
      } else {
        throw new Error(result.message || 'Failed to fetch data from Google Sheet.');
      }
    } catch (err: any) {
      console.error('Fetch error:', err);
      setError('Could not connect to Google Sheet. Check the URL and sheet permissions.');
      setGames(SEED_GAMES);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    const storedUrl = localStorage.getItem(STORAGE_KEY);
    setSheetUrl(storedUrl);
    if (storedUrl) {
      fetchGamesFromSheet(storedUrl);
    } else {
      setGames(SEED_GAMES);
      setIsLoading(false);
    }
  }, [fetchGamesFromSheet]);

  const refetchGames = () => {
    if (sheetUrl) {
        fetchGamesFromSheet(sheetUrl);
    }
  };


  const addGame = useCallback((newGameData: Omit<Game, 'id' | 'createdAt' | 'updatedAt'>) => {
    const newGame: Game = {
      ...newGameData,
      id: crypto.randomUUID(),
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };
    setGames(prevGames => [newGame, ...prevGames]);
    syncToSheet('ADD_GAME', newGame);
  }, [syncToSheet]);

  const updateGame = useCallback((gameId: string, updates: Partial<Game>) => {
    let updatedGame: Game | null = null;
    setGames(prevGames =>
      prevGames.map(game => {
        if (game.id === gameId) {
          updatedGame = { ...game, ...updates, updatedAt: new Date().toISOString() };
          return updatedGame;
        }
        return game;
      })
    );
    if (updatedGame) {
      syncToSheet('UPDATE_GAME', updatedGame);
    }
  }, [syncToSheet]);

  const deleteGame = useCallback((gameId: string) => {
    setGames(prevGames => prevGames.filter(game => game.id !== gameId));
    syncToSheet('DELETE_GAME', { id: gameId });
  }, [syncToSheet]);

  return (
    <GameContext.Provider value={{ games, addGame, updateGame, deleteGame, saveDailySummary, isLoading, error, syncStatus, sheetUrl, saveSheetUrl, clearSheetUrl, refetchGames }}>
      {children}
    </GameContext.Provider>
  );
};

import React, { useState, useEffect } from 'react';
import { useGames } from '../hooks/useGames';
import { Button } from './ui/Button';
import { Input } from './ui/Input';
import { CloseIcon } from './icons';
import CodeBlock from './ui/CodeBlock';
import { Card, CardContent } from './ui/Card';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const appsScriptCode = `
const GAME_SHEET = "Games";
const SUMMARY_SHEET = "DailySummaries";

const GAME_HEADERS = [
  "id", "date", "tableName", "hourlyRate", "startTime", "endTime", "player1", "player2", "winner", 
  "status", "durationSeconds", "priceMAD", "discountMAD", "finalPriceMAD", 
  "paymentStatus", "notes", "createdBy", "modifiedBy", "createdAt", "updatedAt"
];

const SUMMARY_HEADERS = [
  "date", "totalPaid", "totalLoan", "totalDiscount", "gameCount", "archivedAt"
];

function ensureSheet(name, headers) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(name);
  if (!sheet) {
    sheet = ss.insertSheet(name);
    sheet.appendRow(headers);
  } else if (sheet.getLastRow() === 0) {
    sheet.appendRow(headers);
  }
  return sheet;
}

function doGet(e) {
  try {
    const sheet = ensureSheet(GAME_SHEET, GAME_HEADERS);
    const data = sheet.getDataRange().getValues();
    const headers = data.shift();

    const result = data.map(row => {
      let obj = {};
      headers.forEach((h, i) => obj[h] = row[i]);
      return obj;
    });

    return ContentService.createTextOutput(JSON.stringify({ success: true, data: result })).setMimeType(ContentService.MimeType.JSON);
  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({ success: false, message: error.message })).setMimeType(ContentService.MimeType.JSON);
  }
}

function doPost(e) {
  try {
    const postData = JSON.parse(e.postData.contents);
    const action = postData.action;
    const payload = postData.payload;

    if (action === 'SAVE_SUMMARY') {
      const sheet = ensureSheet(SUMMARY_SHEET, SUMMARY_HEADERS);
      const row = SUMMARY_HEADERS.map(h => payload[h] || "");
      sheet.appendRow(row);
    } else {
      const sheet = ensureSheet(GAME_SHEET, GAME_HEADERS);
      const idCol = GAME_HEADERS.indexOf('id') + 1;

      if (action === 'ADD_GAME') {
        const row = GAME_HEADERS.map(h => payload[h] || "");
        sheet.appendRow(row);
      } else if (action === 'UPDATE_GAME') {
        const ids = sheet.getRange(2, idCol, Math.max(1, sheet.getLastRow()-1), 1).getValues().flat();
        const idx = ids.indexOf(payload.id);
        if (idx !== -1) {
          const row = GAME_HEADERS.map(h => payload[h] || "");
          sheet.getRange(idx + 2, 1, 1, GAME_HEADERS.length).setValues([row]);
        }
      } else if (action === 'DELETE_GAME') {
        const ids = sheet.getRange(2, idCol, Math.max(1, sheet.getLastRow()-1), 1).getValues().flat();
        const idx = ids.indexOf(payload.id);
        if (idx !== -1) sheet.deleteRow(idx + 2);
      }
    }
    return ContentService.createTextOutput(JSON.stringify({ success: true })).setMimeType(ContentService.MimeType.JSON);
  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({ success: false, message: error.message })).setMimeType(ContentService.MimeType.JSON);
  }
}
`.trim();

const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose }) => {
  const { sheetUrl, saveSheetUrl, clearSheetUrl, refetchGames } = useGames();
  const [urlInput, setUrlInput] = useState(sheetUrl || '');

  useEffect(() => {
    setUrlInput(sheetUrl || '');
  }, [sheetUrl]);

  const handleSave = () => {
    if (urlInput) {
      saveSheetUrl(urlInput);
      onClose();
      setTimeout(refetchGames, 100); 
    }
  };

  const handleDisconnect = () => {
      clearSheetUrl();
      setUrlInput('');
      onClose();
  }

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-background/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-card border rounded-lg shadow-xl w-full max-w-4xl h-[90vh] flex flex-col">
        <div className="flex justify-between items-center p-4 border-b">
          <h2 className="text-lg font-semibold">Google Sheets Integration</h2>
          <Button variant="ghost" size="icon" onClick={onClose}><CloseIcon /></Button>
        </div>

        <div className="p-6 overflow-y-auto space-y-6">
            <div className="space-y-2">
                <h3 className="font-semibold">Connect your Spreadsheet</h3>
                <p className="text-sm text-muted-foreground">
                    Follow the steps below to use a Google Sheet for daily persistent backups. 
                    The app will now also archive daily summaries automatically.
                </p>
            </div>

            <Card>
                <CardContent className="p-4">
                     <div className="flex flex-col md:flex-row gap-4 items-end">
                        <div className="grid w-full items-center gap-1.5">
                            <label htmlFor="sheetUrl" className="text-sm font-medium">Web App URL</label>
                            <Input id="sheetUrl" type="url" placeholder="https://script.google.com/.../exec" value={urlInput} onChange={e => setUrlInput(e.target.value)} />
                        </div>
                        <div className="flex gap-2 w-full md:w-auto">
                            <Button onClick={handleSave} className="w-full">Save & Connect</Button>
                            {sheetUrl && <Button onClick={handleDisconnect} variant="destructive" className="w-full">Disconnect</Button>}
                        </div>
                    </div>
                </CardContent>
            </Card>

            <div className="space-y-4">
                <h3 className="font-semibold text-lg">Setup Instructions</h3>
                <ol className="list-decimal list-inside space-y-4 text-sm">
                    <li>
                        <strong>Prepare Sheet:</strong> Create a new Google Sheet. 
                        No specific tab names are required anymore; the script will create <strong>Games</strong> and <strong>DailySummaries</strong> automatically.
                    </li>
                    <li>
                        <strong>Apps Script:</strong> Go to <strong>Extensions &gt; Apps Script</strong> and paste the code below.
                    </li>
                    <li>
                       <strong>Deploy:</strong> Click <strong>Deploy &gt; New deployment</strong>. 
                       Select <strong>Web app</strong>, Execute as <strong>Me</strong>, and Who has access <strong>Anyone</strong>.
                    </li>
                     <li>
                        <strong>Connect:</strong> Copy the Web App URL and paste it above.
                    </li>
                </ol>
            </div>

             <div>
                <h3 className="font-semibold text-lg mb-2">Apps Script Code</h3>
                <CodeBlock code={appsScriptCode} />
            </div>

        </div>
      </div>
    </div>
  );
};

export default SettingsModal;

import React, { useState, useMemo, useEffect } from 'react';
import { Game, PaymentStatus, GameStatus, DailySummary } from '../types';
import GamesTable from '../components/GamesTable';
import KpiCard from '../components/KpiCard';
import { formatCurrency } from '../lib/utils';
import { Input } from '../components/ui/Input';
import { DollarSignIcon, HashIcon, ClockIcon, AlertTriangle, TrophyIcon, UsersIcon, LoaderCircle } from '../components/icons';
import PrintResumeButton from '../components/PrintResumeButton';
import { useAuth } from '../hooks/useAuth';
import { useGames } from '../hooks/useGames';
import { useBusinessDay } from '../hooks/useBusinessDay';
import UserManagement from '../components/UserManagement';
import AnalyticsCard from '../components/AnalyticsCard';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '../components/ui/Card';
import { Button } from '../components/ui/Button';


const AdminPage: React.FC = () => {
  const { user } = useAuth();
  const { games, updateGame, deleteGame, saveDailySummary, sheetUrl, error: gameError } = useGames();
  const { businessDate, advanceDay } = useBusinessDay();
  const [selectedDate, setSelectedDate] = useState(businessDate);
  const [isArchiving, setIsArchiving] = useState(false);

  useEffect(() => {
    setSelectedDate(businessDate);
  }, [businessDate]);

  const filteredGames = useMemo(() => {
    return games
      .filter(game => game.date === selectedDate)
      .sort((a, b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime());
  }, [games, selectedDate]);

  const dailyStats = useMemo(() => {
    const currentDayGames = games.filter(g => g.date === businessDate);
    const incomePaid = currentDayGames
      .filter(g => g.paymentStatus === PaymentStatus.PAID)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const allTimeLoans = games
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    return {
      totalGames: currentDayGames.length,
      incomePaid,
      loansOutstanding: allTimeLoans,
    };
  }, [games, businessDate]);

    const receiptStats = useMemo(() => {
        return filteredGames.reduce(
            (acc, game) => {
                if (game.paymentStatus === PaymentStatus.PAID) {
                    acc.paid += game.finalPriceMAD || 0;
                }
                if (game.paymentStatus === PaymentStatus.LOAN) {
                    acc.loan += game.finalPriceMAD || 0;
                }
                acc.discount += game.discountMAD || 0;
                return acc;
            },
            { paid: 0, loan: 0, discount: 0 }
        );
    }, [filteredGames]);

  const analyticsData = useMemo(() => {
    const playerStats: { [key: string]: { paid: number; loan: number; wins: number } } = {};

    const addPlayerStat = (player: string | null, key: 'paid' | 'loan', value: number) => {
        if (!player || value <= 0) return;
        if (!playerStats[player]) {
            playerStats[player] = { paid: 0, loan: 0, wins: 0 };
        }
        playerStats[player][key] += value;
    };

    games.forEach(game => {
        if (game.status !== GameStatus.FINISHED || !game.finalPriceMAD) {
            return;
        }

        const { player1, player2, winner, finalPriceMAD, paymentStatus } = game;

        [player1, player2].forEach(p => {
            if (p && !playerStats[p]) {
                playerStats[p] = { paid: 0, loan: 0, wins: 0 };
            }
        });

        if (paymentStatus === PaymentStatus.PAID) {
            const amount = player2 ? finalPriceMAD / 2 : finalPriceMAD;
            addPlayerStat(player1, 'paid', amount);
            addPlayerStat(player2, 'paid', amount);
        } else if (paymentStatus === PaymentStatus.LOAN) {
            let loanee = player1;
            if (player2) {
                if (winner && winner === player1) loanee = player2;
                else if (winner && winner === player2) loanee = player1;
            }
            addPlayerStat(loanee, 'loan', finalPriceMAD);
        }

        if (winner && playerStats[winner]) {
            playerStats[winner].wins += 1;
        }
    });

    const allPlayers = Object.entries(playerStats).map(([name, stats]) => ({ name, ...stats }));
    const topWinners = [...allPlayers].sort((a, b) => b.wins - a.wins).filter(p => p.wins > 0).slice(0, 5);
    const topPaid = [...allPlayers].sort((a, b) => b.paid - a.paid).filter(p => p.paid > 0).slice(0, 5);
    const playersWithLoans = [...allPlayers].sort((a, b) => b.loan - a.loan).filter(p => p.loan > 0);

    return { topWinners, topPaid, playersWithLoans };
  }, [games]);

  const handleAdvanceDay = async () => {
    if (!window.confirm("Are you sure you want to end the current business day? All stats for today will be archived.")) return;

    if (sheetUrl) {
      setIsArchiving(true);
      const summary: DailySummary = {
        date: businessDate,
        totalPaid: receiptStats.paid,
        totalLoan: receiptStats.loan,
        totalDiscount: receiptStats.discount,
        gameCount: filteredGames.length,
        archivedAt: new Date().toISOString()
      };

      try {
        await saveDailySummary(summary);
      } catch (e) {
        console.error("Failed to archive summary", e);
      } finally {
        setIsArchiving(false);
      }
    }

    advanceDay();
  };

  if (!user) return null;

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Admin Dashboard</h1>
          <p className="text-muted-foreground">Club overview for {new Date(businessDate + 'T00:00:00').toDateString()}.</p>
        </div>
        {!sheetUrl && (
          <Badge variant="outline" className="text-amber-500 border-amber-500 bg-amber-500/10">
            <AlertTriangle className="h-3 w-3 mr-1" /> Not connected to Google Sheets
          </Badge>
        )}
      </div>

      {gameError && (
        <div className="p-4 bg-destructive/10 border border-destructive/20 rounded-md text-destructive flex items-center gap-3">
            <AlertTriangle className="h-5 w-5"/>
            <div>
                <h4 className="font-bold">Connection Error</h4>
                <p className="text-sm">{gameError}</p>
            </div>
        </div>
      )}

      <div className="grid gap-4 md:grid-cols-3">
        <KpiCard title="Total Games (Current Day)" value={dailyStats.totalGames.toString()} icon={<HashIcon />} />
        <KpiCard title="Income (Current Day)" value={`${dailyStats.incomePaid.toFixed(2)} MAD`} icon={<DollarSignIcon />} />
        <KpiCard title="Total Loans Outstanding" value={`${dailyStats.loansOutstanding.toFixed(2)} MAD`} icon={<ClockIcon />} />
      </div>

      <Card>
          <CardHeader>
              <CardTitle>Daily Receipt for {new Date(selectedDate + 'T00:00:00').toDateString()}</CardTitle>
              <CardDescription>A summary of financial activity for the selected date.</CardDescription>
          </CardHeader>
          <CardContent className="grid gap-4 text-sm md:grid-cols-3">
              <div className="flex items-center justify-between p-3 border rounded-md bg-background">
                  <span className="text-muted-foreground">Income (Paid):</span>
                  <span className="font-bold text-green-600">{formatCurrency(receiptStats.paid)}</span>
              </div>
              <div className="flex items-center justify-between p-3 border rounded-md bg-background">
                  <span className="text-muted-foreground">New Loans:</span>
                  <span className="font-bold text-amber-600">{formatCurrency(receiptStats.loan)}</span>
              </div>
              <div className="flex items-center justify-between p-3 border rounded-md bg-background">
                  <span className="text-muted-foreground">Discounts Given:</span>
                  <span className="font-bold text-red-600">{formatCurrency(receiptStats.discount)}</span>
              </div>
          </CardContent>
      </Card>

      <div className="space-y-4">
        <h2 className="text-2xl font-bold">Player Analytics</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            <AnalyticsCard title="Top Winners" icon={<TrophyIcon />}>
                {analyticsData.topWinners.length > 0 ? (
                    analyticsData.topWinners.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-sm py-1.5 border-b last:border-b-0">
                            <span>{player.name}</span>
                            <span className="font-semibold">{player.wins} Wins</span>
                        </div>
                    ))
                ) : (
                    <p className="text-sm text-muted-foreground">No data.</p>
                )}
            </AnalyticsCard>

            <AnalyticsCard title="Top Spenders (Paid)" icon={<DollarSignIcon />}>
                    {analyticsData.topPaid.length > 0 ? (
                    analyticsData.topPaid.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-sm py-1.5 border-b last:border-b-0">
                            <span>{player.name}</span>
                            <span className="font-semibold">{formatCurrency(player.paid)}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-sm text-muted-foreground">No data.</p>
                )}
            </AnalyticsCard>

            <AnalyticsCard title="Outstanding Loans" icon={<UsersIcon />}>
                {analyticsData.playersWithLoans.length > 0 ? (
                    analyticsData.playersWithLoans.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-sm py-1.5 border-b last:border-b-0">
                            <span>{player.name}</span>
                            <span className="font-semibold text-destructive">{formatCurrency(player.loan)}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-sm text-muted-foreground">None.</p>
                )}
            </AnalyticsCard>
        </div>
      </div>

      <div className="space-y-4">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
            <h2 className="text-2xl font-bold">Game Records</h2>
            <div className="flex flex-wrap items-center gap-2">
                <Input
                    type="date"
                    value={selectedDate}
                    onChange={e => setSelectedDate(e.target.value)}
                    className="w-[180px]"
                />
                <PrintResumeButton games={filteredGames} selectedDate={selectedDate} />
                <Button 
                    onClick={handleAdvanceDay} 
                    disabled={isArchiving} 
                    variant={selectedDate === businessDate ? "default" : "outline"}
                >
                    {isArchiving ? (
                        <>
                            <LoaderCircle className="mr-2 h-4 w-4 animate-spin" />
                            Archiving...
                        </>
                    ) : (
                        "End Day & Save"
                    )}
                </Button>
            </div>
        </div>
        <GamesTable 
            games={filteredGames} 
            isAdmin={true} 
            updateGame={updateGame} 
            deleteGame={deleteGame}
            currentUserId={user.id}
        />
      </div>

      <div className="space-y-4">
