        <div className="flex justify-between items-center p-4 border-b">
          <h2 className="text-lg font-semibold">Google Sheets Integration</h2>
          <Button variant="ghost" size="icon" onClick={onClose}><CloseIcon /></Button>
        </div>

        <div className="p-6 overflow-y-auto space-y-6">
            <div className="space-y-2">
                <h3 className="font-semibold">Connect your Spreadsheet</h3>
                <p className="text-sm text-muted-foreground">
                    Follow the steps below to use a Google Sheet for daily persistent backups and analytics.
                </p>
            </div>

            <Card>
                <CardContent className="p-4 space-y-4">
                     <div className="grid w-full items-center gap-1.5">
                        <label htmlFor="sheetUrl" className="text-sm font-medium">1. Apps Script Web App URL (Required for Sync)</label>
                        <Input id="sheetUrl" type="url" placeholder="https://script.google.com/.../exec" value={urlInput} onChange={e => setUrlInput(e.target.value)} />
                        <p className="text-[10px] text-muted-foreground italic">Obtained after "Deploying" the script below.</p>
                    </div>

                    <div className="grid w-full items-center gap-1.5">
                        <label htmlFor="viewUrl" className="text-sm font-medium">2. Spreadsheet View URL (Optional Link)</label>
                        <Input id="viewUrl" type="url" placeholder="https://docs.google.com/spreadsheets/d/..." value={viewUrlInput} onChange={e => setViewUrlInput(e.target.value)} />
                        <p className="text-[10px] text-muted-foreground italic">Paste the URL of your sheet here so you can open it easily from the app.</p>
                    </div>

                    <div className="flex gap-2 w-full pt-2">
                        <Button onClick={handleSave} className="flex-1">Save & Connect</Button>
                        {sheetUrl && <Button onClick={handleDisconnect} variant="destructive">Disconnect</Button>}
                    </div>
                </CardContent>
            </Card>

            <div className="space-y-4">
                <h3 className="font-semibold text-lg">Setup Instructions</h3>
                <ol className="list-decimal list-inside space-y-4 text-sm">
                    <li>
                        <strong>Create Sheet:</strong> Open <a href="https://sheets.new" target="_blank" className="underline text-primary">sheets.new</a>.
                    </li>
                    <li>
                        <strong>Apps Script:</strong> Go to <strong>Extensions &gt; Apps Script</strong> and paste the code below.
                    </li>
                    <li>
                       <strong>Deploy:</strong> Click <strong>Deploy &gt; New deployment</strong>. 
                       Select <strong>Web app</strong>, Execute as <strong>Me</strong>, and Who has access <strong>Anyone</strong>.
                    </li>
                     <li>
                        <strong>Connect:</strong> Copy the Web App URL and paste it into field #1 above. 
                        Copy the Browser URL and paste it into field #2.
                    </li>
                </ol>
            </div>

             <div>
                <h3 className="font-semibold text-lg mb-2">Apps Script Code</h3>
                <CodeBlock code={appsScriptCode} />
            </div>

        </div>
      </div>
    </div>
  );
};

