  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  const fetchGames = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const { data, error: sbError } = await supabase
        .from('games')
        .select('*')
        .order('startTime', { ascending: false });

      if (sbError) {
        throw sbError;
      }
      setGames(data || []);
    } catch (err: any) {
      const msg = err?.message || err?.details || 'Database connection error';
      console.error('Supabase fetch error:', msg, err);
      setError(`Supabase error: ${msg}. Make sure to run the SQL schema in Settings.`);
      setGames(SEED_GAMES);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchGames();

    // Subscribe to real-time changes
    const channel = supabase
      .channel('public:games')
      .on('postgres_changes', { event: '*', table: 'games', schema: 'public' }, () => {
        fetchGames();
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
