    setSyncStatus('syncing');
    try {
      const { error: sbError } = await supabase
        .from('games')
        .insert([newGameData]);

      if (sbError) throw sbError;
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
    } catch (err: any) {
      console.error('Add game error:', err.message || err);
      setSyncStatus('error');
    }
  }, []);

  const updateGame = useCallback(async (gameId: string, updates: Partial<Game>) => {
    setSyncStatus('syncing');
    try {
      const { error: sbError } = await supabase
        .from('games')
        .update({ ...updates, updatedAt: new Date().toISOString() })
        .eq('id', gameId);

      if (sbError) throw sbError;
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
    } catch (err: any) {
      console.error('Update game error:', err.message || err);
      setSyncStatus('error');
    }
  }, []);

  const deleteGame = useCallback(async (gameId: string) => {
    setSyncStatus('syncing');
    try {
      const { error: sbError } = await supabase
        .from('games')
        .delete()
        .eq('id', gameId);

      if (sbError) throw sbError;
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
    } catch (err: any) {
      console.error('Delete game error:', err.message || err);
      setSyncStatus('error');
    }
  }, []);

  const saveDailySummary = useCallback(async (summary: DailySummary) => {
    setSyncStatus('syncing');
    try {
      const { error: sbError } = await supabase
        .from('daily_summaries')
        .insert([summary]);

      if (sbError) throw sbError;
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
    } catch (err: any) {
      console.error('Save summary error:', err.message || err);
      setSyncStatus('error');
    }
  }, []);

  useEffect(() => {
    setSheetUrl(localStorage.getItem(STORAGE_KEY));
    setSpreadsheetViewUrl(localStorage.getItem(VIEW_STORAGE_KEY));
  }, []);

  return (
    <GameContext.Provider value={{ 
      games, addGame, updateGame, deleteGame, saveDailySummary, 
      isLoading, error, syncStatus, sheetUrl, spreadsheetViewUrl, 
      saveSheetUrl, clearSheetUrl, refetchGames: fetchGames 
    }}>
      {children}
    </GameContext.Provider>
  );
};

