import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Game, PaymentStatus } from '../types';

/**
 * Generates a concise daily summary for the snooker club report.
 * Adheres to Google GenAI SDK best practices.
 */
export const generateDailySummaryText = async (games: Game[]): Promise<string> => {
    // Guidelines: The API key must be obtained exclusively from the environment variable process.env.API_KEY.
    // Assume it is pre-configured and accessible.

    if (games.length === 0) {
        return "No games were played on this date.";
    }

    // Guidelines: Always use new GoogleGenAI({ apiKey: process.env.API_KEY }); directly.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Guidelines: Use 'gemini-3-flash-preview' for basic text summarization tasks.
    const modelName = 'gemini-3-flash-preview';

    const totals = games.reduce(
        (acc, game) => {
            if(game.paymentStatus === PaymentStatus.PAID) acc.paid += game.finalPriceMAD || 0;
            if(game.paymentStatus === PaymentStatus.LOAN) acc.loan += game.finalPriceMAD || 0;
            acc.discount += game.discountMAD || 0;
            return acc;
        }, { paid: 0, loan: 0, discount: 0 });

    const prompt = `
        You are an assistant for a snooker club manager.
        Based on the following summary data for a specific day, write a short, professional summary paragraph for a PDF report.

        Your tone should be concise and informative.
        Start with a general statement about the day's activity.
        Mention the key financial figures: total income from paid games, any new loans, and total discounts.
        Do not just list the numbers; weave them into a natural-sounding paragraph.

        Daily Data:
        - Total Games Played: ${games.length}
        - Total Income (Paid): ${totals.paid.toFixed(2)} MAD
        - Total Outstanding (Loan): ${totals.loan.toFixed(2)} MAD
        - Total Discounts Given: ${totals.discount.toFixed(2)} MAD
        - Most active table: ${findMostActiveTable(games)}

        Generate only the summary paragraph. Do not add any extra titles or greetings.
    `;

    try {
        // Guidelines: Use ai.models.generateContent to fetch a response and type the result as GenerateContentResponse.
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: modelName,
            contents: prompt,
        });

        // Guidelines: Access the generated text using the .text property (not a method).
        return response.text || "No summary generated.";
    } catch (error) {
        console.error("Error calling Gemini API:", error);
        return "An error occurred while generating the summary.";
    }
};

function findMostActiveTable(games: Game[]): string {
    if (games.length === 0) return "N/A";
    const tableCounts = games.reduce((acc, game) => {
        if (game.tableName) {
            acc[game.tableName] = (acc[game.tableName] || 0) + 1;
        }
        return acc;
    }, {} as Record<string, number>);

    const mostActive = Object.entries(tableCounts).sort(([, a], [, b]) => b - a)[0];
    return mostActive ? mostActive[0] : "N/A";
}

