import React, { createContext, useState, ReactNode, useCallback, useEffect } from 'react';
import { Game, GameStatus, DailySummary } from '../types';
import { SEED_GAMES, DEFAULT_HOURLY_RATE } from '../constants';
import { supabase } from '../lib/supabase';

type SyncStatus = 'idle' | 'syncing' | 'synced' | 'error' | 'offline';

interface GameContextType {
  games: Game[];
  addGame: (newGame: Omit<Game, 'id' | 'createdAt' | 'updatedAt'>) => Promise<void>;
  updateGame: (gameId: string, updates: Partial<Game>) => Promise<void>;
  deleteGame: (gameId: string) => Promise<void>;
  saveDailySummary: (summary: DailySummary) => Promise<void>;
  isLoading: boolean;
  error: string | null;
  syncStatus: SyncStatus;
  sheetUrl: string | null;
  spreadsheetViewUrl: string | null;
  saveSheetUrl: (webAppUrl: string, viewUrl: string) => void;
  clearSheetUrl: () => void;
  refetchGames: () => void;
}

export const GameContext = createContext<GameContextType | undefined>(undefined);

const STORAGE_KEY = 'googleSheetWebAppUrl';
const VIEW_STORAGE_KEY = 'googleSpreadsheetViewUrl';
const GAMES_CACHE_KEY = 'snooker_games_cache';

export const GameProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [games, setGames] = useState<Game[]>(() => {
    const cached = localStorage.getItem(GAMES_CACHE_KEY);
    return cached ? JSON.parse(cached) : SEED_GAMES;
  });
  const [sheetUrl, setSheetUrl] = useState<string | null>(null);
  const [spreadsheetViewUrl, setSpreadsheetViewUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  const fetchGames = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const { data, error: sbError } = await supabase
        .from('games')
        .select('*')
        .order('startTime', { ascending: false });

      if (sbError) {
        throw sbError;
      }

      const gameData = data || [];
      setGames(gameData);
      localStorage.setItem(GAMES_CACHE_KEY, JSON.stringify(gameData));
      setSyncStatus('idle');
    } catch (err: any) {
      const isFetchError = err.message === 'Failed to fetch' || err.name === 'TypeError';
      const msg = isFetchError 
        ? "Database Unreachable: The app is running in Offline Mode. Check if the Supabase project is paused or blocked by your network."
        : (err?.message || err?.details || 'Database connection error');

      console.error('Supabase fetch error:', msg);
      setError(msg);
      if (isFetchError) setSyncStatus('offline');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchGames();

    const channel = supabase
      .channel('public:games')
      .on('postgres_changes', { event: '*', table: 'games', schema: 'public' }, () => {
        fetchGames();
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [fetchGames]);

  const saveSheetUrl = (webAppUrl: string, viewUrl: string) => {
    localStorage.setItem(STORAGE_KEY, webAppUrl);
    localStorage.setItem(VIEW_STORAGE_KEY, viewUrl);
    setSheetUrl(webAppUrl);
    setSpreadsheetViewUrl(viewUrl);
  };

  const clearSheetUrl = () => {
    localStorage.removeItem(STORAGE_KEY);
    localStorage.removeItem(VIEW_STORAGE_KEY);
    setSheetUrl(null);
    setSpreadsheetViewUrl(null);
  };

  const addGame = useCallback(async (newGameData: Omit<Game, 'id' | 'createdAt' | 'updatedAt'>) => {
    setSyncStatus('syncing');

    try {
      const { error: sbError } = await supabase
        .from('games')
        .insert([newGameData]);

      if (sbError) throw sbError;
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
      fetchGames();
    } catch (err: any) {
      console.error('Add game error:', err.message || 'Network error');
      setSyncStatus('error');
    }
  }, [fetchGames]);

  const updateGame = useCallback(async (gameId: string, updates: Partial<Game>) => {
    setSyncStatus('syncing');

    try {
      const { error: sbError } = await supabase
        .from('games')
        .update({ ...updates, updatedAt: new Date().toISOString() })
        .eq('id', gameId);

      if (sbError) throw sbError;
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
      fetchGames();
    } catch (err: any) {
      console.error('Update game error:', err.message || 'Network error');
      setSyncStatus('error');
    }
  }, [fetchGames]);

  const deleteGame = useCallback(async (gameId: string) => {
    setSyncStatus('syncing');

    try {
      const { error: sbError } = await supabase
        .from('games')
        .delete()
        .eq('id', gameId);

      if (sbError) throw sbError;
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
      fetchGames();
    } catch (err: any) {
      console.error('Delete game error:', err.message || 'Network error');
      setSyncStatus('error');
    }
  }, [fetchGames]);

  const saveDailySummary = useCallback(async (summary: DailySummary) => {
    setSyncStatus('syncing');
    try {
      const { error: sbError } = await supabase
        .from('daily_summaries')
        .insert([summary]);

      if (sbError) throw sbError;
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
    } catch (err: any) {
      console.error('Save summary error:', err.message || 'Network error');
      setSyncStatus('error');
    }
  }, []);

  useEffect(() => {
    setSheetUrl(localStorage.getItem(STORAGE_KEY));
    setSpreadsheetViewUrl(localStorage.getItem(VIEW_STORAGE_KEY));
  }, []);

  return (
    <GameContext.Provider value={{ 
      games, addGame, updateGame, deleteGame, saveDailySummary, 
      isLoading, error, syncStatus, sheetUrl, spreadsheetViewUrl, 
      saveSheetUrl, clearSheetUrl, refetchGames: fetchGames 
    }}>
      {children}
    </GameContext.Provider>
  );
};

import React, { createContext, useState, ReactNode, useCallback, useEffect } from 'react';
import { User, Role } from '../types';
import { supabase } from '../lib/supabase';

interface UserContextType {
  users: User[];
  addUser: (user: Omit<User, 'id'>) => Promise<void>;
  deleteUser: (userId: string) => Promise<void>;
  findUserByEmail: (email: string) => User | undefined;
  isLoading: boolean;
}

export const UserContext = createContext<UserContextType | undefined>(undefined);

const USERS_CACHE_KEY = 'snooker_users_cache';

// Default users for initial boot if offline and no cache
const DEFAULT_USERS: User[] = [
  { id: '1', email: 'admin@snooker.club', password: 'admin', role: Role.ADMIN },
  { id: '2', email: 'user@snooker.club', password: 'user', role: Role.USER }
];

export const UserProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [users, setUsers] = useState<User[]>(() => {
    const cached = localStorage.getItem(USERS_CACHE_KEY);
    return cached ? JSON.parse(cached) : DEFAULT_USERS;
  });
  const [isLoading, setIsLoading] = useState(true);

  const fetchUsers = useCallback(async () => {
    try {
      const { data, error } = await supabase
        .from('users')
        .select('*');

      if (error) throw error;

      const userData = data || [];
      setUsers(userData);
      localStorage.setItem(USERS_CACHE_KEY, JSON.stringify(userData));
    } catch (err: any) {
      const isFetchError = err.message === 'Failed to fetch' || err.name === 'TypeError';
      console.warn('User fetch failed, using cache:', isFetchError ? 'Offline Mode' : err.message);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchUsers();
  }, [fetchUsers]);

  const addUser = useCallback(async (newUser: Omit<User, 'id'>) => {
    try {
      const { data, error } = await supabase
        .from('users')
        .insert([{ ...newUser }])
        .select();

      if (error) throw error;
      if (data) {
        const updatedUsers = [...users, data[0]];
        setUsers(updatedUsers);
        localStorage.setItem(USERS_CACHE_KEY, JSON.stringify(updatedUsers));
      }
    } catch (err: any) {
      alert(err.message || 'Error adding user');
    }
  }, [users]);

  const deleteUser = useCallback(async (userId: string) => {
    try {
      const { error } = await supabase
        .from('users')
        .delete()
        .eq('id', userId);

      if (error) throw error;
      const updatedUsers = users.filter(user => user.id !== userId);
      setUsers(updatedUsers);
      localStorage.setItem(USERS_CACHE_KEY, JSON.stringify(updatedUsers));
    } catch (err: any) {
      alert(err.message || 'Error deleting user');
    }
  }, [users]);

  const findUserByEmail = useCallback((email: string) => {
    return users.find(user => user.email.toLowerCase() === email.toLowerCase());
  }, [users]);

  return (
    <UserContext.Provider value={{ users, addUser, deleteUser, findUserByEmail, isLoading }}>
      {children}
    </UserContext.Provider>
  );
};

import React, { createContext, useState, ReactNode, useCallback, useEffect } from 'react';
import { supabase } from '../lib/supabase';

const getTodayDateString = () => {
    const today = new Date();
    today.setMinutes(today.getMinutes() - today.getTimezoneOffset());
    return today.toISOString().split('T')[0];
};

interface BusinessDayContextType {
  businessDate: string;
  advanceDay: () => Promise<void>;
  isLoading: boolean;
}

export const BusinessDayContext = createContext<BusinessDayContextType | undefined>(undefined);

const CONFIG_KEY = 'business_date';
const BUSINESS_DATE_CACHE_KEY = 'snooker_business_date_cache';

export const BusinessDayProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [businessDate, setBusinessDate] = useState<string>(() => {
    return localStorage.getItem(BUSINESS_DATE_CACHE_KEY) || getTodayDateString();
  });
  const [isLoading, setIsLoading] = useState(true);

  const fetchConfig = useCallback(async () => {
    try {
      const { data, error } = await supabase
        .from('app_config')
        .select('value')
        .eq('key', CONFIG_KEY)
        .single();

      if (error) {
          if (error.code === 'PGRST116') {
              // Row not found, try to create it
              await supabase.from('app_config').insert([{ key: CONFIG_KEY, value: getTodayDateString() }]);
              setBusinessDate(getTodayDateString());
              localStorage.setItem(BUSINESS_DATE_CACHE_KEY, getTodayDateString());
          } else {
              throw error;
          }
      } else if (data) {
        setBusinessDate(data.value);
        localStorage.setItem(BUSINESS_DATE_CACHE_KEY, data.value);
      }
    } catch (err: any) {
      const isFetchError = err.message === 'Failed to fetch' || err.name === 'TypeError';
      console.warn('Config fetch failed, using local date:', isFetchError ? 'Offline Mode' : err.message);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchConfig();

    const channel = supabase
      .channel('public:app_config')
      .on('postgres_changes', { event: 'UPDATE', table: 'app_config', schema: 'public' }, (payload) => {
        if (payload.new && payload.new.key === CONFIG_KEY) {
            setBusinessDate(payload.new.value);
            localStorage.setItem(BUSINESS_DATE_CACHE_KEY, payload.new.value);
        }
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [fetchConfig]);

  const advanceDay = useCallback(async () => {
    const nextDate = new Date(businessDate);
    nextDate.setDate(nextDate.getDate() + 1);
    nextDate.setMinutes(nextDate.getMinutes() - nextDate.getTimezoneOffset());
    const nextDateStr = nextDate.toISOString().split('T')[0];

    try {
        const { error } = await supabase
            .from('app_config')
            .update({ value: nextDateStr })
            .eq('key', CONFIG_KEY);

        if (error) throw error;

        setBusinessDate(nextDateStr);
        localStorage.setItem(BUSINESS_DATE_CACHE_KEY, nextDateStr);
    } catch (err: any) {
        const msg = err.message || 'Network error';
        console.error('Error advancing day:', msg);
        // Even if network fails, we can allow local advancement for testing/demo
        setBusinessDate(nextDateStr);
        localStorage.setItem(BUSINESS_DATE_CACHE_KEY, nextDateStr);
        alert(`Note: Business day advanced locally, but server update failed: ${msg}`);
    }
  }, [businessDate]);

  return (
    <BusinessDayContext.Provider value={{ businessDate, advanceDay, isLoading }}>
      {children}
    </BusinessDayContext.Provider>
  );
};

