/**
 * Helper to identify if an error is specifically about a missing table/schema.
 */
export const isMissingTableError = (error: any): boolean => {
  if (!error) return false;

  // Handle different variations of "table not found" errors
  const code = error.code;
  const message = error.message?.toLowerCase() || '';

  return (
    code === '42P01' || // undefined_table (Standard PG error)
    code === 'PGRST204' || // resource_not_found (PostgREST)
    message.includes('schema cache') ||
    message.includes('could not find the table') ||
    message.includes('relation "public.games" does not exist') ||
    message.includes('relation "games" does not exist') ||
    message.includes('relation "users" does not exist') ||
    message.includes('relation "app_config" does not exist')
  );
};

/**
 * Diagnostic tool to check Supabase connectivity.
 */
export const checkSupabaseConnection = async (): Promise<{ ok: boolean; message: string; isSetupRequired?: boolean }> => {
  try {
    const { data, error, status } = await supabase.from('app_config').select('key').limit(1);

    if (error) {
      if (isMissingTableError(error)) {
        return { ok: false, message: "Database tables not found. Setup required.", isSetupRequired: true };
      }
      if (status === 401 || status === 403) {
        return { ok: false, message: "Access Denied: Check API Key or RLS settings." };
      }
      return { ok: false, message: error.message };
    }
    return { ok: true, message: "Connected successfully." };
  } catch (err: any) {
    if (err.message === 'Failed to fetch' || err.name === 'TypeError') {
      return { 
        ok: false, 
        message: "Network Error: Cannot reach Supabase API." 
      };
    }
    return { ok: false, message: err.message || "Unknown connectivity error" };
  }
};

import React, { createContext, useState, ReactNode, useCallback, useEffect } from 'react';
import { User, Role } from '../types';
import { supabase, isMissingTableError } from '../lib/supabase';

interface UserContextType {
  users: User[];
  addUser: (user: Omit<User, 'id'>) => Promise<void>;
  deleteUser: (userId: string) => Promise<void>;
  findUserByEmail: (email: string) => User | undefined;
  isLoading: boolean;
  isTableMissing: boolean;
}

export const UserContext = createContext<UserContextType | undefined>(undefined);

const USERS_CACHE_KEY = 'snooker_users_cache';

// Using valid UUID formats for default users to ensure compatibility with DB foreign keys
const DEFAULT_USERS: User[] = [
  { id: '00000000-0000-0000-0000-000000000001', email: 'admin@snooker.club', password: 'admin', role: Role.ADMIN },
  { id: '00000000-0000-0000-0000-000000000002', email: 'user@snooker.club', password: 'user', role: Role.USER }
];

export const UserProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [users, setUsers] = useState<User[]>(() => {
    const cached = localStorage.getItem(USERS_CACHE_KEY);
    // Filter out old non-uuid IDs from cache if they exist
    if (cached) {
      const parsed = JSON.parse(cached);
      if (parsed.length > 0 && parsed[0].id === '1') return DEFAULT_USERS;
      return parsed;
    }
    return DEFAULT_USERS;
  });
  const [isLoading, setIsLoading] = useState(true);
  const [isTableMissing, setIsTableMissing] = useState(false);

  const fetchUsers = useCallback(async () => {
    try {
      const { data, error } = await supabase
        .from('users')
        .select('*');

      if (error) throw error;

      const userData = data || [];
      if (userData.length > 0) {
        setUsers(userData);
        localStorage.setItem(USERS_CACHE_KEY, JSON.stringify(userData));
      }
      setIsTableMissing(false);
    } catch (err: any) {
      if (isMissingTableError(err)) {
        setIsTableMissing(true);
      }
      const isFetchError = err.message === 'Failed to fetch' || err.name === 'TypeError';
      console.warn('User fetch failed, using cache:', isFetchError ? 'Offline Mode' : err.message);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchUsers();
  }, [fetchUsers]);

  const addUser = useCallback(async (newUser: Omit<User, 'id'>) => {
    try {
      const { data, error } = await supabase
        .from('users')
        .insert([{ ...newUser }])
        .select();

      if (error) throw error;
      if (data) {
        const updatedUsers = [...users, data[0]];
        setUsers(updatedUsers);
        localStorage.setItem(USERS_CACHE_KEY, JSON.stringify(updatedUsers));
      }
    } catch (err: any) {
      alert(err.message || 'Error adding user');
    }
  }, [users]);

  const deleteUser = useCallback(async (userId: string) => {
    try {
      const { error } = await supabase
        .from('users')
        .delete()
        .eq('id', userId);

      if (error) throw error;
      const updatedUsers = users.filter(user => user.id !== userId);
      setUsers(updatedUsers);
      localStorage.setItem(USERS_CACHE_KEY, JSON.stringify(updatedUsers));
    } catch (err: any) {
      alert(err.message || 'Error deleting user');
    }
  }, [users]);

  const findUserByEmail = useCallback((email: string) => {
    return users.find(user => user.email.toLowerCase() === email.toLowerCase());
  }, [users]);

  return (
    <UserContext.Provider value={{ users, addUser, deleteUser, findUserByEmail, isLoading, isTableMissing }}>
      {children}
    </UserContext.Provider>
  );
};

import React, { createContext, useState, ReactNode, useCallback, useEffect } from 'react';
import { Game, GameStatus, DailySummary } from '../types';
import { SEED_GAMES } from '../constants';
import { supabase, isMissingTableError } from '../lib/supabase';

type SyncStatus = 'idle' | 'syncing' | 'synced' | 'error' | 'offline';

interface GameContextType {
  games: Game[];
  addGame: (newGame: Omit<Game, 'id' | 'createdAt' | 'updatedAt'>) => Promise<void>;
  updateGame: (gameId: string, updates: Partial<Game>) => Promise<void>;
  deleteGame: (gameId: string) => Promise<void>;
  saveDailySummary: (summary: DailySummary) => Promise<void>;
  isLoading: boolean;
  error: string | null;
  isTableMissing: boolean;
  syncStatus: SyncStatus;
  sheetUrl: string | null;
  spreadsheetViewUrl: string | null;
  saveSheetUrl: (webAppUrl: string, viewUrl: string) => void;
  clearSheetUrl: () => void;
  refetchGames: () => void;
}

export const GameContext = createContext<GameContextType | undefined>(undefined);

const STORAGE_KEY = 'googleSheetWebAppUrl';
const VIEW_STORAGE_KEY = 'googleSpreadsheetViewUrl';
const GAMES_CACHE_KEY = 'snooker_games_cache';

export const GameProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [games, setGames] = useState<Game[]>(() => {
    const cached = localStorage.getItem(GAMES_CACHE_KEY);
    return cached ? JSON.parse(cached) : SEED_GAMES;
  });
  const [sheetUrl, setSheetUrl] = useState<string | null>(null);
  const [spreadsheetViewUrl, setSpreadsheetViewUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [isTableMissing, setIsTableMissing] = useState<boolean>(false);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  const fetchGames = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    setIsTableMissing(false);
    try {
      const { data, error: sbError } = await supabase
        .from('games')
        .select('*')
        .order('startTime', { ascending: false });

      if (sbError) throw sbError;

      const gameData = data || [];
      setGames(gameData);
      localStorage.setItem(GAMES_CACHE_KEY, JSON.stringify(gameData));
      setSyncStatus('idle');
    } catch (err: any) {
      if (isMissingTableError(err)) {
        setIsTableMissing(true);
        setError("Setup Required: The 'games' table does not exist in your Supabase project.");
      } else {
        const isFetchError = err.message === 'Failed to fetch' || err.name === 'TypeError';
        setError(isFetchError ? "Network Error: Could not reach database." : err.message);
        if (isFetchError) setSyncStatus('offline');
      }
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchGames();
    const channel = supabase
      .channel('public:games')
      .on('postgres_changes', { event: '*', table: 'games', schema: 'public' }, () => fetchGames())
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [fetchGames]);

  const saveSheetUrl = (webAppUrl: string, viewUrl: string) => {
    localStorage.setItem(STORAGE_KEY, webAppUrl);
    localStorage.setItem(VIEW_STORAGE_KEY, viewUrl);
    setSheetUrl(webAppUrl);
    setSpreadsheetViewUrl(viewUrl);
  };

  const clearSheetUrl = () => {
    localStorage.removeItem(STORAGE_KEY);
    localStorage.removeItem(VIEW_STORAGE_KEY);
    setSheetUrl(null);
    setSpreadsheetViewUrl(null);
  };

  const addGame = useCallback(async (newGameData: Omit<Game, 'id' | 'createdAt' | 'updatedAt'>) => {
    setSyncStatus('syncing');
    try {
      const { error: sbError } = await supabase.from('games').insert([newGameData]);
      if (sbError) throw sbError;
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
      await fetchGames();
    } catch (err: any) {
      setSyncStatus('error');
      alert(`Failed to start game: ${err.message || 'Unknown error'}`);
      console.error('Add game error:', err);
    }
  }, [fetchGames]);

  const updateGame = useCallback(async (gameId: string, updates: Partial<Game>) => {
    setSyncStatus('syncing');
    try {
      const { error: sbError } = await supabase.from('games').update({ ...updates, updatedAt: new Date().toISOString() }).eq('id', gameId);
      if (sbError) throw sbError;
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
      await fetchGames();
    } catch (err: any) {
      setSyncStatus('error');
      alert(`Update failed: ${err.message}`);
    }
  }, [fetchGames]);

  const deleteGame = useCallback(async (gameId: string) => {
    setSyncStatus('syncing');
    try {
      const { error: sbError } = await supabase.from('games').delete().eq('id', gameId);
      if (sbError) throw sbError;
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
      await fetchGames();
    } catch (err: any) {
      setSyncStatus('error');
      alert(`Delete failed: ${err.message}`);
    }
  }, [fetchGames]);

  const saveDailySummary = useCallback(async (summary: DailySummary) => {
    try {
      const { error: sbError } = await supabase.from('daily_summaries').upsert([summary], { onConflict: 'date' });
      if (sbError) throw sbError;
    } catch (err: any) {
      console.error('Save summary failed:', err.message);
    }
  }, []);

  useEffect(() => {
    setSheetUrl(localStorage.getItem(STORAGE_KEY));
    setSpreadsheetViewUrl(localStorage.getItem(VIEW_STORAGE_KEY));
  }, []);

  return (
    <GameContext.Provider value={{ 
      games, addGame, updateGame, deleteGame, saveDailySummary, 
      isLoading, error, isTableMissing, syncStatus, sheetUrl, spreadsheetViewUrl, 
      saveSheetUrl, clearSheetUrl, refetchGames: fetchGames 
    }}>
      {children}
    </GameContext.Provider>
  );
};

