                    analyticsData.topWinners.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-sm py-1.5 border-b last:border-b-0">
                            <span>{player.name}</span>
                            <span className="font-semibold">{player.wins} Wins</span>
                        </div>
