import React, { useState } from 'react';
import { useAuth } from '../hooks/useAuth';
import { useGames } from '../hooks/useGames';
import { useBusinessDay } from '../hooks/useBusinessDay';
import GamesTable from '../components/GamesTable';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';
import { Select } from '../components/ui/Select';
import { Card, CardContent, CardHeader, CardTitle } from '../components/ui/Card';
import { TABLES, DEFAULT_HOURLY_RATE } from '../constants';
import { GameStatus, PaymentStatus } from '../types';
import { AlertTriangle } from '../components/icons';

const DashboardPage: React.FC = () => {
  const { user } = useAuth();
  const { games, addGame, updateGame, isTableMissing } = useGames();
  const { businessDate } = useBusinessDay();
  const [player1, setPlayer1] = useState('');
  const [player2, setPlayer2] = useState('');
  const [selectedTableId, setSelectedTableId] = useState('');

  // Identify busy tables (tables with at least one running game)
  const busyTableNames = games
    .filter(g => g.status === GameStatus.RUNNING)
    .map(g => g.tableName);

  const handleStartGame = () => {
    if (!player1 || !user) {
      alert('Player 1 name is required.');
      return;
    }

    if (!selectedTableId) {
      alert('Please select a table.');
      return;
    }

    const tableConfig = TABLES.find(t => t.id === selectedTableId);
    const tableName = tableConfig ? tableConfig.name : 'Unknown';
    const hourlyRate = tableConfig ? tableConfig.rate : DEFAULT_HOURLY_RATE;

    // Check if table is already busy
    const isTableBusy = games.some(g => g.tableName === tableName && g.status === GameStatus.RUNNING);

    if (isTableBusy) {
      alert(`Table "${tableName}" is currently occupied. Please finish the current game before starting a new one.`);
      return;
    }

    addGame({
      date: businessDate,
      tableName: tableName,
      hourlyRate: hourlyRate,
      startTime: new Date().toISOString(),
      endTime: null,
      player1,
      player2: player2 || null,
      winner: null,
      status: GameStatus.RUNNING,
      durationSeconds: null,
      priceMAD: null,
      discountMAD: 0,
      finalPriceMAD: null,
      paymentStatus: PaymentStatus.PENDING,
      notes: null,
      createdBy: user.id,
      modifiedBy: null,
    });

    setPlayer1('');
    setPlayer2('');
    setSelectedTableId('');
  };

  const myGames = games.filter(game => game.createdBy === user?.id);
  const dayGames = games.filter(g => g.date === businessDate);

  return (
    <div className="space-y-8">
      {isTableMissing && (
        <Card className="border-destructive bg-destructive/10">
          <CardContent className="p-4 flex items-center gap-3">
            <AlertTriangle className="h-6 w-6 text-destructive" />
            <div className="flex-1">
              <p className="font-bold text-destructive">Database Setup Required</p>
              <p className="text-sm opacity-90">Please open Settings (gear icon) and follow the Supabase setup instructions to start saving games.</p>
            </div>
          </CardContent>
        </Card>
      )}

      <Card>
        <CardHeader>
          <CardTitle>Start a New Game</CardTitle>
        </CardHeader>
        <CardContent className="flex flex-col md:flex-row gap-4 items-end">
          <div className="grid w-full items-center gap-1.5">
              <label htmlFor="p1">Player 1*</label>
              <Input id="p1" type="text" placeholder="Player 1 Name" value={player1} onChange={e => setPlayer1(e.target.value)} disabled={isTableMissing} />
          </div>
           <div className="grid w-full items-center gap-1.5">
              <label htmlFor="p2">Player 2</label>
              <Input id="p2" type="text" placeholder="Player 2 Name" value={player2} onChange={e => setPlayer2(e.target.value)} disabled={isTableMissing} />
          </div>
          <div className="grid w-full md:max-w-[200px] items-center gap-1.5">
              <label htmlFor="table">Table*</label>
              <Select id="table" value={selectedTableId} onChange={e => setSelectedTableId(e.target.value)} disabled={isTableMissing}>
                <option value="" disabled>Select Table</option>
                {TABLES.map(t => {
                  const isBusy = busyTableNames.includes(t.name);
                  return (
                    <option 
                      key={t.id} 
                      value={t.id} 
                      disabled={isBusy}
                      className={isBusy ? "text-muted-foreground bg-muted" : ""}
                    >
                      {t.name} ({t.rate} MAD/h) {isBusy ? '(Busy)' : ''}
                    </option>
                  );
                })}
              </Select>
          </div>
          <Button onClick={handleStartGame} disabled={isTableMissing}>Start Game</Button>
        </CardContent>
      </Card>

      <div className="space-y-4">
        <h2 className="text-2xl font-bold">My Added Games</h2>
        <GamesTable 
          games={myGames} 
          isAdmin={false} 
          updateGame={updateGame} 
          deleteGame={undefined} 
          currentUserId={user?.id}
        />
      </div>

      <div className="space-y-4">
        <h2 className="text-2xl font-bold">All Games for the Day ({new Date(businessDate + 'T00:00:00').toDateString()})</h2>
        <GamesTable games={dayGames} isAdmin={false} />
      </div>

    </div>
  );
};

export default DashboardPage;

import React, { useState, useEffect } from 'react';
import { Game, GameStatus, PaymentStatus } from '../types';
import { formatCurrency, formatDuration, calculateLivePrice, calculateFinalPrice } from '../lib/utils';
import { Badge } from './ui/Badge';
import { Button } from './ui/Button';
import { MoreVerticalIcon } from './icons';
import { Input } from './ui/Input';
import { Select } from './ui/Select';
import { TABLES, DEFAULT_HOURLY_RATE } from '../constants';

interface GameRowProps {
  game: Game;
  isAdmin: boolean;
  updateGame?: (gameId: string, updates: Partial<Game>) => void;
  deleteGame?: (gameId:string) => void;
  currentUserId?: string;
}

const GameRow: React.FC<GameRowProps> = ({ game, isAdmin, updateGame, deleteGame, currentUserId }) => {
    // Fallback if game rate is missing (backward compatibility)
    const gameRate = game.hourlyRate || DEFAULT_HOURLY_RATE;

    const calculateCurrentDuration = () => {
        if (game.status === GameStatus.RUNNING) {
            const start = new Date(game.startTime).getTime();
            const now = Date.now();
            return Math.max(0, Math.floor((now - start) / 1000));
        }
        return 0;
    };

    const [liveDuration, setLiveDuration] = useState<number>(calculateCurrentDuration);

    const [livePrice, setLivePrice] = useState<number>(() => {
         if (game.status === GameStatus.RUNNING) {
             return calculateLivePrice(game.startTime, gameRate);
         }
         return 0;
    });

    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [isEditing, setIsEditing] = useState(false);

    const [editableGame, setEditableGame] = useState({
      tableName: game.tableName ?? '',
      hourlyRate: gameRate,
      player1: game.player1,
      player2: game.player2 ?? '',
      winner: game.winner ?? null,
      discountMAD: game.discountMAD ?? 0,
      status: game.status,
      // If the game is starting settlement, default it to Paid instead of Pending
      paymentStatus: game.paymentStatus === PaymentStatus.PENDING ? PaymentStatus.PAID : game.paymentStatus,
      finalPriceMAD: game.finalPriceMAD ?? 0,
    });

    useEffect(() => {
        if (game.status === GameStatus.RUNNING && !isEditing) {
            const updateStats = () => {
                setLiveDuration(calculateCurrentDuration());
                setLivePrice(calculateLivePrice(game.startTime, gameRate));
            };

            updateStats(); // Immediate update on mount/status change

            const interval = setInterval(updateStats, 1000);
            return () => clearInterval(interval);
        }
    }, [game.status, game.startTime, isEditing, gameRate]);

    const resetEditableGame = () => {
        setEditableGame({
            tableName: game.tableName ?? '',
            hourlyRate: gameRate,
            player1: game.player1,
            player2: game.player2 ?? '',
            winner: game.winner ?? null,
            discountMAD: game.discountMAD ?? 0,
            status: game.status,
            paymentStatus: game.paymentStatus === PaymentStatus.PENDING ? PaymentStatus.PAID : game.paymentStatus,
            finalPriceMAD: game.finalPriceMAD ?? 0,
        });
    };

    const startEditing = () => {
        resetEditableGame();
        setIsEditing(true);
        setIsMenuOpen(false);
    };

    const handleTableChange = (tableId: string) => {
        const config = TABLES.find(t => t.id === tableId);
        if (config) {
             setEditableGame({
                 ...editableGame,
                 tableName: config.name,
                 hourlyRate: config.rate
             });
        }
    };

    const handleStatusChange = (newStatus: GameStatus) => {
        let newFinalPrice = editableGame.finalPriceMAD;
        if (game.status === GameStatus.RUNNING && newStatus === GameStatus.FINISHED) {
            const endTime = new Date().toISOString();
            const discount = isAdmin ? Number(editableGame.discountMAD) : game.discountMAD;
            const { finalPrice } = calculateFinalPrice(game.startTime, endTime, discount, editableGame.hourlyRate);
            newFinalPrice = Number(finalPrice.toFixed(2));
        }

        setEditableGame({
            ...editableGame,
            status: newStatus,
            finalPriceMAD: newFinalPrice,
        });
    }

    const handleSaveChanges = () => {
      if (!updateGame || !currentUserId) return;

      const updates: Partial<Game> = {
          tableName: editableGame.tableName,
          hourlyRate: editableGame.hourlyRate,
          player1: editableGame.player1,
          player2: editableGame.player2 || null,
          winner: editableGame.winner,
          paymentStatus: editableGame.paymentStatus,
          modifiedBy: currentUserId,
      };

      if (game.status === GameStatus.RUNNING && editableGame.status === GameStatus.FINISHED) {
          const endTime = new Date().toISOString();
          const discount = isAdmin ? Number(editableGame.discountMAD) : game.discountMAD;
          const { durationSeconds, price } = calculateFinalPrice(game.startTime, endTime, discount, editableGame.hourlyRate);

          updates.status = GameStatus.FINISHED;
          updates.endTime = endTime;
          updates.durationSeconds = durationSeconds;
          updates.priceMAD = price;
          updates.finalPriceMAD = Number(editableGame.finalPriceMAD);
          updates.discountMAD = discount;
      } else if (game.status === GameStatus.FINISHED) {
        updates.finalPriceMAD = Number(editableGame.finalPriceMAD);
        if (isAdmin) {
          updates.discountMAD = Number(editableGame.discountMAD);
        }
      }

      updateGame(game.id, updates);
      setIsEditing(false);
      setIsMenuOpen(false);
    };

    const handleCancelEdit = () => {
      setIsEditing(false);
      resetEditableGame();
    };

    const priceToDisplay = game.status === GameStatus.RUNNING ? livePrice : (game.finalPriceMAD ?? 0);
    const durationToDisplay = game.status === GameStatus.RUNNING ? liveDuration : (game.durationSeconds ?? 0);

    const paymentStatusBadge = {
        [PaymentStatus.PAID]: 'bg-green-600/80 hover:bg-green-600/70',
        [PaymentStatus.PENDING]: 'bg-blue-600/80 hover:bg-blue-600/70',
        [PaymentStatus.LOAN]: 'bg-amber-500/80 hover:bg-amber-500/70',
    };

    const canCurrentUserEdit = game.createdBy === currentUserId && !isAdmin;
    const showActions = isAdmin || canCurrentUserEdit;

    // Find table ID from name for select box
    const currentTableConfig = TABLES.find(t => t.name === editableGame.tableName);
    const currentTableId = currentTableConfig ? currentTableConfig.id : '';

    if (isEditing) {
        return (
            <tr className="border-b transition-colors hover:bg-muted/50 data-[state=selected]:bg-muted">
                <td colSpan={8} className="p-4">
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                        <div className="space-y-2">
                            <label className="text-xs font-medium text-muted-foreground">Table</label>
                            <Select value={currentTableId} onChange={(e) => handleTableChange(e.target.value)}>
                                <option value="" disabled>Select Table</option>
                                {TABLES.map(t => (
                                    <option key={t.id} value={t.id}>{t.name}</option>
                                ))}
                            </Select>
                        </div>
                         <div className="space-y-2">
                            <label className="text-xs font-medium text-muted-foreground">Player 1</label>
                            <Input type="text" value={editableGame.player1} onChange={(e) => setEditableGame({...editableGame, player1: e.target.value})} className="h-8" />
                        </div>
                        <div className="space-y-2">
                            <label className="text-xs font-medium text-muted-foreground">Player 2</label>
                            <Input type="text" value={editableGame.player2} onChange={(e) => setEditableGame({...editableGame, player2: e.target.value})} className="h-8" />
                        </div>
                        <div className="space-y-2">
                            <label className="text-xs font-medium text-muted-foreground">Status</label>
                             <Select value={editableGame.status} onChange={(e) => handleStatusChange(e.target.value as GameStatus)} disabled={game.status === GameStatus.FINISHED}>
                                <option value={GameStatus.RUNNING}>Running</option>
                                <option value={GameStatus.FINISHED}>Finished</option>
                            </Select>
                        </div>
                        {editableGame.status === GameStatus.FINISHED && (
                             <div className="space-y-2">
                                <label className="text-xs font-medium text-muted-foreground">Final Price</label>
                                <Input type="number" value={editableGame.finalPriceMAD} onChange={(e) => setEditableGame({ ...editableGame, finalPriceMAD: Number(e.target.value) })} className="h-8" placeholder="Price" />
                            </div>
                        )}
                         {isAdmin && editableGame.status === GameStatus.FINISHED && (
                            <div className="space-y-2">
                                <label className="text-xs font-medium text-muted-foreground">Discount</label>
                                <Input type="number" value={editableGame.discountMAD} onChange={(e) => setEditableGame({...editableGame, discountMAD: Number(e.target.value)})} className="h-8" placeholder="Discount" />
                            </div>
                        )}
                        <div className="space-y-2">
                            <label className="text-xs font-medium text-muted-foreground">Payment Settlement</label>
                            <Select 
                                value={editableGame.paymentStatus} 
                                onChange={(e) => setEditableGame({ ...editableGame, paymentStatus: e.target.value as PaymentStatus })} 
                                disabled={editableGame.status !== GameStatus.FINISHED}
                            >
                                <option value={PaymentStatus.PAID}>Paid</option>
                                <option value={PaymentStatus.LOAN}>Loan</option>
                            </Select>
                        </div>
                        {editableGame.status === GameStatus.FINISHED && game.player2 && (
                            <div className="space-y-2">
                                <label className="text-xs font-medium text-muted-foreground">Winner</label>
                                <Select value={editableGame.winner ?? ''} onChange={(e) => setEditableGame({...editableGame, winner: e.target.value || null })}>
                                    <option value="">None / Draw</option>
                                    <option value={game.player1}>{game.player1}</option>
                                    <option value={game.player2}>{game.player2}</option>
                                </Select>
                            </div>
                        )}
                    </div>
                    <div className="flex items-center justify-end gap-2 mt-4">
                        <Button size="sm" onClick={handleSaveChanges}>Save</Button>
                        <Button size="sm" variant="ghost" onClick={handleCancelEdit}>Cancel</Button>
                    </div>
                </td>
            </tr>
        );
    }

    return (
        <tr className="border-b transition-colors hover:bg-muted/50 data-[state=selected]:bg-muted">
            {/* Desktop View */}
            <td className="p-4 align-middle hidden md:table-cell">{game.tableName ?? '-'}</td>
            <td className="p-4 align-middle font-medium hidden md:table-cell">
                {`${game.player1}${game.player2 ? `, ${game.player2}` : ''}`}
                {game.winner && <div className="text-xs text-green-500">Winner: {game.winner}</div>}
            </td>
            <td className="p-4 align-middle text-muted-foreground text-xs hidden md:table-cell">
                <div>Start: {new Date(game.startTime).toLocaleTimeString()}</div>
                <div>End: {game.endTime ? new Date(game.endTime).toLocaleTimeString() : '...'}</div>
            </td>
            <td className="p-4 align-middle hidden md:table-cell">{formatDuration(durationToDisplay)}</td>
            <td className="p-4 align-middle hidden md:table-cell">
