  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='games' AND column_name='endtime') THEN
    ALTER TABLE public.games RENAME COLUMN "endtime" TO "endTime";
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='games' AND column_name='durationseconds') THEN
    ALTER TABLE public.games RENAME COLUMN "durationseconds" TO "durationSeconds";
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='games' AND column_name='pricemad') THEN
    ALTER TABLE public.games RENAME COLUMN "pricemad" TO "priceMAD";
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='games' AND column_name='discountmad') THEN
    ALTER TABLE public.games RENAME COLUMN "discountmad" TO "discountMAD";
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='games' AND column_name='finalpricemad') THEN
    ALTER TABLE public.games RENAME COLUMN "finalpricemad" TO "finalPriceMAD";
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='games' AND column_name='paymentstatus') THEN
    ALTER TABLE public.games RENAME COLUMN "paymentstatus" TO "paymentStatus";
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='games' AND column_name='createdby') THEN
    ALTER TABLE public.games RENAME COLUMN "createdby" TO "createdBy";
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='games' AND column_name='modifiedby') THEN
    ALTER TABLE public.games RENAME COLUMN "modifiedby" TO "modifiedBy";
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='games' AND column_name='createdat') THEN
    ALTER TABLE public.games RENAME COLUMN "createdat" TO "createdAt";
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='games' AND column_name='updatedat') THEN
    ALTER TABLE public.games RENAME COLUMN "updatedat" TO "updatedAt";
  END IF;
END $$;

-- 4. CREATE DAILY SUMMARIES TABLE
CREATE TABLE IF NOT EXISTS public.daily_summaries (
  "id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "date" date UNIQUE NOT NULL,
  "totalPaid" numeric DEFAULT 0,
  "totalLoan" numeric DEFAULT 0,
  "totalDiscount" numeric DEFAULT 0,
  "gameCount" int DEFAULT 0,
  "archivedAt" timestamptz DEFAULT now()
);

-- 5. CREATE APP CONFIG TABLE
CREATE TABLE IF NOT EXISTS public.app_config (
  "key" text PRIMARY KEY,
  "value" text NOT NULL
);

-- 6. DISABLE RLS
ALTER TABLE public.users DISABLE ROW LEVEL SECURITY;
ALTER TABLE public.games DISABLE ROW LEVEL SECURITY;
ALTER TABLE public.daily_summaries DISABLE ROW LEVEL SECURITY;
ALTER TABLE public.app_config DISABLE ROW LEVEL SECURITY;

-- 7. INSERT INITIAL DATA
INSERT INTO public.users ("id", "email", "password", "role") 
VALUES 
  ('00000000-0000-0000-0000-000000000001', 'admin@snooker.club', 'admin', 'admin'),
