export default GameRow;

import { Game, GameStatus } from '../types';
import { DEFAULT_HOURLY_RATE } from '../constants';

export const formatCurrency = (amount: number | null | undefined) => {
  if (amount === null || amount === undefined) return 'N/A';
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'MAD',
    minimumFractionDigits: 2,
  }).format(amount).replace('MAD', '') + ' MAD';
};

export const formatDuration = (totalSeconds: number | null | undefined) => {
  if (totalSeconds === null || totalSeconds === undefined) return '00:00:00';
  const hours = Math.floor(totalSeconds / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;
  return [hours, minutes, seconds]
    .map(v => v < 10 ? '0' + v : v)
    .join(':');
};

/**
 * Gets the minimum charge for a table based on its name.
 * Royal tables: 30 MAD
 * Mini tables: 20 MAD
 */
export const getMinPrice = (tableName: string = ''): number => {
    const name = tableName.toLowerCase();
    if (name.includes('royal')) return 30;
    if (name.includes('mini')) return 20;
    return 0; // Fallback
};

export const calculateLivePrice = (startTime: string, hourlyRate: number = DEFAULT_HOURLY_RATE, tableName: string = '') => {
    const start = new Date(startTime).getTime();
    const now = new Date().getTime();
    const durationSeconds = Math.max(0, Math.floor((now - start) / 1000));
    const calculatedPrice = (hourlyRate * (durationSeconds / 3600));

    // Live price respects the minimum
    return Math.max(getMinPrice(tableName), calculatedPrice);
};

export const calculateFinalPrice = (startTime: string, endTime: string, discount: number = 0, hourlyRate: number = DEFAULT_HOURLY_RATE, tableName: string = '') => {
  const start = new Date(startTime).getTime();
  const end = new Date(endTime).getTime();
  const durationSeconds = Math.max(0, Math.floor((end - start) / 1000));
  const price = (hourlyRate * (durationSeconds / 3600));

  // The final price is either the minimum or (calculated - discount), whichever is higher
  const minPrice = getMinPrice(tableName);
  const discountedPrice = price - discount;
  const finalPrice = Math.max(minPrice, discountedPrice);

  return {
    durationSeconds,
    price,
    finalPrice
  };
};

export const getTodayDateString = () => {
    return new Date().toISOString().split('T')[0];
};

export const getGameComputedValues = (game: Game) => {
  if (game.status === GameStatus.FINISHED && game.endTime) {
    const { durationSeconds, price, finalPrice } = calculateFinalPrice(
        game.startTime, 
        game.endTime, 
        game.discountMAD, 
        game.hourlyRate,
        game.tableName
    );
    return {
      durationSeconds,
      priceMAD: price,
      finalPriceMAD: finalPrice
    };
  }
  return {
    durationSeconds: game.durationSeconds,
    priceMAD: game.priceMAD,
    finalPriceMAD: game.finalPriceMAD,
  };
};

import React, { useState, useEffect } from 'react';
import { Game, GameStatus, PaymentStatus } from '../types';
import { formatCurrency, formatDuration, calculateLivePrice, calculateFinalPrice, getMinPrice } from '../lib/utils';
import { Badge } from './ui/Badge';
import { Button } from './ui/Button';
import { MoreVerticalIcon } from './icons';
import { Input } from './ui/Input';
import { Select } from './ui/Select';
import { TABLES, DEFAULT_HOURLY_RATE } from '../constants';

interface GameRowProps {
  game: Game;
  isAdmin: boolean;
  updateGame?: (gameId: string, updates: Partial<Game>) => void;
  deleteGame?: (gameId:string) => void;
  currentUserId?: string;
}

const GameRow: React.FC<GameRowProps> = ({ game, isAdmin, updateGame, deleteGame, currentUserId }) => {
    // Fallback if game rate is missing (backward compatibility)
    const gameRate = game.hourlyRate || DEFAULT_HOURLY_RATE;

    const calculateCurrentDuration = () => {
        if (game.status === GameStatus.RUNNING) {
            const start = new Date(game.startTime).getTime();
            const now = Date.now();
            return Math.max(0, Math.floor((now - start) / 1000));
        }
        return 0;
    };

    const [liveDuration, setLiveDuration] = useState<number>(calculateCurrentDuration);

    const [livePrice, setLivePrice] = useState<number>(() => {
         if (game.status === GameStatus.RUNNING) {
             return calculateLivePrice(game.startTime, gameRate, game.tableName);
         }
         return 0;
    });

    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [isEditing, setIsEditing] = useState(false);

    const [editableGame, setEditableGame] = useState({
      tableName: game.tableName ?? '',
      hourlyRate: gameRate,
      player1: game.player1,
      player2: game.player2 ?? '',
      winner: game.winner ?? null,
      discountMAD: game.discountMAD ?? 0,
      status: game.status,
      // If the game is starting settlement, default it to Paid instead of Pending
      paymentStatus: game.paymentStatus === PaymentStatus.PENDING ? PaymentStatus.PAID : game.paymentStatus,
      finalPriceMAD: game.finalPriceMAD ?? 0,
    });

    useEffect(() => {
        if (game.status === GameStatus.RUNNING && !isEditing) {
            const updateStats = () => {
                setLiveDuration(calculateCurrentDuration());
                setLivePrice(calculateLivePrice(game.startTime, gameRate, game.tableName));
            };

            updateStats(); // Immediate update on mount/status change

            const interval = setInterval(updateStats, 1000);
            return () => clearInterval(interval);
        }
    }, [game.status, game.startTime, isEditing, gameRate, game.tableName]);

    const resetEditableGame = () => {
        setEditableGame({
            tableName: game.tableName ?? '',
            hourlyRate: gameRate,
            player1: game.player1,
            player2: game.player2 ?? '',
            winner: game.winner ?? null,
            discountMAD: game.discountMAD ?? 0,
            status: game.status,
            paymentStatus: game.paymentStatus === PaymentStatus.PENDING ? PaymentStatus.PAID : game.paymentStatus,
            finalPriceMAD: game.finalPriceMAD ?? 0,
        });
    };

    const startEditing = () => {
        resetEditableGame();
        setIsEditing(true);
        setIsMenuOpen(false);
    };

    const handleTableChange = (tableId: string) => {
        const config = TABLES.find(t => t.id === tableId);
        if (config) {
             setEditableGame({
                 ...editableGame,
                 tableName: config.name,
                 hourlyRate: config.rate
             });
        }
    };

    const handleStatusChange = (newStatus: GameStatus) => {
        let newFinalPrice = editableGame.finalPriceMAD;
        if (game.status === GameStatus.RUNNING && newStatus === GameStatus.FINISHED) {
            const endTime = new Date().toISOString();
            const discount = isAdmin ? Number(editableGame.discountMAD) : game.discountMAD;
            const { finalPrice } = calculateFinalPrice(game.startTime, endTime, discount, editableGame.hourlyRate, editableGame.tableName);
            newFinalPrice = Number(finalPrice.toFixed(2));
        }

        setEditableGame({
            ...editableGame,
            status: newStatus,
            finalPriceMAD: newFinalPrice,
        });
    }

    const handleSaveChanges = () => {
      if (!updateGame || !currentUserId) return;

      const updates: Partial<Game> = {
          tableName: editableGame.tableName,
          hourlyRate: editableGame.hourlyRate,
          player1: editableGame.player1,
          player2: editableGame.player2 || null,
          winner: editableGame.winner,
          paymentStatus: editableGame.paymentStatus,
          modifiedBy: currentUserId,
      };

      if (game.status === GameStatus.RUNNING && editableGame.status === GameStatus.FINISHED) {
          const endTime = new Date().toISOString();
          const discount = isAdmin ? Number(editableGame.discountMAD) : game.discountMAD;
          const { durationSeconds, price, finalPrice } = calculateFinalPrice(game.startTime, endTime, discount, editableGame.hourlyRate, editableGame.tableName);

          updates.status = GameStatus.FINISHED;
          updates.endTime = endTime;
          updates.durationSeconds = durationSeconds;
          updates.priceMAD = price;
          // Ensure we respect the minimum even on save
          updates.finalPriceMAD = Math.max(getMinPrice(editableGame.tableName), Number(editableGame.finalPriceMAD));
          updates.discountMAD = discount;
      } else if (game.status === GameStatus.FINISHED) {
        updates.finalPriceMAD = Number(editableGame.finalPriceMAD);
        if (isAdmin) {
          updates.discountMAD = Number(editableGame.discountMAD);
        }
      }

      updateGame(game.id, updates);
