            <td className="p-4 align-middle hidden md:table-cell">
                <div className="font-semibold">{formatCurrency(priceToDisplay)}</div>
                {game.discountMAD > 0 && <div className="text-xs text-red-400">-{formatCurrency(game.discountMAD)} discount</div>}
            </td>
            <td className="p-4 align-middle hidden sm:table-cell">
                <Badge variant={game.status === GameStatus.RUNNING ? "default" : "secondary"}>{game.status}</Badge>
