            <td className="p-4 align-middle hidden md:table-cell">
                <Badge className={`${paymentStatusBadge[game.paymentStatus]} text-white border-transparent`}>
                    {game.paymentStatus === PaymentStatus.PENDING ? 'Active' : game.paymentStatus}
