interface DailyResumePDFProps {
  games: Game[];
  summaryText: string;
  selectedDate: string;
}

const DailyResumePDF: React.FC<DailyResumePDFProps> = ({ games, summaryText, selectedDate }) => {
    const totals = games.reduce(
        (acc, game) => {
            if (game.paymentStatus === PaymentStatus.PAID) {
                acc.paid += game.finalPriceMAD || 0;
            }
            if (game.paymentStatus === PaymentStatus.LOAN) {
                acc.loan += game.finalPriceMAD || 0;
            }
            acc.discount += game.discountMAD || 0;
            return acc;
        },
        { paid: 0, loan: 0, discount: 0 }
    );

    const getDebtor = (game: Game) => {
        if (game.paymentStatus !== PaymentStatus.LOAN) return '-';
        if (!game.player2) return game.player1;
        if (game.winner === game.player1) return game.player2; // Loser owes
        if (game.winner === game.player2) return game.player1; // Loser owes
        return game.player1; // Default to P1 if no winner marked
    };

    const getGameTime = (game: Game) => {
        const start = new Date(game.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: false });
        const end = game.endTime ? new Date(game.endTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: false }) : '...';
        return `${start}-${end}`;
    };

    return (
        <Document>
        <Page size="A4" style={styles.page}>
            <View style={styles.header}>
                <Text style={styles.title}>Snooker Club Report</Text>
                <Text style={styles.subtitle}>Business Date: {new Date(selectedDate).toDateString()}</Text>
            </View>

            <View style={styles.section}>
                <Text style={styles.sectionTitle}>Manager's Summary</Text>
                <Text style={styles.summaryText}>{summaryText}</Text>
            </View>

            <View style={styles.section}>
                <Text style={styles.sectionTitle}>Game Records</Text>
                <View style={styles.table}>
                    <View style={[styles.tableRow, styles.tableHeader]}>
                        <Text style={[styles.tableCol, styles.colTable]}>Table</Text>
                        <Text style={[styles.tableCol, styles.colPlayers]}>Players</Text>
                        <Text style={[styles.tableCol, styles.colTime]}>Time</Text>
                        <Text style={[styles.tableCol, styles.colDuration]}>Dur.</Text>
                        <Text style={[styles.tableCol, styles.colPrice]}>Price</Text>
                        <Text style={[styles.tableCol, styles.colStatus]}>Type</Text>
                        <Text style={[styles.tableCol, styles.colDebtor]}>Debtor</Text>
                    </View>
                    {games.map(game => (
                        <View key={game.id} style={styles.tableRow}>
                            <Text style={[styles.tableCol, styles.colTable]}>{game.tableName || '-'}</Text>
                            <Text style={[styles.tableCol, styles.colPlayers]}>{game.player1}{game.player2 ? ` vs ${game.player2}` : ''}</Text>
                            <Text style={[styles.tableCol, styles.colTime]}>{getGameTime(game)}</Text>
                            <Text style={[styles.tableCol, styles.colDuration]}>{formatDuration(game.durationSeconds).split(':').slice(0,2).join(':')}</Text>
                            <Text style={[styles.tableCol, styles.colPrice]}>{formatCurrency(game.finalPriceMAD)}</Text>
                            <Text style={[styles.tableCol, styles.colStatus]}>{game.paymentStatus}</Text>
                            <Text style={[styles.tableCol, styles.colDebtor]}>{getDebtor(game)}</Text>
                        </View>
                    ))}
                </View>
            </View>

            <View style={styles.totalsContainer}>
                 <View style={styles.totalRow}>
                    <Text style={styles.totalLabel}>Paid Income:</Text>
                    <Text>{formatCurrency(totals.paid)}</Text>
                 </View>
                 <View style={styles.totalRow}>
                    <Text style={styles.totalLabel}>New Loans:</Text>
                    <Text>{formatCurrency(totals.loan)}</Text>
                 </View>
                 <View style={styles.totalRow}>
                    <Text style={styles.totalLabel}>Discounts:</Text>
                    <Text>{formatCurrency(totals.discount)}</Text>
                 </View>
                 <View style={[styles.totalRow, { marginTop: 5, borderTopWidth: 1, paddingTop: 5 }]}>
                    <Text style={[styles.totalLabel, { fontSize: 11 }]}>Total Value:</Text>
                    <Text style={{ fontSize: 11, fontFamily: 'Helvetica-Bold' }}>{formatCurrency(totals.paid + totals.loan)}</Text>
                 </View>
            </View>
        </Page>
        </Document>
    );
};

