import React, { useState } from 'react';
import { PDFDownloadLink } from '@react-pdf/renderer';
import { Game } from '../types';
import DailyResumePDF from './DailyResumePDF';
import { Button } from './ui/Button';
import { generateDailySummaryText } from '../services/geminiService';
import { LoaderCircle, CheckCircle } from './icons';

interface PrintResumeButtonProps {
  games: Game[];
  selectedDate: string;
}

const PrintResumeButton: React.FC<PrintResumeButtonProps> = ({ games, selectedDate }) => {
  const [summaryText, setSummaryText] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isReady, setIsReady] = useState(false);

  const handleGenerate = async () => {
    setIsGenerating(true);
    setIsReady(false);
    try {
      const summary = await generateDailySummaryText(games);
      setSummaryText(summary);
      setIsReady(true);
    } catch (error) {
      console.error('Error generating summary:', error);
      alert('Failed to generate summary. Please try again.');
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="flex items-center gap-2">
      {!isReady ? (
        <Button onClick={handleGenerate} disabled={isGenerating || games.length === 0}>
          {isGenerating ? (
            <>
              <LoaderCircle className="mr-2 h-4 w-4 animate-spin" />
              Preparing Report...
            </>
          ) : (
            'Generate PDF Data'
          )}
        </Button>
      ) : (
        <PDFDownloadLink
          document={<DailyResumePDF games={games} summaryText={summaryText} selectedDate={selectedDate} />}
          fileName={`snooker-report-${selectedDate}.pdf`}
        >
          {({ loading }) => (
            <Button variant="secondary" className="bg-green-600 text-white hover:bg-green-700" disabled={loading}>
              {loading ? (
                <>
                  <LoaderCircle className="mr-2 h-4 w-4 animate-spin" />
                  Building PDF...
                </>
              ) : (
                <>
                  <CheckCircle className="mr-2 h-4 w-4" />
                  Download PDF Report
                </>
              )}
            </Button>
          )}
        </PDFDownloadLink>
      )}

      {isReady && (
          <Button variant="ghost" size="sm" onClick={() => setIsReady(false)}>
              Reset
          </Button>
      )}
    </div>
  );
};

