const DailyResumePDF: React.FC<DailyResumePDFProps> = ({ games, summaryText, selectedDate }) => {
    const totals = games.reduce(
        (acc, game) => {
            if (game.paymentStatus === PaymentStatus.PAID) {
                acc.paid += game.finalPriceMAD || 0;
            }
            if (game.paymentStatus === PaymentStatus.LOAN) {
                acc.loan += game.finalPriceMAD || 0;
            }
            acc.discount += game.discountMAD || 0;
            return acc;
        },
        { paid: 0, loan: 0, discount: 0 }
    );

    const getDebtor = (game: Game) => {
        if (game.paymentStatus !== PaymentStatus.LOAN) return '-';
        if (!game.player2) return game.player1;
        if (game.winner === game.player1) return game.player2; // Loser owes
        if (game.winner === game.player2) return game.player1; // Loser owes
        return game.player1; // Default
