                    <Text>{formatCurrency(totals.discount)}</Text>
                 </View>
                 <View style={[styles.totalRow, { marginTop: 5, borderTopWidth: 1, paddingTop: 5 }]}>
                    <Text style={[styles.totalLabel, { fontSize: 10 }]}>Total:</Text>
                    <Text style={{ fontSize: 10, fontFamily: 'Helvetica-Bold' }}>{formatCurrency(totals.paid + totals.loan)}</Text>
                 </View>
            </View>
        </Page>
        </Document>
    );
};

