import React, { useState, useMemo, useEffect } from 'react';
import { Game, PaymentStatus, GameStatus, DailySummary } from '../types';
import GamesTable from '../components/GamesTable';
import KpiCard from '../components/KpiCard';
import { formatCurrency } from '../lib/utils';
import { Input } from '../components/ui/Input';
import { DollarSignIcon, HashIcon, ClockIcon, AlertTriangle, TrophyIcon, UsersIcon, LoaderCircle, ExternalLinkIcon, CheckCircle } from '../components/icons';
import PrintResumeButton from '../components/PrintResumeButton';
import { useAuth } from '../hooks/useAuth';
import { useGames } from '../hooks/useGames';
import { useBusinessDay } from '../hooks/useBusinessDay';
import UserManagement from '../components/UserManagement';
import AnalyticsCard from '../components/AnalyticsCard';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '../components/ui/Card';
import { Button } from '../components/ui/Button';
import { Badge } from '../components/ui/Badge';
import DailyClosureReport from '../components/DailyClosureReport';

const AdminPage: React.FC = () => {
  const { user } = useAuth();
  const { games, updateGame, deleteGame, saveDailySummary, sheetUrl, spreadsheetViewUrl, error: gameError } = useGames();
  const { businessDate, advanceDay } = useBusinessDay();
  const [selectedDate, setSelectedDate] = useState(businessDate);
  const [isArchiving, setIsArchiving] = useState(false);
  const [showClosureReport, setShowClosureReport] = useState(false);
  const [closureDate, setClosureDate] = useState('');
  const [closureGames, setClosureGames] = useState<Game[]>([]);

  useEffect(() => {
    setSelectedDate(businessDate);
  }, [businessDate]);

  const filteredGames = useMemo(() => {
    return games
      .filter(game => game.date === selectedDate)
      .sort((a, b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime());
  }, [games, selectedDate]);

  const dailyStats = useMemo(() => {
    const currentDayGames = games.filter(g => g.date === businessDate);
    const incomePaid = currentDayGames
      .filter(g => g.paymentStatus === PaymentStatus.PAID)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const allTimeLoans = games
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    return {
      totalGames: currentDayGames.length,
      incomePaid,
      loansOutstanding: allTimeLoans,
    };
  }, [games, businessDate]);

  const receiptStats = useMemo(() => {
      return filteredGames.reduce(
          (acc, game) => {
              if (game.paymentStatus === PaymentStatus.PAID) {
                  acc.paid += game.finalPriceMAD || 0;
              }
              if (game.paymentStatus === PaymentStatus.LOAN) {
                  acc.loan += game.finalPriceMAD || 0;
              }
              acc.discount += game.discountMAD || 0;
              return acc;
          },
          { paid: 0, loan: 0, discount: 0 }
      );
  }, [filteredGames]);

  // Comprehensive Loan List
  const allLoans = useMemo(() => {
    return games
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [games]);

  const getDebtorName = (loan: Game) => {
    if (!loan.player2) return loan.player1;
    if (loan.winner === loan.player1) return loan.player2; // Loser owes
    if (loan.winner === loan.player2) return loan.player1; // Loser owes
    return `${loan.player1}${loan.player2 ? ' & ' + loan.player2 : ''}`;
  };

  const formatGameTime = (loan: Game) => {
    const start = new Date(loan.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    const end = loan.endTime ? new Date(loan.endTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '...';
    return `${start} - ${end}`;
  };

  const analyticsData = useMemo(() => {
    const playerStats: { [key: string]: { paid: number; loan: number; wins: number } } = {};

    const addPlayerStat = (player: string | null, key: 'paid' | 'loan', value: number) => {
        if (!player || value <= 0) return;
        if (!playerStats[player]) {
            playerStats[player] = { paid: 0, loan: 0, wins: 0 };
        }
        playerStats[player][key] += value;
    };

    games.forEach(game => {
        if (game.status !== GameStatus.FINISHED || !game.finalPriceMAD) {
            return;
        }

        const { player1, player2, winner, finalPriceMAD, paymentStatus } = game;

        if (paymentStatus === PaymentStatus.PAID) {
            const amount = player2 ? finalPriceMAD / 2 : finalPriceMAD;
            addPlayerStat(player1, 'paid', amount);
            addPlayerStat(player2, 'paid', amount);
        } else if (paymentStatus === PaymentStatus.LOAN) {
            let loanee = player1;
            if (player2) {
                if (winner && winner === player1) loanee = player2;
                else if (winner && winner === player2) loanee = player1;
            }
            addPlayerStat(loanee, 'loan', finalPriceMAD);
        }

        if (winner) {
            if (!playerStats[winner]) playerStats[winner] = { paid: 0, loan: 0, wins: 0 };
            playerStats[winner].wins += 1;
        }
    });

    const allPlayers = Object.entries(playerStats).map(([name, stats]) => ({ name, ...stats }));
    const topWinners = [...allPlayers].sort((a, b) => b.wins - a.wins).filter(p => p.wins > 0).slice(0, 5);
    const topPaid = [...allPlayers].sort((a, b) => b.paid - a.paid).filter(p => p.paid > 0).slice(0, 5);
    const playersWithLoans = [...allPlayers].sort((a, b) => b.loan - a.loan).filter(p => p.loan > 0);

    return { topWinners, topPaid, playersWithLoans };
  }, [games]);

  const handleAdvanceDay = async () => {
    if (!window.confirm("Are you sure you want to end the current business day? All stats for today will be archived and a final invoice will be generated.")) return;

    setIsArchiving(true);
    // Capture data for report before advancing
    const reportDate = businessDate;
    const reportGames = [...filteredGames];

    try {
      const summary: DailySummary = {
        date: businessDate,
        totalPaid: receiptStats.paid,
        totalLoan: receiptStats.loan,
        totalDiscount: receiptStats.discount,
        gameCount: filteredGames.length,
        archivedAt: new Date().toISOString()
      };

      await saveDailySummary(summary);
      await advanceDay();

      // Successfully archived, show the report
      setClosureDate(reportDate);
      setClosureGames(reportGames);
      setShowClosureReport(true);
    } catch (e) {
      console.error("Failed to archive summary", e);
      alert("Error archiving summary. Please try again.");
    } finally {
      setIsArchiving(false);
    }
  };

  const settleLoan = async (gameId: string) => {
    if (!window.confirm("Mark this loan as fully paid?")) return;
    try {
        await updateGame(gameId, { paymentStatus: PaymentStatus.PAID });
    } catch (e) {
        console.error("Failed to settle loan", e);
    }
  };

  if (!user) return null;

  if (showClosureReport) {
      return (
        <DailyClosureReport 
            date={closureDate} 
            games={closureGames} 
            onBack={() => setShowClosureReport(false)} 
        />
      );
  }

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Admin Dashboard</h1>
          <p className="text-muted-foreground">Club overview for {new Date(businessDate + 'T00:00:00').toDateString()}.</p>
        </div>
        {!sheetUrl && (
          <Badge variant="outline" className="text-amber-500 border-amber-500 bg-amber-500/10">
            <AlertTriangle className="h-3 w-3 mr-1" /> Not connected to Google Sheets
          </Badge>
        )}
      </div>

      {gameError && (
        <div className="p-4 bg-destructive/10 border border-destructive/20 rounded-md text-destructive flex items-center gap-3">
            <AlertTriangle className="h-5 w-5"/>
            <div>
                <h4 className="font-bold">Connection Error</h4>
                <p className="text-sm">{gameError}</p>
            </div>
        </div>
      )}

      <div className="grid gap-4 md:grid-cols-3">
        <KpiCard title="Total Games (Current Day)" value={dailyStats.totalGames.toString()} icon={<HashIcon />} />
        <KpiCard title="Income (Current Day)" value={`${dailyStats.incomePaid.toFixed(2)} MAD`} icon={<DollarSignIcon />} />
        <KpiCard title="Total Loans Outstanding" value={`${dailyStats.loansOutstanding.toFixed(2)} MAD`} icon={<ClockIcon />} />
      </div>

      <div className="grid gap-4 md:grid-cols-2">
          <Card>
              <CardHeader>
                  <CardTitle>Daily Receipt for {new Date(selectedDate + 'T00:00:00').toDateString()}</CardTitle>
                  <CardDescription>Financial activity for the selected date.</CardDescription>
              </CardHeader>
              <CardContent className="grid gap-4 text-sm">
                  <div className="flex items-center justify-between p-3 border rounded-md bg-background">
                      <span className="text-muted-foreground">Income (Paid):</span>
                      <span className="font-bold text-green-600">{formatCurrency(receiptStats.paid)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border rounded-md bg-background">
                      <span className="text-muted-foreground">New Loans:</span>
                      <span className="font-bold text-amber-600">{formatCurrency(receiptStats.loan)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border rounded-md bg-background">
                      <span className="text-muted-foreground">Discounts Given:</span>
                      <span className="font-bold text-red-600">{formatCurrency(receiptStats.discount)}</span>
                  </div>
              </CardContent>
          </Card>

          <Card className="border-amber-200 dark:border-amber-900/50">
              <CardHeader className="flex flex-row items-center justify-between space-y-0">
                  <div>
                    <CardTitle className="flex items-center gap-2">
                        <ClockIcon className="h-5 w-5 text-amber-500" />
                        Global Debt Tracker
                    </CardTitle>
                    <CardDescription>All loans with Loser, Table, and Time.</CardDescription>
                  </div>
                  <Badge variant="outline" className="bg-amber-500/10 text-amber-600">{allLoans.length} Loans</Badge>
              </CardHeader>
              <CardContent className="h-[210px] overflow-y-auto">
                  {allLoans.length > 0 ? (
                    <div className="space-y-3">
                        {allLoans.map((loan) => (
                            <div key={loan.id} className="flex items-center justify-between p-2 rounded-lg bg-muted/30 border border-transparent hover:border-amber-500/30 transition-all">
                                <div className="grid gap-0.5">
                                    <span className="font-bold text-sm text-foreground">
                                        {getDebtorName(loan)} <span className="text-[10px] text-muted-foreground font-normal">(Debtor)</span>
                                    </span>
                                    <div className="flex flex-wrap items-center gap-x-2 gap-y-0.5 text-[11px] text-muted-foreground">
                                        <div className="flex items-center gap-1">
                                            <ClockIcon className="h-3 w-3" />
                                            <span>{new Date(loan.date + 'T00:00:00').toLocaleDateString('en-GB')}</span>
                                        </div>
                                        <span className="opacity-30">|</span>
                                        <span>{formatGameTime(loan)}</span>
                                        <span className="opacity-30">|</span>
                                        <span className="font-medium text-amber-600/80">{loan.tableName}</span>
                                    </div>
                                </div>
                                <div className="flex items-center gap-3">
                                    <span className="font-bold text-amber-600">{formatCurrency(loan.finalPriceMAD)}</span>
                                    <Button size="icon" variant="ghost" className="h-8 w-8 text-green-600 hover:bg-green-500/10" onClick={() => settleLoan(loan.id)} title="Mark as Paid">
                                        <CheckCircle className="h-4 w-4" />
                                    </Button>
                                </div>
                            </div>
                        ))}
                    </div>
                  ) : (
                    <div className="flex flex-col items-center justify-center h-full text-muted-foreground gap-2">
                        <CheckCircle className="h-8 w-8 opacity-20" />
                        <p className="text-sm">No outstanding debts!</p>
                    </div>
                  )}
              </CardContent>
          </Card>
      </div>

      <div className="space-y-4">
        <h2 className="text-2xl font-bold">Player Analytics</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            <AnalyticsCard title="Top Winners" icon={<TrophyIcon />}>
                {analyticsData.topWinners.length > 0 ? (
                    analyticsData.topWinners.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-sm py-1.5 border-b last:border-b-0">
                            <span>{player.name}</span>
                            <span className="font-semibold">{player.wins} Wins</span>
                        </div>
                    ))
                ) : (
                    <p className="text-sm text-muted-foreground">No data.</p>
                )}
            </AnalyticsCard>

            <AnalyticsCard title="Top Spenders (Paid)" icon={<DollarSignIcon />}>
                    {analyticsData.topPaid.length > 0 ? (
                    analyticsData.topPaid.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-sm py-1.5 border-b last:border-b-0">
                            <span>{player.name}</span>
                            <span className="font-semibold">{formatCurrency(player.paid)}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-sm text-muted-foreground">No data.</p>
                )}
            </AnalyticsCard>

            <AnalyticsCard title="Debtor Summary" icon={<UsersIcon />}>
                {analyticsData.playersWithLoans.length > 0 ? (
                    analyticsData.playersWithLoans.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-sm py-1.5 border-b last:border-b-0">
                            <span>{player.name}</span>
                            <span className="font-semibold text-destructive">{formatCurrency(player.loan)}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-sm text-muted-foreground">None.</p>
                )}
            </AnalyticsCard>
        </div>
      </div>

      <div className="space-y-4">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
            <h2 className="text-2xl font-bold">Game Records</h2>
            <div className="flex flex-wrap items-center gap-2">
                <Input
                    type="date"
                    value={selectedDate}
                    onChange={e => setSelectedDate(e.target.value)}
                    className="w-[180px]"
                />
                <PrintResumeButton games={filteredGames} selectedDate={selectedDate} />
                {spreadsheetViewUrl && (
                    <Button variant="outline" asChild>
                        <a href={spreadsheetViewUrl} target="_blank" rel="noopener noreferrer">
                            <ExternalLinkIcon className="mr-2 h-4 w-4" />
                            View Google Sheet
                        </a>
                    </Button>
                )}
                <Button 
                    onClick={handleAdvanceDay} 
