import React, { useState } from 'react';
import { Game } from '../types';
import { Button } from './ui/Button';
import { generateDailySummaryText } from '../services/geminiService';
import { LoaderCircle, PrinterIcon } from './icons';
import DailyClosureReport from './DailyClosureReport';

interface PrintResumeButtonProps {
  games: Game[];
  selectedDate: string;
}

const PrintResumeButton: React.FC<PrintResumeButtonProps> = ({ games, selectedDate }) => {
  const [summaryText, setSummaryText] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [showReport, setShowReport] = useState(false);

  const handlePrepare = async () => {
    setIsGenerating(true);
    try {
      const summary = await generateDailySummaryText(games);
      setSummaryText(summary);
      setShowReport(true);
    } catch (error) {
      console.error('Error generating summary:', error);
      alert('Failed to generate summary. Please try again.');
    } finally {
      setIsGenerating(false);
    }
  };

  if (showReport) {
      return (
          <div className="fixed inset-0 z-[100] bg-background overflow-y-auto">
              <DailyClosureReport 
                date={selectedDate} 
                games={games} 
                onBack={() => setShowReport(false)} 
                summaryText={summaryText}
                isArchiveView={true}
              />
          </div>
      );
  }

  return (
    <Button 
        onClick={handlePrepare} 
        disabled={isGenerating || games.length === 0}
        variant="outline"
        className="gap-2"
    >
      {isGenerating ? (
        <>
          <LoaderCircle className="h-4 w-4 animate-spin" />
          Preparing Report...
        </>
      ) : (
        <>
          <PrinterIcon className="h-4 w-4" />
          Print Daily Record
        </>
      )}
    </Button>
  );
};

