import React, { useState, useMemo, useEffect } from 'react';
import { Game, PaymentStatus, GameStatus, DailySummary } from '../types';
import GamesTable from '../components/GamesTable';
import KpiCard from '../components/KpiCard';
import { formatCurrency } from '../lib/utils';
import { Input } from '../components/ui/Input';
import { DollarSignIcon, HashIcon, ClockIcon, AlertTriangle, TrophyIcon, UsersIcon, LoaderCircle, ExternalLinkIcon, CheckCircle } from '../components/icons';
import PrintResumeButton from '../components/PrintResumeButton';
import { useAuth } from '../hooks/useAuth';
import { useGames } from '../hooks/useGames';
import { useBusinessDay } from '../hooks/useBusinessDay';
import UserManagement from '../components/UserManagement';
import AnalyticsCard from '../components/AnalyticsCard';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '../components/ui/Card';
import { Button } from '../components/ui/Button';
import { Badge } from '../components/ui/Badge';
import DailyClosureReport from '../components/DailyClosureReport';

const AdminPage: React.FC = () => {
  const { user } = useAuth();
  const { games, updateGame, deleteGame, saveDailySummary, sheetUrl, spreadsheetViewUrl, error: gameError } = useGames();
  const { businessDate, advanceDay } = useBusinessDay();
  const [selectedDate, setSelectedDate] = useState(businessDate);
  const [isArchiving, setIsArchiving] = useState(false);
  const [showClosureReport, setShowClosureReport] = useState(false);
  const [closureDate, setClosureDate] = useState('');
  const [closureGames, setClosureGames] = useState<Game[]>([]);

  const isLiveDay = selectedDate === businessDate;

  useEffect(() => {
    // If business date changes (e.g. from another tab), update selected date if we were on the live day
    if (isLiveDay) {
        setSelectedDate(businessDate);
    }
  }, [businessDate]);

  const filteredGames = useMemo(() => {
    return games
      .filter(game => game.date === selectedDate)
      .sort((a, b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime());
  }, [games, selectedDate]);

  // These stats are reactive to the SELECTED date
  const selectedDayStats = useMemo(() => {
    const incomePaid = filteredGames
      .filter(g => g.paymentStatus === PaymentStatus.PAID)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const dayLoans = filteredGames
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const discounts = filteredGames
      .reduce((sum, g) => sum + (g.discountMAD || 0), 0);

    return {
      totalGames: filteredGames.length,
      incomePaid,
      dayLoans,
      discounts,
      runningCount: filteredGames.filter(g => g.status === GameStatus.RUNNING).length
    };
  }, [filteredGames]);

  // Global loans (unpaid across all time)
  const globalOutstandingLoans = useMemo(() => {
      return games
        .filter(g => g.paymentStatus === PaymentStatus.LOAN)
        .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);
  }, [games]);

  // Comprehensive Loan List (Global)
  const allLoansList = useMemo(() => {
    return games
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [games]);

  const getDebtorName = (loan: Game) => {
    if (!loan.player2) return loan.player1;
    if (loan.winner === loan.player1) return loan.player2; // Loser owes
    if (loan.winner === loan.player2) return loan.player1; // Loser owes
    return `${loan.player1}${loan.player2 ? ' & ' + loan.player2 : ''}`;
  };

  const formatGameTime = (loan: Game) => {
    const start = new Date(loan.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    const end = loan.endTime ? new Date(loan.endTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '...';
    return `${start} - ${end}`;
  };

  const analyticsData = useMemo(() => {
    const playerStats: { [key: string]: { paid: number; loan: number; wins: number } } = {};

    const addPlayerStat = (player: string | null, key: 'paid' | 'loan', value: number) => {
        if (!player || value <= 0) return;
        if (!playerStats[player]) {
            playerStats[player] = { paid: 0, loan: 0, wins: 0 };
        }
        playerStats[player][key] += value;
    };

    games.forEach(game => {
        if (game.status !== GameStatus.FINISHED || !game.finalPriceMAD) {
            return;
        }

        const { player1, player2, winner, finalPriceMAD, paymentStatus } = game;

        if (paymentStatus === PaymentStatus.PAID) {
            const amount = player2 ? finalPriceMAD / 2 : finalPriceMAD;
            addPlayerStat(player1, 'paid', amount);
            addPlayerStat(player2, 'paid', amount);
        } else if (paymentStatus === PaymentStatus.LOAN) {
            let loanee = player1;
            if (player2) {
                if (winner && winner === player1) loanee = player2;
                else if (winner && winner === player2) loanee = player1;
            }
            addPlayerStat(loanee, 'loan', finalPriceMAD);
        }

        if (winner) {
            if (!playerStats[winner]) playerStats[winner] = { paid: 0, loan: 0, wins: 0 };
            playerStats[winner].wins += 1;
        }
    });

    const allPlayers = Object.entries(playerStats).map(([name, stats]) => ({ name, ...stats }));
    const topWinners = [...allPlayers].sort((a, b) => b.wins - a.wins).filter(p => p.wins > 0).slice(0, 5);
    const topPaid = [...allPlayers].sort((a, b) => b.paid - a.paid).filter(p => p.paid > 0).slice(0, 5);
    const playersWithLoans = [...allPlayers].sort((a, b) => b.loan - a.loan).filter(p => p.loan > 0);

    return { topWinners, topPaid, playersWithLoans };
  }, [games]);

  const handleAdvanceDay = async () => {
    // Check for running games
    if (selectedDayStats.runningCount > 0) {
        alert(`Cannot end the day while ${selectedDayStats.runningCount} games are still running. Please finish all games first.`);
        return;
    }

    if (!window.confirm("End Session: All data for today will be locked and archived. Start a new business session?")) return;

    setIsArchiving(true);
    const reportDate = businessDate;
    const reportGames = [...filteredGames];

    try {
      const summary: DailySummary = {
        date: businessDate,
        totalPaid: selectedDayStats.incomePaid,
        totalLoan: selectedDayStats.dayLoans,
        totalDiscount: selectedDayStats.discounts,
        gameCount: selectedDayStats.totalGames,
        archivedAt: new Date().toISOString()
      };

      await saveDailySummary(summary);
      await advanceDay();

      setClosureDate(reportDate);
      setClosureGames(reportGames);
      setShowClosureReport(true);
    } catch (e) {
      console.error("Failed to archive summary", e);
      alert("Error archiving session data.");
    } finally {
      setIsArchiving(false);
    }
  };

  const settleLoan = async (gameId: string) => {
    if (!window.confirm("Settle this debt?")) return;
    try {
        await updateGame(gameId, { paymentStatus: PaymentStatus.PAID });
    } catch (e) {
        console.error("Failed to settle loan", e);
    }
  };

  if (!user) return null;

  if (showClosureReport) {
      return (
        <DailyClosureReport 
            date={closureDate} 
            games={closureGames} 
            onBack={() => setShowClosureReport(false)} 
        />
      );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <div className="flex items-center gap-3">
            <h1 className="text-3xl font-black tracking-tighter uppercase">Admin Control</h1>
            {isLiveDay ? (
                <Badge className="bg-green-600 hover:bg-green-600 animate-pulse border-none px-3">Active Session (LIVE)</Badge>
            ) : (
                <Badge variant="outline" className="text-muted-foreground border-muted-foreground px-3">Archive View</Badge>
            )}
          </div>
          <p className="text-muted-foreground mt-1">
            Viewing records for {new Date(selectedDate + 'T00:00:00').toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}
          </p>
        </div>
        <div className="flex items-center gap-3 bg-muted/50 p-2 rounded-lg border">
            <span className="text-xs font-bold uppercase text-muted-foreground px-2">Jump to Date:</span>
            <Input
                type="date"
                value={selectedDate}
                onChange={e => setSelectedDate(e.target.value)}
                className="w-[180px] bg-background h-9"
            />
        </div>
      </div>

      {gameError && (
        <div className="p-4 bg-destructive/10 border border-destructive/20 rounded-md text-destructive flex items-center gap-3">
            <AlertTriangle className="h-5 w-5"/>
            <div>
                <h4 className="font-bold">Database Error</h4>
                <p className="text-sm">{gameError}</p>
            </div>
        </div>
      )}

      {/* KPI Section */}
      <div className="grid gap-4 md:grid-cols-4">
        <KpiCard title="Session Games" value={selectedDayStats.totalGames.toString()} icon={<HashIcon />} />
        <KpiCard title="Session Cash" value={`${selectedDayStats.incomePaid.toFixed(2)} MAD`} icon={<DollarSignIcon />} />
        <KpiCard title="Session Loans" value={`${selectedDayStats.dayLoans.toFixed(2)} MAD`} icon={<ClockIcon />} />
        <KpiCard title="Global Debt" value={`${globalOutstandingLoans.toFixed(2)} MAD`} icon={<AlertTriangle className="text-amber-500" />} />
      </div>

      <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          {/* Daily Receipt Card */}
          <Card className="lg:col-span-1 shadow-sm">
              <CardHeader className="bg-muted/30 pb-4">
                  <CardTitle className="text-lg">Daily Receipt</CardTitle>
                  <CardDescription>Financial outcome for this specific date.</CardDescription>
              </CardHeader>
              <CardContent className="grid gap-4 pt-6">
                  <div className="flex items-center justify-between p-3 border-2 border-green-500/10 rounded-xl bg-green-50/30 dark:bg-green-950/10">
                      <span className="text-xs font-bold uppercase text-green-600/70">Total Paid:</span>
                      <span className="font-black text-green-600">{formatCurrency(selectedDayStats.incomePaid)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border-2 border-amber-500/10 rounded-xl bg-amber-50/30 dark:bg-amber-950/10">
                      <span className="text-xs font-bold uppercase text-amber-600/70">Total Loaned:</span>
                      <span className="font-black text-amber-600">{formatCurrency(selectedDayStats.dayLoans)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border border-dashed rounded-xl">
                      <span className="text-xs font-bold uppercase text-muted-foreground">Total Discounts:</span>
                      <span className="font-bold text-muted-foreground">{formatCurrency(selectedDayStats.discounts)}</span>
                  </div>
                  <div className="pt-4 border-t-2 border-zinc-900 dark:border-white mt-2">
                      <div className="flex justify-between items-center px-1">
                          <span className="font-black text-sm uppercase">Gross Total:</span>
                          <span className="text-xl font-black">{formatCurrency(selectedDayStats.incomePaid + selectedDayStats.dayLoans)}</span>
                      </div>
                  </div>
              </CardContent>
          </Card>

          {/* Debt Tracker Card */}
          <Card className="lg:col-span-2 border-amber-200 dark:border-amber-900/50 shadow-md">
              <CardHeader className="flex flex-row items-center justify-between bg-amber-50/50 dark:bg-amber-950/10 pb-4">
                  <div>
                    <CardTitle className="flex items-center gap-2 text-amber-700 dark:text-amber-400">
                        <ClockIcon className="h-5 w-5" />
                        Global Debt List
                    </CardTitle>
                    <CardDescription>All unpaid games across all history.</CardDescription>
                  </div>
                  <Badge className="bg-amber-500">{allLoansList.length} Unpaid</Badge>
              </CardHeader>
              <CardContent className="h-[280px] overflow-y-auto pt-4">
                  {allLoansList.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {allLoansList.map((loan) => (
                            <div key={loan.id} className="flex items-center justify-between p-3 rounded-xl bg-muted/30 border border-transparent hover:border-amber-500/30 transition-all">
                                <div className="grid gap-0.5">
                                    <span className="font-black text-sm text-foreground uppercase tracking-tight">
                                        {getDebtorName(loan)}
                                    </span>
                                    <div className="flex items-center gap-2 text-[10px] text-muted-foreground">
                                        <span className="font-bold text-amber-600/80">{loan.tableName}</span>
                                        <span>•</span>
                                        <span>{new Date(loan.date + 'T00:00:00').toLocaleDateString('en-GB')}</span>
                                    </div>
                                </div>
                                <div className="flex items-center gap-3">
                                    <span className="font-bold text-amber-600">{formatCurrency(loan.finalPriceMAD)}</span>
                                    <Button size="icon" variant="ghost" className="h-8 w-8 text-green-600 hover:bg-green-500/10 rounded-full" onClick={() => settleLoan(loan.id)}>
                                        <CheckCircle className="h-5 w-5" />
                                    </Button>
                                </div>
                            </div>
                        ))}
                    </div>
                  ) : (
                    <div className="flex flex-col items-center justify-center h-full text-muted-foreground gap-2 opacity-50">
                        <CheckCircle className="h-12 w-12" />
                        <p className="text-sm font-medium">Clear Account: No current debts.</p>
                    </div>
                  )}
              </CardContent>
          </Card>
      </div>

      <div className="space-y-4">
        <div className="flex items-center justify-between border-b pb-4">
            <h2 className="text-2xl font-black uppercase tracking-tighter">Player Analytics</h2>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            <AnalyticsCard title="Hall of Fame" icon={<TrophyIcon className="text-yellow-500" />}>
                {analyticsData.topWinners.length > 0 ? (
                    analyticsData.topWinners.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-sm py-2 border-b border-dashed last:border-b-0">
                            <span className="font-bold">{player.name}</span>
