                    <p className="text-sm text-muted-foreground italic py-4">No data yet.</p>
                )}
            </AnalyticsCard>

            <AnalyticsCard title="Top Customers" icon={<DollarSignIcon className="text-green-500" />}>
                    {analyticsData.topPaid.length > 0 ? (
                    analyticsData.topPaid.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-sm py-2 border-b border-dashed last:border-b-0">
                            <span className="font-bold">{player.name}</span>
                            <span className="font-black text-green-600">{formatCurrency(player.paid)}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-sm text-muted-foreground italic py-4">No data yet.</p>
                )}
            </AnalyticsCard>

            <AnalyticsCard title="Debtor Summary" icon={<UsersIcon className="text-red-500" />}>
                {analyticsData.playersWithLoans.length > 0 ? (
                    analyticsData.playersWithLoans.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-sm py-2 border-b border-dashed last:border-b-0">
                            <span className="font-bold">{player.name}</span>
                            <span className="font-black text-destructive">{formatCurrency(player.loan)}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-sm text-muted-foreground italic py-4">Clean records.</p>
                )}
            </AnalyticsCard>
        </div>
      </div>

      <div className="space-y-4">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4 border-b pb-4">
            <h2 className="text-2xl font-black uppercase tracking-tighter">Session Logs</h2>
            <div className="flex flex-wrap items-center gap-2">
                <PrintResumeButton games={filteredGames} selectedDate={selectedDate} />

                {isLiveDay && (
                    <Button 
                        onClick={handleAdvanceDay} 
                        disabled={isArchiving} 
                        className="bg-primary hover:bg-primary/90 font-black uppercase tracking-widest px-6"
                    >
                        {isArchiving ? (
                            <>
                                <LoaderCircle className="mr-2 h-4 w-4 animate-spin" />
                                Archiving...
                            </>
                        ) : (
                            "End Session & Archive"
                        )}
                    </Button>
                )}
            </div>
        </div>
        <GamesTable 
            games={filteredGames} 
            isAdmin={true} 
            updateGame={updateGame} 
            deleteGame={deleteGame}
            currentUserId={user.id}
        />
      </div>

      <div className="pt-12">
        <h2 className="text-2xl font-black uppercase tracking-tighter border-b pb-4 mb-6">User Access Control</h2>
        <UserManagement />
      </div>

    </div>
  );
};

