import React, { createContext, useState, ReactNode, useCallback, useEffect } from 'react';
import { supabase, isMissingTableError } from '../lib/supabase';

const getTodayDateString = () => {
    const today = new Date();
    // Return YYYY-MM-DD in local time
    return `${today.getFullYear()}-${String(today.getMonth() + 1).padStart(2, '0')}-${String(today.getDate()).padStart(2, '0')}`;
};

interface BusinessDayContextType {
  businessDate: string;
  advanceDay: () => Promise<void>;
  isLoading: boolean;
  isTableMissing: boolean;
}

export const BusinessDayContext = createContext<BusinessDayContextType | undefined>(undefined);

const CONFIG_KEY = 'business_date';
const BUSINESS_DATE_CACHE_KEY = 'snooker_business_date_cache';

export const BusinessDayProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [businessDate, setBusinessDate] = useState<string>(() => {
    return localStorage.getItem(BUSINESS_DATE_CACHE_KEY) || getTodayDateString();
  });
  const [isLoading, setIsLoading] = useState(true);
  const [isTableMissing, setIsTableMissing] = useState(false);

  const fetchConfig = useCallback(async () => {
    setIsTableMissing(false);
    try {
      const { data, error } = await supabase
        .from('app_config')
        .select('value')
        .eq('key', CONFIG_KEY)
        .single();

      if (error) {
          if (isMissingTableError(error)) {
              setIsTableMissing(true);
              return;
          }
          if (error.code === 'PGRST116') {
              // Row not found, try to create it
              const today = getTodayDateString();
              await supabase.from('app_config').upsert([{ key: CONFIG_KEY, value: today }]);
              setBusinessDate(today);
              localStorage.setItem(BUSINESS_DATE_CACHE_KEY, today);
          } else {
              throw error;
          }
      } else if (data) {
        setBusinessDate(data.value);
        localStorage.setItem(BUSINESS_DATE_CACHE_KEY, data.value);
      }
    } catch (err: any) {
      console.warn('Config fetch failed, using local/cached date');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchConfig();

    const channel = supabase
      .channel('public:app_config')
      .on('postgres_changes', { event: 'UPDATE', table: 'app_config', schema: 'public' }, (payload) => {
        if (payload.new && payload.new.key === CONFIG_KEY) {
            setBusinessDate(payload.new.value);
            localStorage.setItem(BUSINESS_DATE_CACHE_KEY, payload.new.value);
        }
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [fetchConfig]);

  const advanceDay = useCallback(async () => {
    // Robust date increment without timezone bugs
    const [year, month, day] = businessDate.split('-').map(Number);
    const date = new Date(year, month - 1, day);
    date.setDate(date.getDate() + 1);

    const nextDateStr = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;

    try {
        const { error } = await supabase
            .from('app_config')
            .update({ value: nextDateStr })
            .eq('key', CONFIG_KEY);

        if (error) throw error;

        setBusinessDate(nextDateStr);
        localStorage.setItem(BUSINESS_DATE_CACHE_KEY, nextDateStr);
    } catch (err: any) {
        console.error('Error advancing day:', err.message);
        // Fallback to local advancement if DB fails (offline support)
        setBusinessDate(nextDateStr);
        localStorage.setItem(BUSINESS_DATE_CACHE_KEY, nextDateStr);
    }
  }, [businessDate]);

  return (
    <BusinessDayContext.Provider value={{ businessDate, advanceDay, isLoading, isTableMissing }}>
      {children}
    </BusinessDayContext.Provider>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Game, PaymentStatus, GameStatus, DailySummary } from '../types';
import GamesTable from '../components/GamesTable';
import KpiCard from '../components/KpiCard';
import { formatCurrency } from '../lib/utils';
import { Input } from '../components/ui/Input';
import { DollarSignIcon, HashIcon, ClockIcon, AlertTriangle, TrophyIcon, UsersIcon, LoaderCircle, ExternalLinkIcon, CheckCircle } from '../components/icons';
import PrintResumeButton from '../components/PrintResumeButton';
import { useAuth } from '../hooks/useAuth';
import { useGames } from '../hooks/useGames';
import { useBusinessDay } from '../hooks/useBusinessDay';
import UserManagement from '../components/UserManagement';
import AnalyticsCard from '../components/AnalyticsCard';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '../components/ui/Card';
import { Button } from '../components/ui/Button';
import { Badge } from '../components/ui/Badge';
import DailyClosureReport from '../components/DailyClosureReport';

const AdminPage: React.FC = () => {
  const { user } = useAuth();
  const { games, updateGame, deleteGame, saveDailySummary, sheetUrl, spreadsheetViewUrl, error: gameError } = useGames();
  const { businessDate, advanceDay } = useBusinessDay();
  const [selectedDate, setSelectedDate] = useState(businessDate);
  const [isArchiving, setIsArchiving] = useState(false);
  const [showClosureReport, setShowClosureReport] = useState(false);
  const [closureDate, setClosureDate] = useState('');
  const [closureGames, setClosureGames] = useState<Game[]>([]);

  // CRITICAL: When the business day advances, automatically update the admin view to the new session
  useEffect(() => {
    setSelectedDate(businessDate);
  }, [businessDate]);

  const isLiveDay = selectedDate === businessDate;

  const filteredGames = useMemo(() => {
    return games
      .filter(game => game.date === selectedDate)
      .sort((a, b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime());
  }, [games, selectedDate]);

  const selectedDayStats = useMemo(() => {
    const incomePaid = filteredGames
      .filter(g => g.paymentStatus === PaymentStatus.PAID)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const dayLoans = filteredGames
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const discounts = filteredGames
      .reduce((sum, g) => sum + (g.discountMAD || 0), 0);

    return {
      totalGames: filteredGames.length,
      incomePaid,
      dayLoans,
      discounts,
      runningCount: filteredGames.filter(g => g.status === GameStatus.RUNNING).length
    };
  }, [filteredGames]);

  const globalOutstandingLoans = useMemo(() => {
      return games
        .filter(g => g.paymentStatus === PaymentStatus.LOAN)
        .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);
  }, [games]);

  const allLoansList = useMemo(() => {
    return games
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [games]);

  const getDebtorName = (loan: Game) => {
    if (!loan.player2) return loan.player1;
    if (loan.winner === loan.player1) return loan.player2;
    if (loan.winner === loan.player2) return loan.player1;
    return `${loan.player1}${loan.player2 ? ' & ' + loan.player2 : ''}`;
  };

  const analyticsData = useMemo(() => {
    const playerStats: { [key: string]: { paid: number; loan: number; wins: number } } = {};

    const addPlayerStat = (player: string | null, key: 'paid' | 'loan', value: number) => {
        if (!player || value <= 0) return;
        if (!playerStats[player]) {
            playerStats[player] = { paid: 0, loan: 0, wins: 0 };
        }
        playerStats[player][key] += value;
    };

    games.forEach(game => {
        if (game.status !== GameStatus.FINISHED || !game.finalPriceMAD) return;
        const { player1, player2, winner, finalPriceMAD, paymentStatus } = game;
        if (paymentStatus === PaymentStatus.PAID) {
            const amount = player2 ? finalPriceMAD / 2 : finalPriceMAD;
            addPlayerStat(player1, 'paid', amount);
            addPlayerStat(player2, 'paid', amount);
        } else if (paymentStatus === PaymentStatus.LOAN) {
            let loanee = player1;
            if (player2) {
                if (winner && winner === player1) loanee = player2;
                else if (winner && winner === player2) loanee = player1;
            }
            addPlayerStat(loanee, 'loan', finalPriceMAD);
        }
        if (winner) {
            if (!playerStats[winner]) playerStats[winner] = { paid: 0, loan: 0, wins: 0 };
            playerStats[winner].wins += 1;
        }
    });

    const allPlayers = Object.entries(playerStats).map(([name, stats]) => ({ name, ...stats }));
    const topWinners = [...allPlayers].sort((a, b) => b.wins - a.wins).filter(p => p.wins > 0).slice(0, 5);
    const topPaid = [...allPlayers].sort((a, b) => b.paid - a.paid).filter(p => p.paid > 0).slice(0, 5);
    const playersWithLoans = [...allPlayers].sort((a, b) => b.loan - a.loan).filter(p => p.loan > 0);
    return { topWinners, topPaid, playersWithLoans };
  }, [games]);

  const handleAdvanceDay = async () => {
    if (selectedDayStats.runningCount > 0) {
        alert(`STOP: You still have ${selectedDayStats.runningCount} table(s) active. You must finish all games before closing the session.`);
        return;
    }

    if (!window.confirm("CONFIRM CLOSURE: This will archive all of today's totals and start a completely fresh session. Continue?")) return;

    setIsArchiving(true);
    const reportDate = businessDate;
    const reportGames = [...filteredGames];

    try {
      const summary: DailySummary = {
        date: businessDate,
        totalPaid: selectedDayStats.incomePaid,
        totalLoan: selectedDayStats.dayLoans,
        totalDiscount: selectedDayStats.discounts,
        gameCount: selectedDayStats.totalGames,
        archivedAt: new Date().toISOString()
      };

      await saveDailySummary(summary);
      await advanceDay(); // This updates businessDate context

      // Setup report view
      setClosureDate(reportDate);
      setClosureGames(reportGames);
      setShowClosureReport(true);
    } catch (e: any) {
      console.error("Closure failed", e);
      alert(`Error during session closure: ${e.message}. Please ensure all database tables are correctly setup in Settings.`);
    } finally {
      setIsArchiving(false);
    }
  };

  const settleLoan = async (gameId: string) => {
    if (!window.confirm("Mark this debt as settled?")) return;
    try {
        await updateGame(gameId, { paymentStatus: PaymentStatus.PAID });
    } catch (e) {
        console.error("Failed to settle loan", e);
    }
  };

  if (!user) return null;

  if (showClosureReport) {
