            ) : (
                <Badge variant="outline" className="text-muted-foreground border-muted-foreground px-3 py-1 font-bold">HISTORICAL RECORD</Badge>
            )}
          </div>
          <p className="text-muted-foreground mt-2 font-medium">
            Currently Viewing: <span className="text-foreground">{new Date(selectedDate + 'T00:00:00').toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}</span>
          </p>
        </div>
        <div className="flex items-center gap-3 bg-muted/30 p-2 rounded-xl border w-full md:w-auto">
            <span className="text-[10px] font-black uppercase text-muted-foreground px-2">Time Machine:</span>
            <Input
                type="date"
                value={selectedDate}
                onChange={e => setSelectedDate(e.target.value)}
                className="w-full md:w-[160px] bg-background h-8 text-xs font-bold cursor-pointer border-none shadow-none focus-visible:ring-0"
            />
        </div>
      </div>

      {gameError && (
        <div className="p-4 bg-destructive/10 border border-destructive/20 rounded-xl text-destructive flex items-center gap-3">
            <AlertTriangle className="h-5 w-5 flex-shrink-0"/>
            <div>
                <h4 className="font-bold text-sm">Database Sync Issue</h4>
                <p className="text-xs opacity-80">{gameError}</p>
            </div>
        </div>
      )}

      <div className="grid gap-4 md:grid-cols-4">
        <KpiCard title="Session Games" value={selectedDayStats.totalGames.toString()} icon={<HashIcon />} />
        <KpiCard title="Session Cash" value={`${selectedDayStats.incomePaid.toFixed(2)} MAD`} icon={<DollarSignIcon />} />
        <KpiCard title="Session Loans" value={`${selectedDayStats.dayLoans.toFixed(2)} MAD`} icon={<ClockIcon />} />
        <KpiCard title="Global Debt" value={`${globalOutstandingLoans.toFixed(2)} MAD`} icon={<AlertTriangle className="text-amber-500" />} />
      </div>

      {/* Analytics and Debt tracker... */}
      <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          <Card className="lg:col-span-1 shadow-sm border-dashed">
              <CardHeader className="bg-muted/10 pb-4">
                  <CardTitle className="text-sm font-black uppercase tracking-widest">Financial Summary</CardTitle>
              </CardHeader>
              <CardContent className="grid gap-4 pt-6">
                  <div className="flex items-center justify-between p-3 border-2 border-green-500/10 rounded-xl bg-green-50/30 dark:bg-green-950/10">
                      <span className="text-[10px] font-black uppercase text-green-600/70">Total Paid:</span>
                      <span className="font-black text-green-600">{formatCurrency(selectedDayStats.incomePaid)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border-2 border-amber-500/10 rounded-xl bg-amber-50/30 dark:bg-amber-950/10">
                      <span className="text-[10px] font-black uppercase text-amber-600/70">Total Loaned:</span>
                      <span className="font-black text-amber-600">{formatCurrency(selectedDayStats.dayLoans)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border border-dashed rounded-xl">
                      <span className="text-[10px] font-black uppercase text-muted-foreground">Total Discounts:</span>
                      <span className="font-bold text-muted-foreground">{formatCurrency(selectedDayStats.discounts)}</span>
                  </div>
                  <div className="pt-4 border-t-2 border-zinc-900 dark:border-white mt-2">
                      <div className="flex justify-between items-center px-1">
                          <span className="font-black text-xs uppercase tracking-widest">Gross Session Total:</span>
                          <span className="text-xl font-black">{formatCurrency(selectedDayStats.incomePaid + selectedDayStats.dayLoans)}</span>
                      </div>
                  </div>
              </CardContent>
          </Card>

          <Card className="lg:col-span-2 border-amber-200 dark:border-amber-900/50 shadow-md">
              <CardHeader className="flex flex-row items-center justify-between bg-amber-50/50 dark:bg-amber-950/10 pb-4">
                  <div>
                    <CardTitle className="flex items-center gap-2 text-amber-700 dark:text-amber-400 text-sm font-black uppercase tracking-widest">
                        <ClockIcon className="h-4 w-4" />
                        Live Debtors
                    </CardTitle>
                  </div>
                  <Badge className="bg-amber-500 font-bold">{allLoansList.length} Unpaid Transactions</Badge>
              </CardHeader>
              <CardContent className="h-[280px] overflow-y-auto pt-4">
                  {allLoansList.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {allLoansList.map((loan) => (
