};

export default AdminPage;

import React, { useState, useMemo, useEffect } from 'react';
import { Game, PaymentStatus, GameStatus, DailySummary } from '../types';
import GamesTable from '../components/GamesTable';
import KpiCard from '../components/KpiCard';
import { formatCurrency } from '../lib/utils';
import { Input } from '../components/ui/Input';
import { DollarSignIcon, HashIcon, ClockIcon, AlertTriangle, TrophyIcon, UsersIcon, LoaderCircle, CheckCircle } from '../components/icons';
import PrintResumeButton from '../components/PrintResumeButton';
import { useAuth } from '../hooks/useAuth';
import { useGames } from '../hooks/useGames';
import { useBusinessDay } from '../hooks/useBusinessDay';
import UserManagement from '../components/UserManagement';
import AnalyticsCard from '../components/AnalyticsCard';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '../components/ui/Card';
import { Button } from '../components/ui/Button';
import { Badge } from '../components/ui/Badge';
import DailyClosureReport from '../components/DailyClosureReport';

const AdminPage: React.FC = () => {
  const { user } = useAuth();
  const { games, updateGame, deleteGame, saveDailySummary, error: gameError } = useGames();
  const { businessDate, advanceDay } = useBusinessDay();
  const [selectedDate, setSelectedDate] = useState(businessDate);
  const [isArchiving, setIsArchiving] = useState(false);
  const [showClosureReport, setShowClosureReport] = useState(false);
  const [closureDate, setClosureDate] = useState('');
  const [closureGames, setClosureGames] = useState<Game[]>([]);

  // Keep selected date in sync with the live business date
  useEffect(() => {
    setSelectedDate(businessDate);
  }, [businessDate]);

  const isLiveDay = selectedDate === businessDate;

  const filteredGames = useMemo(() => {
    return games
      .filter(game => game.date === selectedDate)
      .sort((a, b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime());
  }, [games, selectedDate]);

  const selectedDayStats = useMemo(() => {
    const incomePaid = filteredGames
      .filter(g => g.paymentStatus === PaymentStatus.PAID)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const dayLoans = filteredGames
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const discounts = filteredGames
      .reduce((sum, g) => sum + (g.discountMAD || 0), 0);

    return {
      totalGames: filteredGames.length,
      incomePaid,
      dayLoans,
      discounts,
      runningCount: filteredGames.filter(g => g.status === GameStatus.RUNNING).length
    };
  }, [filteredGames]);

  const globalOutstandingLoans = useMemo(() => {
      return games
        .filter(g => g.paymentStatus === PaymentStatus.LOAN)
        .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);
  }, [games]);

  const allLoansList = useMemo(() => {
    return games
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [games]);

  const getDebtorName = (loan: Game) => {
    if (!loan.player2) return loan.player1;
    if (loan.winner === loan.player1) return loan.player2;
    if (loan.winner === loan.player2) return loan.player1;
    return `${loan.player1}${loan.player2 ? ' & ' + loan.player2 : ''}`;
  };

  const analyticsData = useMemo(() => {
    const playerStats: { [key: string]: { paid: number; loan: number; wins: number } } = {};

    const addPlayerStat = (player: string | null, key: 'paid' | 'loan', value: number) => {
        if (!player || value <= 0) return;
        if (!playerStats[player]) {
            playerStats[player] = { paid: 0, loan: 0, wins: 0 };
        }
        playerStats[player][key] += value;
    };

    games.forEach(game => {
        if (game.status !== GameStatus.FINISHED || !game.finalPriceMAD) return;
        const { player1, player2, winner, finalPriceMAD, paymentStatus } = game;
        if (paymentStatus === PaymentStatus.PAID) {
            const amount = player2 ? finalPriceMAD / 2 : finalPriceMAD;
            addPlayerStat(player1, 'paid', amount);
            addPlayerStat(player2, 'paid', amount);
        } else if (paymentStatus === PaymentStatus.LOAN) {
            let loanee = player1;
            if (player2) {
                if (winner && winner === player1) loanee = player2;
                else if (winner && winner === player2) loanee = player1;
            }
            addPlayerStat(loanee, 'loan', finalPriceMAD);
        }
        if (winner) {
            if (!playerStats[winner]) playerStats[winner] = { paid: 0, loan: 0, wins: 0 };
            playerStats[winner].wins += 1;
        }
    });

    const allPlayers = Object.entries(playerStats).map(([name, stats]) => ({ name, ...stats }));
    const topWinners = [...allPlayers].sort((a, b) => b.wins - a.wins).filter(p => p.wins > 0).slice(0, 5);
    const topPaid = [...allPlayers].sort((a, b) => b.paid - a.paid).filter(p => p.paid > 0).slice(0, 5);
    const playersWithLoans = [...allPlayers].sort((a, b) => b.loan - a.loan).filter(p => p.loan > 0);
    return { topWinners, topPaid, playersWithLoans };
  }, [games]);

  const handleAdvanceDay = async () => {
    // 1. Safety check for active games
    if (selectedDayStats.runningCount > 0) {
        alert(`You still have ${selectedDayStats.runningCount} games running. Please finish them before ending the session.`);
        return;
    }

    // 2. Explicit confirmation message as requested
    const confirmed = window.confirm("All data will be saved and you will begin a new session with new calculations. Continue?");
    if (!confirmed) return;

    setIsArchiving(true);
    const reportDate = businessDate;
    const reportGames = [...filteredGames];

    try {
      const summary: DailySummary = {
        date: businessDate,
        totalPaid: selectedDayStats.incomePaid,
        totalLoan: selectedDayStats.dayLoans,
        totalDiscount: selectedDayStats.discounts,
        gameCount: selectedDayStats.totalGames,
        archivedAt: new Date().toISOString()
      };

      // Step 3: Archive totals to daily_summaries
      await saveDailySummary(summary);

      // Step 4: Increment business day to start a fresh session
      await advanceDay(); 

      // Step 5: Transition UI to report view
      setClosureDate(reportDate);
      setClosureGames(reportGames);
      setShowClosureReport(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (e: any) {
      console.error("Session closure failed:", e);
      alert(`Error ending session: ${e.message || "Unknown error"}. Check database connection.`);
    } finally {
      setIsArchiving(false);
    }
  };

  const settleLoan = async (gameId: string) => {
    if (!window.confirm("Mark this debt as settled?")) return;
    try {
        await updateGame(gameId, { paymentStatus: PaymentStatus.PAID });
    } catch (e) {
        console.error("Failed to settle loan", e);
    }
  };

  if (!user) return null;

  if (showClosureReport) {
      return (
        <DailyClosureReport 
            date={closureDate} 
            games={closureGames} 
            onBack={() => setShowClosureReport(false)} 
        />
      );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pt-4">
      {/* Fixed Header Layout to prevent overlap */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 border-b pb-6">
        <div className="space-y-2">
          <div className="flex flex-wrap items-center gap-3">
            <h1 className="text-3xl font-black tracking-tighter uppercase leading-none">Admin Control</h1>
            {isLiveDay ? (
                <Badge className="bg-green-600 hover:bg-green-600 animate-pulse border-none px-3 py-1 text-[10px] font-black">LIVE SESSION</Badge>
            ) : (
                <Badge variant="outline" className="text-muted-foreground border-muted-foreground px-3 py-1 text-[10px] font-black">ARCHIVE</Badge>
            )}
          </div>
          <p className="text-muted-foreground font-medium text-sm">
            Current Date: <span className="text-foreground">{new Date(selectedDate + 'T00:00:00').toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}</span>
          </p>
        </div>
        <div className="flex items-center gap-3 bg-muted/30 p-2 rounded-xl border w-full md:w-auto">
            <span className="text-[10px] font-black uppercase text-muted-foreground px-2">Jump to Date:</span>
            <Input
                type="date"
                value={selectedDate}
                onChange={e => setSelectedDate(e.target.value)}
                className="w-full md:w-[160px] bg-background h-8 text-xs font-bold cursor-pointer border-none shadow-none focus-visible:ring-0"
            />
        </div>
      </div>

      {gameError && (
        <div className="p-4 bg-destructive/10 border border-destructive/20 rounded-xl text-destructive flex items-center gap-3">
            <AlertTriangle className="h-5 w-5 flex-shrink-0"/>
            <div className="text-xs">
                <h4 className="font-bold">Sync Error</h4>
                <p>{gameError}</p>
            </div>
        </div>
      )}

      <div className="grid gap-4 md:grid-cols-4">
        <KpiCard title="Session Games" value={selectedDayStats.totalGames.toString()} icon={<HashIcon />} />
        <KpiCard title="Session Cash" value={`${selectedDayStats.incomePaid.toFixed(2)} MAD`} icon={<DollarSignIcon />} />
        <KpiCard title="Session Loans" value={`${selectedDayStats.dayLoans.toFixed(2)} MAD`} icon={<ClockIcon />} />
        <KpiCard title="Global Debt" value={`${globalOutstandingLoans.toFixed(2)} MAD`} icon={<AlertTriangle className="text-amber-500" />} />
      </div>

      <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          <Card className="lg:col-span-1 shadow-sm border-dashed">
              <CardHeader className="bg-muted/10 pb-4">
                  <CardTitle className="text-xs font-black uppercase tracking-widest text-muted-foreground">Financial Summary</CardTitle>
              </CardHeader>
              <CardContent className="grid gap-4 pt-6">
                  <div className="flex items-center justify-between p-3 border-2 border-green-500/10 rounded-xl bg-green-50/30 dark:bg-green-950/10">
                      <span className="text-[10px] font-black uppercase text-green-600/70">Total Paid:</span>
                      <span className="font-black text-green-600">{formatCurrency(selectedDayStats.incomePaid)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border-2 border-amber-500/10 rounded-xl bg-amber-50/30 dark:bg-amber-950/10">
                      <span className="text-[10px] font-black uppercase text-amber-600/70">Total Loaned:</span>
                      <span className="font-black text-amber-600">{formatCurrency(selectedDayStats.dayLoans)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border border-dashed rounded-xl">
                      <span className="text-[10px] font-black uppercase text-muted-foreground">Total Discounts:</span>
                      <span className="font-bold text-muted-foreground">{formatCurrency(selectedDayStats.discounts)}</span>
                  </div>
                  <div className="pt-4 border-t-2 border-zinc-900 dark:border-white mt-2">
                      <div className="flex justify-between items-center px-1">
                          <span className="font-black text-xs uppercase tracking-widest">Gross Session Total:</span>
                          <span className="text-xl font-black">{formatCurrency(selectedDayStats.incomePaid + selectedDayStats.dayLoans)}</span>
                      </div>
                  </div>
              </CardContent>
          </Card>

          <Card className="lg:col-span-2 border-amber-200 dark:border-amber-900/50 shadow-md">
              <CardHeader className="flex flex-row items-center justify-between bg-amber-50/50 dark:bg-amber-950/10 pb-4">
                  <div>
                    <CardTitle className="flex items-center gap-2 text-amber-700 dark:text-amber-400 text-xs font-black uppercase tracking-widest">
                        <ClockIcon className="h-4 w-4" />
                        Live Debtors
                    </CardTitle>
                  </div>
                  <Badge className="bg-amber-500 font-bold text-[10px]">{allLoansList.length} Unpaid</Badge>
              </CardHeader>
              <CardContent className="h-[280px] overflow-y-auto pt-4">
                  {allLoansList.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {allLoansList.map((loan) => (
