      <div className="space-y-4">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4 border-b pb-4">
            <h2 className="text-xl font-black uppercase tracking-tighter">Session Activity Log</h2>
            <div className="flex flex-wrap items-center gap-2">
                <PrintResumeButton games={filteredGames} selectedDate={selectedDate} />

                {isLiveDay && (
                    <Button 
                        onClick={handleAdvanceDay} 
                        disabled={isArchiving} 
                        className="bg-primary hover:bg-primary/90 font-black uppercase tracking-widest px-8 shadow-xl transition-all active:scale-95 border-none"
                    >
                        {isArchiving ? (
                            <>
                                <LoaderCircle className="mr-2 h-4 w-4 animate-spin" />
                                Archiving...
                            </>
                        ) : (
                            "End Session & Archive"
                        )}
                    </Button>
                )}
            </div>
        </div>
        <GamesTable 
            games={filteredGames} 
            isAdmin={true} 
            updateGame={updateGame} 
            deleteGame={deleteGame}
            currentUserId={user.id}
        />
      </div>

      <div className="pt-12 border-t">
        <h2 className="text-xl font-black uppercase tracking-tighter mb-6">Staff Management</h2>
        <UserManagement />
      </div>
    </div>
  );
};

