                                        disabled={isArchiving}
                                    >
                                        {isArchiving ? <LoaderCircle className="h-3 w-3 animate-spin mr-1"/> : null}
                                        Yes, End Session
                                    </Button>
                                    <Button 
                                        size="sm" 
                                        variant="ghost" 
                                        className="h-8 px-4 text-[10px] font-black uppercase tracking-wider"
                                        onClick={() => setIsConfirmingArchive(false)}
                                        disabled={isArchiving}
                                    >
                                        Cancel
                                    </Button>
                                </div>
                            </div>
                        ) : (
                            <Button 
                                type="button"
                                onClick={handleArchiveClick} 
                                className="bg-primary hover:bg-primary/90 font-black uppercase tracking-widest px-8 shadow-xl transition-all active:scale-95 border-none h-11"
                            >
                                End Session & Archive
                            </Button>
                        )}
                    </div>
                )}
            </div>
        </div>
        <GamesTable 
            games={filteredGames} 
            isAdmin={true} 
            updateGame={updateGame} 
            deleteGame={deleteGame}
            currentUserId={user.id}
        />
      </div>

      <div className="pt-12 border-t">
        <h2 className="text-xl font-black uppercase tracking-tighter mb-6">User Management</h2>
        <UserManagement />
      </div>
    </div>
  );
};

