-- SNOOKER CLUB MANAGER - COMPLETE DATABASE REPAIR SCRIPT
-- Copy and run this entire script in the Supabase SQL Editor

-- 1. CREATE USERS TABLE
CREATE TABLE IF NOT EXISTS public.users (
  "id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "email" text UNIQUE NOT NULL,
  "password" text NOT NULL,
  "role" text NOT NULL CHECK ("role" IN ('admin', 'user')),
  "created_at" timestamptz DEFAULT now()
);

-- 2. CREATE GAMES TABLE
CREATE TABLE IF NOT EXISTS public.games (
  "id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "date" date NOT NULL,
  "tableName" text NOT NULL,
  "hourlyRate" numeric NOT NULL,
  "startTime" timestamptz NOT NULL,
  "endTime" timestamptz,
  "player1" text NOT NULL,
  "player2" text,
  "winner" text,
  "status" text NOT NULL,
  "durationSeconds" int,
  "priceMAD" numeric,
  "discountMAD" numeric DEFAULT 0,
  "finalPriceMAD" numeric,
  "paymentStatus" text NOT NULL,
  "notes" text,
  "createdBy" uuid REFERENCES public.users("id") NOT NULL,
  "modifiedBy" uuid REFERENCES public.users("id"),
  "createdAt" timestamptz DEFAULT now(),
  "updatedAt" timestamptz DEFAULT now()
);

-- 3. FIX COLUMN NAMES FOR GAMES (IF NEEDED)
DO $$ 
BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='games' AND column_name='tablename') THEN
    ALTER TABLE public.games RENAME COLUMN "tablename" TO "tableName";
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='games' AND column_name='hourlyrate') THEN
    ALTER TABLE public.games RENAME COLUMN "hourlyrate" TO "hourlyRate";
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='games' AND column_name='starttime') THEN
    ALTER TABLE public.games RENAME COLUMN "starttime" TO "startTime";
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='games' AND column_name='endtime') THEN
    ALTER TABLE public.games RENAME COLUMN "endtime" TO "endTime";
  END IF;
END $$;

-- 4. CREATE DAILY SUMMARIES TABLE & FIX MISSING COLUMNS
CREATE TABLE IF NOT EXISTS public.daily_summaries (
  "id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "date" date UNIQUE NOT NULL,
  "totalPaid" numeric DEFAULT 0,
  "totalLoan" numeric DEFAULT 0,
  "totalDiscount" numeric DEFAULT 0,
  "gameCount" int DEFAULT 0,
  "archivedAt" timestamptz DEFAULT now()
);

-- REPAIR: Add archivedAt if missing from daily_summaries
DO $$ 
BEGIN 
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='daily_summaries' AND column_name='archivedAt') THEN
    ALTER TABLE public.daily_summaries ADD COLUMN "archivedAt" timestamptz DEFAULT now();
  END IF;
END $$;

-- 5. CREATE APP CONFIG TABLE
CREATE TABLE IF NOT EXISTS public.app_config (
  "key" text PRIMARY KEY,
  "value" text NOT NULL
);

-- 6. DISABLE RLS (For MVP simplicity)
ALTER TABLE public.users DISABLE ROW LEVEL SECURITY;
ALTER TABLE public.games DISABLE ROW LEVEL SECURITY;
ALTER TABLE public.daily_summaries DISABLE ROW LEVEL SECURITY;
ALTER TABLE public.app_config DISABLE ROW LEVEL SECURITY;

-- 7. INSERT INITIAL DATA
INSERT INTO public.users ("id", "email", "password", "role") 
VALUES 
  ('00000000-0000-0000-0000-000000000001', 'admin@snooker.club', 'admin', 'admin'),
  ('00000000-0000-0000-0000-000000000002', 'user@snooker.club', 'user', 'user')
ON CONFLICT ("email") DO UPDATE SET "id" = EXCLUDED."id";

INSERT INTO public.app_config ("key", "value")
VALUES ('business_date', CURRENT_DATE::text)
ON CONFLICT ("key") DO NOTHING;

-- 8. ENABLE REALTIME
BEGIN;
  DROP PUBLICATION IF EXISTS supabase_realtime;
  CREATE PUBLICATION supabase_realtime FOR ALL TABLES;
COMMIT;
`.trim();

const appsScriptCode = `
/**
 * Google Apps Script logic for Google Sheets integration.
