import React, { createContext, useState, ReactNode, useCallback, useEffect } from 'react';
import { Game, GameStatus, DailySummary } from '../types';
import { SEED_GAMES } from '../constants';
import { supabase, isMissingTableError, formatError } from '../lib/supabase';

type SyncStatus = 'idle' | 'syncing' | 'synced' | 'error' | 'offline';

interface GameContextType {
  games: Game[];
  addGame: (newGame: Omit<Game, 'id' | 'createdAt' | 'updatedAt'>) => Promise<void>;
  updateGame: (gameId: string, updates: Partial<Game>) => Promise<void>;
  deleteGame: (gameId: string) => Promise<void>;
  saveDailySummary: (summary: DailySummary) => Promise<void>;
  isLoading: boolean;
  error: string | null;
  isTableMissing: boolean;
  syncStatus: SyncStatus;
  sheetUrl: string | null;
  spreadsheetViewUrl: string | null;
  saveSheetUrl: (webAppUrl: string, viewUrl: string) => void;
  clearSheetUrl: () => void;
  refetchGames: () => void;
}

export const GameContext = createContext<GameContextType | undefined>(undefined);

const STORAGE_KEY = 'googleSheetWebAppUrl';
const VIEW_STORAGE_KEY = 'googleSpreadsheetViewUrl';
const GAMES_CACHE_KEY = 'snooker_games_cache';

export const GameProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [games, setGames] = useState<Game[]>(() => {
    const cached = localStorage.getItem(GAMES_CACHE_KEY);
    return cached ? JSON.parse(cached) : SEED_GAMES;
  });
  const [sheetUrl, setSheetUrl] = useState<string | null>(null);
  const [spreadsheetViewUrl, setSpreadsheetViewUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [isTableMissing, setIsTableMissing] = useState<boolean>(false);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  const fetchGames = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    setIsTableMissing(false);
    try {
      const { data, error: sbError } = await supabase
        .from('games')
        .select('*')
        .order('startTime', { ascending: false });

      if (sbError) throw sbError;

      const gameData = data || [];
      setGames(gameData);
      localStorage.setItem(GAMES_CACHE_KEY, JSON.stringify(gameData));
      setSyncStatus('idle');
    } catch (err: any) {
      if (isMissingTableError(err)) {
        setIsTableMissing(true);
        setError("Setup Required: The 'games' table does not exist in your Supabase project.");
      } else {
        const isFetchError = err.message === 'Failed to fetch' || err.name === 'TypeError';
        setError(isFetchError ? "Network Error: Could not reach database." : formatError(err));
        if (isFetchError) setSyncStatus('offline');
      }
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchGames();
    const channel = supabase
      .channel('public:games')
      .on('postgres_changes', { event: '*', table: 'games', schema: 'public' }, () => fetchGames())
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [fetchGames]);

  const saveSheetUrl = (webAppUrl: string, viewUrl: string) => {
    localStorage.setItem(STORAGE_KEY, webAppUrl);
    localStorage.setItem(VIEW_STORAGE_KEY, viewUrl);
    setSheetUrl(webAppUrl);
    setSpreadsheetViewUrl(viewUrl);
  };

  const clearSheetUrl = () => {
    localStorage.removeItem(STORAGE_KEY);
    localStorage.removeItem(VIEW_STORAGE_KEY);
    setSheetUrl(null);
    setSpreadsheetViewUrl(null);
  };

  const addGame = useCallback(async (newGameData: Omit<Game, 'id' | 'createdAt' | 'updatedAt'>) => {
    setSyncStatus('syncing');
    try {
      if (!newGameData.createdBy || newGameData.createdBy.length < 10) {
          throw new Error(`Invalid User ID: ${newGameData.createdBy}. Please log out and log back in.`);
      }

      const { error: sbError } = await supabase.from('games').insert([newGameData]);
      if (sbError) throw sbError;

      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
      await fetchGames();
    } catch (err: any) {
      setSyncStatus('error');
      const errorDetail = formatError(err);
      if (err.code === '23503') {
          alert(`Sync Error: Your account ID is not recognized by the database. Please Logout and Login again.`);
      } else {
          alert(`Failed to start game: ${errorDetail}`);
      }
    }
  }, [fetchGames]);

  const updateGame = useCallback(async (gameId: string, updates: Partial<Game>) => {
    setSyncStatus('syncing');
    try {
      const { error: sbError } = await supabase.from('games').update({ ...updates, updatedAt: new Date().toISOString() }).eq('id', gameId);
      if (sbError) throw sbError;
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
      await fetchGames();
    } catch (err: any) {
      setSyncStatus('error');
      const errorDetail = formatError(err);
      alert(`Update failed: ${errorDetail}`);
    }
  }, [fetchGames]);

  const deleteGame = useCallback(async (gameId: string) => {
    setSyncStatus('syncing');
    try {
      const { error: sbError } = await supabase.from('games').delete().eq('id', gameId);
      if (sbError) throw sbError;
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
      await fetchGames();
    } catch (err: any) {
      setSyncStatus('error');
      const errorDetail = formatError(err);
      alert(`Delete failed: ${errorDetail}`);
    }
  }, [fetchGames]);

  const saveDailySummary = useCallback(async (summary: DailySummary) => {
    // To avoid PGRST204 column missing errors, we omit archivedAt from the payload.
    // The database table should have a default value for this column anyway.
    const { archivedAt, ...payload } = summary;

    const { error: sbError } = await supabase
        .from('daily_summaries')
        .upsert([payload], { onConflict: 'date' });

    if (sbError) {
        console.error('Save summary failed:', formatError(sbError));
        throw sbError;
    }
  }, []);

  useEffect(() => {
    setSheetUrl(localStorage.getItem(STORAGE_KEY));
    setSpreadsheetViewUrl(localStorage.getItem(VIEW_STORAGE_KEY));
  }, []);

  return (
    <GameContext.Provider value={{ 
      games, addGame, updateGame, deleteGame, saveDailySummary, 
      isLoading, error, isTableMissing, syncStatus, sheetUrl, spreadsheetViewUrl, 
      saveSheetUrl, clearSheetUrl, refetchGames: fetchGames 
    }}>
      {children}
    </GameContext.Provider>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Game, PaymentStatus, GameStatus, DailySummary } from '../types';
import GamesTable from '../components/GamesTable';
import KpiCard from '../components/KpiCard';
import { formatCurrency } from '../lib/utils';
import { Input } from '../components/ui/Input';
import { DollarSignIcon, HashIcon, ClockIcon, AlertTriangle, TrophyIcon, UsersIcon, LoaderCircle, CheckCircle } from '../components/icons';
import PrintResumeButton from '../components/PrintResumeButton';
import { useAuth } from '../hooks/useAuth';
import { useGames } from '../hooks/useGames';
import { useBusinessDay } from '../hooks/useBusinessDay';
import UserManagement from '../components/UserManagement';
import AnalyticsCard from '../components/AnalyticsCard';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '../components/ui/Card';
import { Button } from '../components/ui/Button';
import { Badge } from '../components/ui/Badge';
import DailyClosureReport from '../components/DailyClosureReport';

const AdminPage: React.FC = () => {
  const { user } = useAuth();
  const { games, updateGame, deleteGame, saveDailySummary, error: gameError } = useGames();
  const { businessDate, advanceDay } = useBusinessDay();

  const [selectedDate, setSelectedDate] = useState(businessDate);
  const [isArchiving, setIsArchiving] = useState(false);
  const [showClosureReport, setShowClosureReport] = useState(false);
  const [closureDate, setClosureDate] = useState('');
  const [closureGames, setClosureGames] = useState<Game[]>([]);

  // State for the inline confirmation to ensure the button always "reacts"
  const [isConfirmingArchive, setIsConfirmingArchive] = useState(false);
  const [archiveErrorMessage, setArchiveErrorMessage] = useState<string | null>(null);

  // Keep date selector in sync with global business day
  useEffect(() => {
    setSelectedDate(businessDate);
  }, [businessDate]);

  const isLiveDay = selectedDate === businessDate;

  const filteredGames = useMemo(() => {
    return games
      .filter(game => game.date === selectedDate)
      .sort((a, b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime());
  }, [games, selectedDate]);

  const selectedDayStats = useMemo(() => {
    const incomePaid = filteredGames
      .filter(g => g.paymentStatus === PaymentStatus.PAID)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const dayLoans = filteredGames
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const discounts = filteredGames
      .reduce((sum, g) => sum + (g.discountMAD || 0), 0);

    return {
      totalGames: filteredGames.length,
      incomePaid,
      dayLoans,
      discounts,
      runningCount: filteredGames.filter(g => g.status === GameStatus.RUNNING).length
    };
  }, [filteredGames]);

  const globalOutstandingLoans = useMemo(() => {
      return games
        .filter(g => g.paymentStatus === PaymentStatus.LOAN)
        .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);
  }, [games]);

  const allLoansList = useMemo(() => {
    return games
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [games]);

  const getDebtorName = (loan: Game) => {
    if (!loan.player2) return loan.player1;
    if (loan.winner === loan.player1) return loan.player2;
    if (loan.winner === loan.player2) return loan.player1;
    return `${loan.player1}${loan.player2 ? ' & ' + loan.player2 : ''}`;
  };

  const analyticsData = useMemo(() => {
    const playerStats: { [key: string]: { paid: number; loan: number; wins: number } } = {};

    const addPlayerStat = (player: string | null, key: 'paid' | 'loan', value: number) => {
        if (!player || value <= 0) return;
        if (!playerStats[player]) {
            playerStats[player] = { paid: 0, loan: 0, wins: 0 };
        }
        playerStats[player][key] += value;
    };

    games.forEach(game => {
        if (game.status !== GameStatus.FINISHED || !game.finalPriceMAD) return;
        const { player1, player2, winner, finalPriceMAD, paymentStatus } = game;
        if (paymentStatus === PaymentStatus.PAID) {
            const amount = player2 ? finalPriceMAD / 2 : finalPriceMAD;
            addPlayerStat(player1, 'paid', amount);
            addPlayerStat(player2, 'paid', amount);
        } else if (paymentStatus === PaymentStatus.LOAN) {
            let loanee = player1;
            if (player2) {
                if (winner && winner === player1) loanee = player2;
                else if (winner && winner === player2) loanee = player1;
            }
            addPlayerStat(loanee, 'loan', finalPriceMAD);
        }
        if (winner) {
            if (!playerStats[winner]) playerStats[winner] = { paid: 0, loan: 0, wins: 0 };
            playerStats[winner].wins += 1;
        }
    });

    const allPlayers = Object.entries(playerStats).map(([name, stats]) => ({ name, ...stats }));
    const topWinners = [...allPlayers].sort((a, b) => b.wins - a.wins).filter(p => p.wins > 0).slice(0, 5);
    const topPaid = [...allPlayers].sort((a, b) => b.paid - a.paid).filter(p => p.paid > 0).slice(0, 5);
    const playersWithLoans = [...allPlayers].sort((a, b) => b.loan - a.loan).filter(p => p.loan > 0);
    return { topWinners, topPaid, playersWithLoans };
  }, [games]);

  const performArchive = async () => {
    console.log("Starting archive process...");
    setIsArchiving(true);
    setArchiveErrorMessage(null);
    const reportDate = businessDate;
    const reportGames = [...filteredGames];

    try {
      const summary: DailySummary = {
        date: businessDate,
        totalPaid: selectedDayStats.incomePaid,
        totalLoan: selectedDayStats.dayLoans,
        totalDiscount: selectedDayStats.discounts,
        gameCount: selectedDayStats.totalGames,
      };

      await saveDailySummary(summary);
      await advanceDay(); 

      setIsConfirmingArchive(false);
      setClosureDate(reportDate);
      setClosureGames(reportGames);
      setShowClosureReport(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (e: any) {
      console.error("Archive Error Details:", e);
      setArchiveErrorMessage(`Database Error: ${e.message || "Archive failed"}`);
    } finally {
      setIsArchiving(false);
    }
  };

  const handleArchiveClick = () => {
    console.log("End session button clicked");
    if (selectedDayStats.runningCount > 0) {
        alert(`CANNOT END SESSION: You still have ${selectedDayStats.runningCount} table(s) active. Please finish or cancel all running games before archiving.`);
        return;
    }
    setIsConfirmingArchive(true);
    setArchiveErrorMessage(null);
  };

  const settleLoan = async (gameId: string) => {
    if (!window.confirm("Mark this debt as settled?")) return;
    try {
        await updateGame(gameId, { paymentStatus: PaymentStatus.PAID });
    } catch (e) {
        console.error("Failed to settle loan", e);
    }
  };

  if (!user) return null;

  if (showClosureReport) {
      return (
        <DailyClosureReport 
            date={closureDate} 
            games={closureGames} 
            onBack={() => setShowClosureReport(false)} 
        />
      );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pt-6">
      {/* Header fixed to prevent icon overlap and improve responsive behavior */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-6 border-b pb-8 px-1">
        <div className="space-y-2">
          <div className="flex flex-wrap items-center gap-3">
            <h1 className="text-4xl font-black tracking-tighter uppercase leading-none break-all sm:break-normal">Admin Control</h1>
            {isLiveDay ? (
                <Badge className="bg-green-600 hover:bg-green-600 animate-pulse border-none px-3 py-1 text-[10px] font-black whitespace-nowrap">LIVE SESSION</Badge>
            ) : (
                <Badge variant="outline" className="text-muted-foreground border-muted-foreground px-3 py-1 text-[10px] font-black whitespace-nowrap">HISTORY</Badge>
            )}
          </div>
          <p className="text-muted-foreground font-medium text-sm">
            Viewing records for: <span className="text-foreground font-bold">{new Date(selectedDate + 'T00:00:00').toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}</span>
          </p>
        </div>
        <div className="flex items-center gap-3 bg-muted/40 p-2 rounded-xl border w-full lg:w-auto overflow-hidden">
            <span className="text-[10px] font-black uppercase text-muted-foreground px-2 whitespace-nowrap">Go to date:</span>
            <Input
                type="date"
                value={selectedDate}
                onChange={e => setSelectedDate(e.target.value)}
                className="w-full lg:w-[160px] bg-background h-8 text-xs font-bold cursor-pointer border-none shadow-none focus-visible:ring-0"
            />
        </div>
      </div>

      {(gameError || archiveErrorMessage) && (
        <div className="p-4 bg-destructive/10 border border-destructive/20 rounded-xl text-destructive flex items-center gap-3 animate-in slide-in-from-top-2">
            <AlertTriangle className="h-5 w-5 flex-shrink-0"/>
            <div className="text-xs font-bold">
                <p>{archiveErrorMessage || `Sync Alert: ${gameError}`}</p>
            </div>
        </div>
      )}

      <div className="grid gap-4 md:grid-cols-4">
        <KpiCard title="Total Games" value={selectedDayStats.totalGames.toString()} icon={<HashIcon />} />
        <KpiCard title="Session Cash" value={`${selectedDayStats.incomePaid.toFixed(2)}`} icon={<DollarSignIcon />} />
        <KpiCard title="New Loans" value={`${selectedDayStats.dayLoans.toFixed(2)}`} icon={<ClockIcon />} />
        <KpiCard title="Global Debt" value={`${globalOutstandingLoans.toFixed(2)}`} icon={<AlertTriangle className="text-amber-500" />} />
      </div>

      <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          <Card className="lg:col-span-1 shadow-sm border-dashed">
              <CardHeader className="bg-muted/10 pb-4">
                  <CardTitle className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Session Performance</CardTitle>
              </CardHeader>
              <CardContent className="grid gap-4 pt-6">
                  <div className="flex items-center justify-between p-3 border-2 border-green-500/10 rounded-xl bg-green-50/30 dark:bg-green-950/10">
                      <span className="text-[10px] font-black uppercase text-green-600/70">Total Paid:</span>
                      <span className="font-black text-green-600">{formatCurrency(selectedDayStats.incomePaid)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border-2 border-amber-500/10 rounded-xl bg-amber-50/30 dark:bg-amber-950/10">
                      <span className="text-[10px] font-black uppercase text-amber-600/70">Total Loaned:</span>
                      <span className="font-black text-amber-600">{formatCurrency(selectedDayStats.dayLoans)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border border-dashed rounded-xl">
                      <span className="text-[10px] font-black uppercase text-muted-foreground">Total Discounts:</span>
                      <span className="font-bold text-muted-foreground">{formatCurrency(selectedDayStats.discounts)}</span>
                  </div>
                  <div className="pt-4 border-t-2 border-zinc-900 dark:border-white mt-2">
                      <div className="flex justify-between items-center px-1">
                          <span className="font-black text-xs uppercase tracking-widest">Gross Session Total:</span>
                          <span className="text-xl font-black">{formatCurrency(selectedDayStats.incomePaid + selectedDayStats.dayLoans)}</span>
                      </div>
                  </div>
              </CardContent>
          </Card>

          <Card className="lg:col-span-2 border-amber-200 dark:border-amber-900/50 shadow-md">
              <CardHeader className="flex flex-row items-center justify-between bg-amber-50/50 dark:bg-amber-950/10 pb-4">
                  <div>
                    <CardTitle className="flex items-center gap-2 text-amber-700 dark:text-amber-400 text-xs font-black uppercase tracking-widest">
                        <ClockIcon className="h-4 w-4" />
                        Live Debt Tracker
                    </CardTitle>
                  </div>
                  <Badge className="bg-amber-500 font-bold text-[10px]">{allLoansList.length} Active Loans</Badge>
              </CardHeader>
              <CardContent className="h-[280px] overflow-y-auto pt-4">
                  {allLoansList.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {allLoansList.map((loan) => (
                            <div key={loan.id} className="flex items-center justify-between p-3 rounded-xl bg-muted/30 border border-transparent hover:border-amber-500/30 transition-all">
                                <div className="grid gap-0.5">
                                    <span className="font-black text-xs text-foreground uppercase tracking-tight">
                                        {getDebtorName(loan)}
                                    </span>
                                    <div className="flex items-center gap-2 text-[10px] text-muted-foreground">
                                        <span className="font-bold text-amber-600/80">{loan.tableName}</span>
                                        <span>•</span>
                                        <span>{new Date(loan.date + 'T00:00:00').toLocaleDateString('en-GB')}</span>
                                    </div>
                                </div>
                                <div className="flex items-center gap-3">
                                    <span className="font-bold text-sm text-amber-600">{formatCurrency(loan.finalPriceMAD)}</span>
                                    <Button size="icon" variant="ghost" className="h-7 w-7 text-green-600 hover:bg-green-500/10 rounded-full" onClick={() => settleLoan(loan.id)}>
                                        <CheckCircle className="h-4 w-4" />
                                    </Button>
                                </div>
                            </div>
                        ))}
                    </div>
                  ) : (
                    <div className="flex flex-col items-center justify-center h-full text-muted-foreground gap-2 opacity-50">
                        <CheckCircle className="h-12 w-12" />
                        <p className="text-[10px] font-black uppercase tracking-widest">Clear Records</p>
                    </div>
                  )}
              </CardContent>
          </Card>
      </div>

      <div className="space-y-4">
        <h2 className="text-xl font-black uppercase tracking-tighter border-b pb-4">Performance Insights</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            <AnalyticsCard title="Hall of Fame" icon={<TrophyIcon className="text-yellow-500" />}>
                {analyticsData.topWinners.length > 0 ? (
                    analyticsData.topWinners.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-xs py-2 border-b border-dashed last:border-b-0">
                            <span className="font-bold uppercase">{player.name}</span>
                            <span className="bg-primary/10 px-2 py-0.5 rounded text-[10px] font-black">{player.wins} WINS</span>
                        </div>
                    ))
                ) : (
                    <p className="text-[10px] text-muted-foreground italic py-4">No data yet.</p>
                )}
            </AnalyticsCard>

            <AnalyticsCard title="Top Revenue" icon={<DollarSignIcon className="text-green-500" />}>
                    {analyticsData.topPaid.length > 0 ? (
                    analyticsData.topPaid.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-xs py-2 border-b border-dashed last:border-b-0">
                            <span className="font-bold uppercase">{player.name}</span>
                            <span className="font-black text-green-600">{formatCurrency(player.paid)}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-[10px] text-muted-foreground italic py-4">No data yet.</p>
                )}
            </AnalyticsCard>

            <AnalyticsCard title="Debtor Summary" icon={<UsersIcon className="text-red-500" />}>
                {analyticsData.playersWithLoans.length > 0 ? (
                    analyticsData.playersWithLoans.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-xs py-2 border-b border-dashed last:border-b-0">
                            <span className="font-bold uppercase">{player.name}</span>
                            <span className="font-black text-destructive">{formatCurrency(player.loan)}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-[10px] text-muted-foreground italic py-4">Records are clear.</p>
                )}
            </AnalyticsCard>
        </div>
      </div>

      <div className="space-y-4">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4 border-b pb-4">
            <h2 className="text-xl font-black uppercase tracking-tighter">Session Activity Log</h2>
            <div className="flex flex-wrap items-center gap-2">
                <PrintResumeButton games={filteredGames} selectedDate={selectedDate} />

                {isLiveDay && (
                    <div className="flex flex-col sm:flex-row items-center gap-2">
                        {isConfirmingArchive ? (
                            <div className="flex flex-col items-end gap-2 p-3 bg-primary/5 rounded-lg border border-primary/20 animate-in fade-in slide-in-from-right-4">
                                <span className="text-[10px] font-black uppercase text-primary text-center w-full px-2">
                                    All data will be saved and you will start a new game. Continue?
                                </span>
                                <div className="flex gap-2 w-full justify-center">
                                    <Button 
                                        size="sm" 
                                        className="bg-green-600 hover:bg-green-700 h-9 px-6 text-[10px] font-black uppercase tracking-wider" 
                                        onClick={performArchive}
                                        disabled={isArchiving}
                                    >
                                        {isArchiving ? <LoaderCircle className="h-3 w-3 animate-spin mr-1"/> : null}
                                        Yes, End Session
                                    </Button>
                                    <Button 
                                        size="sm" 
                                        variant="ghost" 
                                        className="h-9 px-4 text-[10px] font-black uppercase tracking-wider"
                                        onClick={() => setIsConfirmingArchive(false)}
                                        disabled={isArchiving}
                                    >
                                        Cancel
                                    </Button>
                                </div>
                            </div>
                        ) : (
                            <Button 
                                type="button"
                                onClick={handleArchiveClick} 
                                className="bg-primary hover:bg-primary/90 font-black uppercase tracking-widest px-8 shadow-2xl transition-all active:scale-95 border-none h-11"
                            >
                                End Session & Archive
                            </Button>
                        )}
                    </div>
                )}
            </div>
        </div>
        <GamesTable 
            games={filteredGames} 
            isAdmin={true} 
            updateGame={updateGame} 
            deleteGame={deleteGame}
            currentUserId={user.id}
        />
      </div>

      <div className="pt-12 border-t">
        <h2 className="text-xl font-black uppercase tracking-tighter mb-6">User Management</h2>
        <UserManagement />
      </div>
    </div>
  );
};

export default AdminPage;

import React, { createContext, useState, ReactNode, useCallback, useEffect } from 'react';
import { Game, GameStatus, DailySummary } from '../types';
import { SEED_GAMES } from '../constants';
import { supabase, isMissingTableError, formatError } from '../lib/supabase';

type SyncStatus = 'idle' | 'syncing' | 'synced' | 'error' | 'offline';

interface GameContextType {
  games: Game[];
  addGame: (newGame: Omit<Game, 'id' | 'createdAt' | 'updatedAt'>) => Promise<void>;
  updateGame: (gameId: string, updates: Partial<Game>) => Promise<void>;
  deleteGame: (gameId: string) => Promise<void>;
  saveDailySummary: (summary: DailySummary) => Promise<void>;
  isLoading: boolean;
  error: string | null;
  isTableMissing: boolean;
  syncStatus: SyncStatus;
  sheetUrl: string | null;
  spreadsheetViewUrl: string | null;
  saveSheetUrl: (webAppUrl: string, viewUrl: string) => void;
  clearSheetUrl: () => void;
  refetchGames: () => void;
}

export const GameContext = createContext<GameContextType | undefined>(undefined);

const STORAGE_KEY = 'googleSheetWebAppUrl';
const VIEW_STORAGE_KEY = 'googleSpreadsheetViewUrl';
const GAMES_CACHE_KEY = 'snooker_games_cache';

export const GameProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [games, setGames] = useState<Game[]>(() => {
    const cached = localStorage.getItem(GAMES_CACHE_KEY);
    return cached ? JSON.parse(cached) : SEED_GAMES;
  });
  const [sheetUrl, setSheetUrl] = useState<string | null>(null);
  const [spreadsheetViewUrl, setSpreadsheetViewUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [isTableMissing, setIsTableMissing] = useState<boolean>(false);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  const fetchGames = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    setIsTableMissing(false);
    try {
      const { data, error: sbError } = await supabase
        .from('games')
        .select('*')
        .order('startTime', { ascending: false });

      if (sbError) throw sbError;

      const gameData = data || [];
      setGames(gameData);
      localStorage.setItem(GAMES_CACHE_KEY, JSON.stringify(gameData));
      setSyncStatus('idle');
    } catch (err: any) {
      if (isMissingTableError(err)) {
        setIsTableMissing(true);
        setError("Setup Required: The 'games' table does not exist in your Supabase project.");
      } else {
        const isFetchError = err.message === 'Failed to fetch' || err.name === 'TypeError';
        setError(isFetchError ? "Network Error: Could not reach database." : formatError(err));
        if (isFetchError) setSyncStatus('offline');
      }
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchGames();
    const channel = supabase
      .channel('public:games')
      .on('postgres_changes', { event: '*', table: 'games', schema: 'public' }, () => fetchGames())
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [fetchGames]);

  const saveSheetUrl = (webAppUrl: string, viewUrl: string) => {
    localStorage.setItem(STORAGE_KEY, webAppUrl);
    localStorage.setItem(VIEW_STORAGE_KEY, viewUrl);
    setSheetUrl(webAppUrl);
    setSpreadsheetViewUrl(viewUrl);
  };

  const clearSheetUrl = () => {
    localStorage.removeItem(STORAGE_KEY);
    localStorage.removeItem(VIEW_STORAGE_KEY);
    setSheetUrl(null);
    setSpreadsheetViewUrl(null);
  };

  const addGame = useCallback(async (newGameData: Omit<Game, 'id' | 'createdAt' | 'updatedAt'>) => {
    setSyncStatus('syncing');
    try {
      if (!newGameData.createdBy || newGameData.createdBy.length < 10) {
          throw new Error(`Invalid User ID: ${newGameData.createdBy}. Please log out and log back in.`);
      }

      const { error: sbError } = await supabase.from('games').insert([newGameData]);
      if (sbError) throw sbError;

      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
      await fetchGames();
    } catch (err: any) {
      setSyncStatus('error');
      const errorDetail = formatError(err);
      if (err.code === '23503') {
          alert(`Sync Error: Your account ID is not recognized by the database. Please Logout and Login again.`);
      } else {
          alert(`Failed to start game: ${errorDetail}`);
      }
    }
  }, [fetchGames]);

  const updateGame = useCallback(async (gameId: string, updates: Partial<Game>) => {
    setSyncStatus('syncing');
    try {
      const { error: sbError } = await supabase.from('games').update({ ...updates, updatedAt: new Date().toISOString() }).eq('id', gameId);
      if (sbError) throw sbError;
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
      await fetchGames();
    } catch (err: any) {
      setSyncStatus('error');
      const errorDetail = formatError(err);
      alert(`Update failed: ${errorDetail}`);
    }
  }, [fetchGames]);

  const deleteGame = useCallback(async (gameId: string) => {
    setSyncStatus('syncing');
    try {
      const { error: sbError } = await supabase.from('games').delete().eq('id', gameId);
      if (sbError) throw sbError;
      setSyncStatus('synced');
      setTimeout(() => setSyncStatus('idle'), 2000);
      await fetchGames();
    } catch (err: any) {
      setSyncStatus('error');
      const errorDetail = formatError(err);
      alert(`Delete failed: ${errorDetail}`);
    }
  }, [fetchGames]);

  const saveDailySummary = useCallback(async (summary: DailySummary) => {
    // Attempt the full save first
    const { archivedAt, ...payload } = summary;

    try {
      const { error: sbError } = await supabase
          .from('daily_summaries')
          .upsert([payload], { onConflict: 'date' });

      if (sbError) {
          // If we get PGRST204 (column missing), try to save only the absolutely required fields
          if (sbError.code === 'PGRST204') {
              console.warn("Attempting fallback save due to missing columns in daily_summaries table...");
              const fallbackPayload = { 
                  date: payload.date, 
                  totalPaid: payload.totalPaid, 
                  totalLoan: payload.totalLoan 
              };
              const { error: fallbackError } = await supabase
                  .from('daily_summaries')
                  .upsert([fallbackPayload], { onConflict: 'date' });

              if (fallbackError) throw fallbackError;
              return;
          }
          throw sbError;
      }
    } catch (e: any) {
      console.error('Save summary failed:', formatError(e));
      throw e;
    }
  }, []);

  useEffect(() => {
    setSheetUrl(localStorage.getItem(STORAGE_KEY));
    setSpreadsheetViewUrl(localStorage.getItem(VIEW_STORAGE_KEY));
  }, []);

  return (
    <GameContext.Provider value={{ 
      games, addGame, updateGame, deleteGame, saveDailySummary, 
      isLoading, error, isTableMissing, syncStatus, sheetUrl, spreadsheetViewUrl, 
      saveSheetUrl, clearSheetUrl, refetchGames: fetchGames 
    }}>
      {children}
    </GameContext.Provider>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Game, PaymentStatus, GameStatus, DailySummary } from '../types';
import GamesTable from '../components/GamesTable';
import KpiCard from '../components/KpiCard';
import { formatCurrency } from '../lib/utils';
import { Input } from '../components/ui/Input';
import { DollarSignIcon, HashIcon, ClockIcon, AlertTriangle, TrophyIcon, UsersIcon, LoaderCircle, CheckCircle } from '../components/icons';
import PrintResumeButton from '../components/PrintResumeButton';
import { useAuth } from '../hooks/useAuth';
import { useGames } from '../hooks/useGames';
import { useBusinessDay } from '../hooks/useBusinessDay';
import UserManagement from '../components/UserManagement';
import AnalyticsCard from '../components/AnalyticsCard';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '../components/ui/Card';
import { Button } from '../components/ui/Button';
import { Badge } from '../components/ui/Badge';
import DailyClosureReport from '../components/DailyClosureReport';

const AdminPage: React.FC = () => {
  const { user } = useAuth();
  const { games, updateGame, deleteGame, saveDailySummary, error: gameError } = useGames();
  const { businessDate, advanceDay } = useBusinessDay();

  const [selectedDate, setSelectedDate] = useState(businessDate);
  const [isArchiving, setIsArchiving] = useState(false);
  const [showClosureReport, setShowClosureReport] = useState(false);
  const [closureDate, setClosureDate] = useState('');
  const [closureGames, setClosureGames] = useState<Game[]>([]);

  // Custom confirmation state for a better "reaction" in the UI
  const [isConfirmingArchive, setIsConfirmingArchive] = useState(false);
  const [archiveError, setArchiveError] = useState<string | null>(null);

  useEffect(() => {
    setSelectedDate(businessDate);
  }, [businessDate]);

  const isLiveDay = selectedDate === businessDate;

  const filteredGames = useMemo(() => {
    return games
      .filter(game => game.date === selectedDate)
      .sort((a, b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime());
  }, [games, selectedDate]);

  const selectedDayStats = useMemo(() => {
    const incomePaid = filteredGames
      .filter(g => g.paymentStatus === PaymentStatus.PAID)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const dayLoans = filteredGames
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const discounts = filteredGames
      .reduce((sum, g) => sum + (g.discountMAD || 0), 0);

    return {
      totalGames: filteredGames.length,
      incomePaid,
      dayLoans,
      discounts,
      runningCount: filteredGames.filter(g => g.status === GameStatus.RUNNING).length
    };
  }, [filteredGames]);

  const globalOutstandingLoans = useMemo(() => {
      return games
        .filter(g => g.paymentStatus === PaymentStatus.LOAN)
        .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);
  }, [games]);

  const allLoansList = useMemo(() => {
    return games
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [games]);

  const getDebtorName = (loan: Game) => {
    if (!loan.player2) return loan.player1;
    if (loan.winner === loan.player1) return loan.player2;
    if (loan.winner === loan.player2) return loan.player1;
    return `${loan.player1}${loan.player2 ? ' & ' + loan.player2 : ''}`;
  };

  const analyticsData = useMemo(() => {
    const playerStats: { [key: string]: { paid: number; loan: number; wins: number } } = {};

    const addPlayerStat = (player: string | null, key: 'paid' | 'loan', value: number) => {
        if (!player || value <= 0) return;
        if (!playerStats[player]) {
            playerStats[player] = { paid: 0, loan: 0, wins: 0 };
        }
        playerStats[player][key] += value;
    };

    games.forEach(game => {
        if (game.status !== GameStatus.FINISHED || !game.finalPriceMAD) return;
        const { player1, player2, winner, finalPriceMAD, paymentStatus } = game;
        if (paymentStatus === PaymentStatus.PAID) {
            const amount = player2 ? finalPriceMAD / 2 : finalPriceMAD;
            addPlayerStat(player1, 'paid', amount);
            addPlayerStat(player2, 'paid', amount);
        } else if (paymentStatus === PaymentStatus.LOAN) {
            let loanee = player1;
            if (player2) {
                if (winner && winner === player1) loanee = player2;
                else if (winner && winner === player2) loanee = player1;
            }
            addPlayerStat(loanee, 'loan', finalPriceMAD);
        }
        if (winner) {
            if (!playerStats[winner]) playerStats[winner] = { paid: 0, loan: 0, wins: 0 };
            playerStats[winner].wins += 1;
        }
    });

    const allPlayers = Object.entries(playerStats).map(([name, stats]) => ({ name, ...stats }));
    const topWinners = [...allPlayers].sort((a, b) => b.wins - a.wins).filter(p => p.wins > 0).slice(0, 5);
    const topPaid = [...allPlayers].sort((a, b) => b.paid - a.paid).filter(p => p.paid > 0).slice(0, 5);
    const playersWithLoans = [...allPlayers].sort((a, b) => b.loan - a.loan).filter(p => p.loan > 0);
    return { topWinners, topPaid, playersWithLoans };
  }, [games]);

  const performArchive = async () => {
    if (isArchiving) return;

    console.log("Archive sequence starting...");
    setIsArchiving(true);
    setArchiveError(null);
    const reportDate = businessDate;
    const reportGames = [...filteredGames];

    try {
      const summary: DailySummary = {
        date: businessDate,
        totalPaid: selectedDayStats.incomePaid,
        totalLoan: selectedDayStats.dayLoans,
        totalDiscount: selectedDayStats.discounts,
        gameCount: selectedDayStats.totalGames,
      };

      await saveDailySummary(summary);
      await advanceDay(); 

      setIsConfirmingArchive(false);
      setClosureDate(reportDate);
      setClosureGames(reportGames);
      setShowClosureReport(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (e: any) {
      console.error("Critical Archive Failure:", e);
      setArchiveError(`Save failed: ${e.message || "Please run SQL repair script in Settings."}`);
    } finally {
      setIsArchiving(false);
    }
  };

  const handleArchiveClick = () => {
    console.log("End session button clicked");
    if (selectedDayStats.runningCount > 0) {
        alert(`CANNOT END SESSION: You have ${selectedDayStats.runningCount} table(s) running. Finish them first.`);
        return;
    }
    setIsConfirmingArchive(true);
  };

  const settleLoan = async (gameId: string) => {
    if (!window.confirm("Mark this debt as settled?")) return;
    try {
        await updateGame(gameId, { paymentStatus: PaymentStatus.PAID });
    } catch (e) {
        console.error("Failed to settle loan", e);
    }
  };

  if (!user) return null;

  if (showClosureReport) {
      return (
        <DailyClosureReport 
            date={closureDate} 
            games={closureGames} 
            onBack={() => setShowClosureReport(false)} 
        />
      );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pt-6">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-6 border-b pb-8 px-1">
        <div className="space-y-2">
          <div className="flex flex-wrap items-center gap-3">
            <h1 className="text-4xl font-black tracking-tighter uppercase leading-none break-all sm:break-normal">Admin Control</h1>
            {isLiveDay ? (
                <Badge className="bg-green-600 hover:bg-green-600 animate-pulse border-none px-3 py-1 text-[10px] font-black">LIVE SESSION</Badge>
            ) : (
                <Badge variant="outline" className="text-muted-foreground border-muted-foreground px-3 py-1 text-[10px] font-black">HISTORY</Badge>
            )}
          </div>
          <p className="text-muted-foreground font-medium text-sm">
            Current Records: <span className="text-foreground font-bold">{new Date(selectedDate + 'T00:00:00').toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}</span>
          </p>
        </div>
        <div className="flex items-center gap-3 bg-muted/40 p-2 rounded-xl border w-full lg:w-auto overflow-hidden">
            <span className="text-[10px] font-black uppercase text-muted-foreground px-2 whitespace-nowrap">View Date:</span>
            <Input
                type="date"
                value={selectedDate}
                onChange={e => setSelectedDate(e.target.value)}
                className="w-full lg:w-[160px] bg-background h-8 text-xs font-bold cursor-pointer border-none shadow-none focus-visible:ring-0"
            />
        </div>
      </div>

      {(gameError || archiveError) && (
        <div className="p-4 bg-destructive/10 border border-destructive/20 rounded-xl text-destructive flex items-center gap-3 animate-bounce-short">
            <AlertTriangle className="h-5 w-5 flex-shrink-0"/>
            <div className="text-xs font-bold">
                <p>{archiveError || `Sync Alert: ${gameError}`}</p>
            </div>
        </div>
      )}

      <div className="grid gap-4 md:grid-cols-4">
        <KpiCard title="Total Games" value={selectedDayStats.totalGames.toString()} icon={<HashIcon />} />
        <KpiCard title="Session Cash" value={`${selectedDayStats.incomePaid.toFixed(2)}`} icon={<DollarSignIcon />} />
        <KpiCard title="New Loans" value={`${selectedDayStats.dayLoans.toFixed(2)}`} icon={<ClockIcon />} />
        <KpiCard title="Global Debt" value={`${globalOutstandingLoans.toFixed(2)}`} icon={<AlertTriangle className="text-amber-500" />} />
      </div>

      <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          <Card className="lg:col-span-1 shadow-sm border-dashed">
              <CardHeader className="bg-muted/10 pb-4">
                  <CardTitle className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Session Performance</CardTitle>
              </CardHeader>
              <CardContent className="grid gap-4 pt-6">
                  <div className="flex items-center justify-between p-3 border-2 border-green-500/10 rounded-xl bg-green-50/30 dark:bg-green-950/10">
                      <span className="text-[10px] font-black uppercase text-green-600/70">Total Paid:</span>
                      <span className="font-black text-green-600">{formatCurrency(selectedDayStats.incomePaid)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border-2 border-amber-500/10 rounded-xl bg-amber-50/30 dark:bg-amber-950/10">
                      <span className="text-[10px] font-black uppercase text-amber-600/70">Total Loaned:</span>
                      <span className="font-black text-amber-600">{formatCurrency(selectedDayStats.dayLoans)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border border-dashed rounded-xl">
                      <span className="text-[10px] font-black uppercase text-muted-foreground">Total Discounts:</span>
                      <span className="font-bold text-muted-foreground">{formatCurrency(selectedDayStats.discounts)}</span>
                  </div>
                  <div className="pt-4 border-t-2 border-zinc-900 dark:border-white mt-2">
                      <div className="flex justify-between items-center px-1">
                          <span className="font-black text-xs uppercase tracking-widest">Gross Session Total:</span>
                          <span className="text-xl font-black">{formatCurrency(selectedDayStats.incomePaid + selectedDayStats.dayLoans)}</span>
                      </div>
                  </div>
              </CardContent>
          </Card>

          <Card className="lg:col-span-2 border-amber-200 dark:border-amber-900/50 shadow-md">
              <CardHeader className="flex flex-row items-center justify-between bg-amber-50/50 dark:bg-amber-950/10 pb-4">
                  <div>
                    <CardTitle className="flex items-center gap-2 text-amber-700 dark:text-amber-400 text-xs font-black uppercase tracking-widest">
                        <ClockIcon className="h-4 w-4" />
                        Live Debt Tracker
                    </CardTitle>
                  </div>
                  <Badge className="bg-amber-500 font-bold text-[10px]">{allLoansList.length} Active Loans</Badge>
              </CardHeader>
              <CardContent className="h-[280px] overflow-y-auto pt-4">
                  {allLoansList.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {allLoansList.map((loan) => (
                            <div key={loan.id} className="flex items-center justify-between p-3 rounded-xl bg-muted/30 border border-transparent hover:border-amber-500/30 transition-all">
                                <div className="grid gap-0.5">
                                    <span className="font-black text-xs text-foreground uppercase tracking-tight">
                                        {getDebtorName(loan)}
                                    </span>
                                    <div className="flex items-center gap-2 text-[10px] text-muted-foreground">
                                        <span className="font-bold text-amber-600/80">{loan.tableName}</span>
                                        <span>•</span>
                                        <span>{new Date(loan.date + 'T00:00:00').toLocaleDateString('en-GB')}</span>
                                    </div>
                                </div>
                                <div className="flex items-center gap-3">
                                    <span className="font-bold text-sm text-amber-600">{formatCurrency(loan.finalPriceMAD)}</span>
                                    <Button size="icon" variant="ghost" className="h-7 w-7 text-green-600 hover:bg-green-500/10 rounded-full" onClick={() => settleLoan(loan.id)}>
                                        <CheckCircle className="h-4 w-4" />
                                    </Button>
                                </div>
                            </div>
                        ))}
                    </div>
                  ) : (
                    <div className="flex flex-col items-center justify-center h-full text-muted-foreground gap-2 opacity-50">
                        <CheckCircle className="h-12 w-12" />
                        <p className="text-[10px] font-black uppercase tracking-widest">Clear Records</p>
                    </div>
                  )}
              </CardContent>
          </Card>
      </div>

      <div className="space-y-4">
        <h2 className="text-xl font-black uppercase tracking-tighter border-b pb-4">Performance Insights</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            <AnalyticsCard title="Hall of Fame" icon={<TrophyIcon className="text-yellow-500" />}>
                {analyticsData.topWinners.length > 0 ? (
                    analyticsData.topWinners.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-xs py-2 border-b border-dashed last:border-b-0">
                            <span className="font-bold uppercase">{player.name}</span>
                            <span className="bg-primary/10 px-2 py-0.5 rounded text-[10px] font-black">{player.wins} WINS</span>
                        </div>
                    ))
                ) : (
                    <p className="text-[10px] text-muted-foreground italic py-4">No data yet.</p>
                )}
            </AnalyticsCard>

            <AnalyticsCard title="Top Revenue" icon={<DollarSignIcon className="text-green-500" />}>
                    {analyticsData.topPaid.length > 0 ? (
                    analyticsData.topPaid.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-xs py-2 border-b border-dashed last:border-b-0">
                            <span className="font-bold uppercase">{player.name}</span>
                            <span className="font-black text-green-600">{formatCurrency(player.paid)}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-[10px] text-muted-foreground italic py-4">No data yet.</p>
                )}
            </AnalyticsCard>

            <AnalyticsCard title="Debtor Summary" icon={<UsersIcon className="text-red-500" />}>
                {analyticsData.playersWithLoans.length > 0 ? (
                    analyticsData.playersWithLoans.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-xs py-2 border-b border-dashed last:border-b-0">
                            <span className="font-bold uppercase">{player.name}</span>
                            <span className="font-black text-destructive">{formatCurrency(player.loan)}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-[10px] text-muted-foreground italic py-4">Records are clear.</p>
                )}
            </AnalyticsCard>
        </div>
      </div>

      <div className="space-y-4">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4 border-b pb-4">
            <h2 className="text-xl font-black uppercase tracking-tighter">Session Activity Log</h2>
            <div className="flex flex-wrap items-center gap-2">
                <PrintResumeButton games={filteredGames} selectedDate={selectedDate} />

                {isLiveDay && (
                    <div className="flex flex-col sm:flex-row items-center gap-2">
                        {isConfirmingArchive ? (
                            <div className="flex flex-col items-center gap-4 p-4 bg-primary text-primary-foreground rounded-xl shadow-2xl animate-in fade-in zoom-in border-4 border-white dark:border-zinc-800">
                                <div className="text-center space-y-1">
                                    <p className="text-xs font-black uppercase tracking-widest">End Current Session?</p>
                                    <p className="text-[10px] opacity-90 max-w-[200px]">All data will be saved and you will start a new day. This cannot be undone.</p>
                                </div>
                                <div className="flex gap-2 w-full">
                                    <Button 
                                        size="sm" 
                                        variant="secondary"
                                        className="flex-1 h-10 font-black uppercase tracking-wider text-[10px]" 
                                        onClick={performArchive}
                                        disabled={isArchiving}
                                    >
                                        {isArchiving ? <LoaderCircle className="h-3 w-3 animate-spin mr-1"/> : "Yes, Save & End"}
                                    </Button>
                                    <Button 
                                        size="sm" 
                                        variant="outline" 
                                        className="flex-1 h-10 font-black uppercase tracking-wider text-[10px] bg-transparent border-white/30 text-white hover:bg-white/10"
                                        onClick={() => setIsConfirmingArchive(false)}
                                        disabled={isArchiving}
                                    >
                                        Cancel
                                    </Button>
                                </div>
                            </div>
                        ) : (
                            <Button 
                                type="button"
                                onClick={handleArchiveClick} 
                                className="bg-primary hover:bg-primary/90 font-black uppercase tracking-widest px-8 shadow-2xl transition-all active:scale-95 border-none h-12"
                            >
                                End Session & Archive
                            </Button>
                        )}
                    </div>
                )}
            </div>
        </div>
        <GamesTable 
            games={filteredGames} 
            isAdmin={true} 
            updateGame={updateGame} 
            deleteGame={deleteGame}
            currentUserId={user.id}
        />
      </div>

      <div className="pt-12 border-t">
        <h2 className="text-xl font-black uppercase tracking-tighter mb-6">User Management</h2>
        <UserManagement />
      </div>
    </div>
  );
};

export default AdminPage;

import React, { useState, useEffect } from 'react';
