      <div className="grid gap-4 md:grid-cols-4">
        <KpiCard title="Games Played" value={selectedDayStats.totalGames.toString()} icon={<HashIcon />} />
        <KpiCard title="Cash Income" value={`${selectedDayStats.incomePaid.toFixed(2)}`} icon={<DollarSignIcon />} />
        <KpiCard title="Total Loans" value={`${selectedDayStats.dayLoans.toFixed(2)}`} icon={<ClockIcon />} />
        <KpiCard title="Global Debt" value={`${globalOutstandingLoans.toFixed(2)}`} icon={<AlertTriangle className="text-amber-500" />} />
      </div>

      <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          <Card className="lg:col-span-1 shadow-sm border-dashed">
