const DashboardPage: React.FC = () => {
  const { user } = useAuth();
  const { games, addGame, updateGame, isTableMissing } = useGames();
  const { businessDate } = useBusinessDay();
  const [player1, setPlayer1] = useState('');
  const [player2, setPlayer2] = useState('');
  const [selectedTableId, setSelectedTableId] = useState('');

  // Identify busy tables (tables with at least one running game)
  const busyTableNames = useMemo(() => {
    return games
      .filter(g => g.status === GameStatus.RUNNING)
      .map(g => g.tableName);
  }, [games]);

  const handleStartGame = () => {
    if (!player1 || !user) {
      alert('Player 1 name is required.');
      return;
    }

    if (!selectedTableId) {
      alert('Please select a table.');
      return;
    }

    const tableConfig = TABLES.find(t => t.id === selectedTableId);
    const tableName = tableConfig ? tableConfig.name : 'Unknown';
    const hourlyRate = tableConfig ? tableConfig.rate : DEFAULT_HOURLY_RATE;

    // Check if table is already busy
    const isTableBusy = games.some(g => g.tableName === tableName && g.status === GameStatus.RUNNING);

    if (isTableBusy) {
      alert(`Table "${tableName}" is currently occupied. Please finish the current game before starting a new one.`);
      return;
    }

    addGame({
      date: businessDate,
      tableName: tableName,
      hourlyRate: hourlyRate,
      startTime: new Date().toISOString(),
      endTime: null,
      player1,
      player2: player2 || null,
      winner: null,
      status: GameStatus.RUNNING,
      durationSeconds: null,
      priceMAD: null,
      discountMAD: 0,
      finalPriceMAD: null,
      paymentStatus: PaymentStatus.PENDING,
      notes: null,
      createdBy: user.id,
      modifiedBy: null,
    });

    setPlayer1('');
    setPlayer2('');
    setSelectedTableId('');
  };

  // CRITICAL FIX: Filter "My Added Games" by the current business date so it resets on End Session
  const myCurrentSessionGames = useMemo(() => {
    return games.filter(game => 
        game.createdBy === user?.id && 
        game.date === businessDate
    );
  }, [games, user?.id, businessDate]);

  const allDayGames = useMemo(() => {
    return games.filter(g => g.date === businessDate);
  }, [games, businessDate]);

  const formattedDate = new Date(businessDate + 'T00:00:00').toLocaleDateString('en-GB', {
    weekday: 'long',
    day: 'numeric',
    month: 'long',
    year: 'numeric'
  });

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Dynamic Header showing the current session state */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 border-b pb-6">
        <div className="space-y-1">
          <h1 className="text-3xl font-black tracking-tighter uppercase">Player Dashboard</h1>
          <div className="flex items-center gap-2 text-muted-foreground">
            <ClockIcon className="h-4 w-4" />
            <span className="text-sm font-bold">Session: <span className="text-foreground underline decoration-primary/30 underline-offset-4">{formattedDate}</span></span>
          </div>
        </div>
        <Badge className="bg-primary/10 text-primary border-primary/20 font-black px-4 py-1.5 uppercase tracking-widest text-[10px]">
            {allDayGames.length} Games Total Today
        </Badge>
      </div>

      {isTableMissing && (
        <Card className="border-destructive bg-destructive/10 border-2 shadow-lg">
          <CardContent className="p-4 flex items-center gap-4">
            <AlertTriangle className="h-8 w-8 text-destructive animate-pulse" />
            <div className="flex-1">
              <p className="font-black text-destructive uppercase tracking-tight">Database Offline</p>
              <p className="text-xs font-bold opacity-80 uppercase tracking-tight">Setup Required: Open Settings (gear icon) to initialize Supabase.</p>
            </div>
          </CardContent>
        </Card>
      )}

      <Card className="border-2 shadow-sm border-zinc-200 dark:border-zinc-800 overflow-hidden">
        <div className="bg-muted/30 px-6 py-4 border-b">
            <h2 className="text-sm font-black uppercase tracking-widest">New Game Entry</h2>
        </div>
        <CardContent className="p-6">
