            <div className="grid w-full lg:max-w-[240px] items-center gap-2">
                <label className="text-[10px] font-black uppercase tracking-widest opacity-60 ml-1">Select Table</label>
                <Select value={selectedTableId} onChange={e => setSelectedTableId(e.target.value)} disabled={isTableMissing} className="h-12 font-bold">
                  <option value="" disabled>Choose Table...</option>
                  {TABLES.map(t => {
