export default DashboardPage;

import React, { useState, useEffect } from 'react';
import { Game, GameStatus, PaymentStatus } from '../types';
import { formatCurrency, formatDuration, calculateLivePrice, calculateFinalPrice, getMinPrice } from '../lib/utils';
import { Badge } from './ui/Badge';
import { Button } from './ui/Button';
import { MoreVerticalIcon, ClockIcon } from './icons';
import { Input } from './ui/Input';
import { Select } from './ui/Select';
import { TABLES, DEFAULT_HOURLY_RATE } from '../constants';

interface GameRowProps {
  game: Game;
  isAdmin: boolean;
  updateGame?: (gameId: string, updates: Partial<Game>) => void;
  deleteGame?: (gameId:string) => void;
  currentUserId?: string;
}

const GameRow: React.FC<GameRowProps> = ({ game, isAdmin, updateGame, deleteGame, currentUserId }) => {
    const gameRate = game.hourlyRate || DEFAULT_HOURLY_RATE;

    const calculateCurrentDuration = () => {
        if (game.status === GameStatus.RUNNING) {
            const start = new Date(game.startTime).getTime();
            const now = Date.now();
            return Math.max(0, Math.floor((now - start) / 1000));
        }
        return 0;
    };

    const [liveDuration, setLiveDuration] = useState<number>(calculateCurrentDuration);

    const [livePrice, setLivePrice] = useState<number>(() => {
         if (game.status === GameStatus.RUNNING) {
             return calculateLivePrice(game.startTime, gameRate, game.tableName);
         }
         return 0;
    });

    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [isEditing, setIsEditing] = useState(false);

    const [editableGame, setEditableGame] = useState({
      tableName: game.tableName ?? '',
      hourlyRate: gameRate,
      player1: game.player1,
      player2: game.player2 ?? '',
      winner: game.winner ?? null,
      discountMAD: game.discountMAD ?? 0,
      status: game.status,
      paymentStatus: game.paymentStatus === PaymentStatus.PENDING ? PaymentStatus.PAID : game.paymentStatus,
      finalPriceMAD: game.finalPriceMAD ?? 0,
    });

    useEffect(() => {
        if (game.status === GameStatus.RUNNING && !isEditing) {
            const updateStats = () => {
                setLiveDuration(calculateCurrentDuration());
                setLivePrice(calculateLivePrice(game.startTime, gameRate, game.tableName));
            };

            updateStats();
            const interval = setInterval(updateStats, 1000);
            return () => clearInterval(interval);
        }
    }, [game.status, game.startTime, isEditing, gameRate, game.tableName]);

    const resetEditableGame = () => {
        setEditableGame({
            tableName: game.tableName ?? '',
            hourlyRate: gameRate,
            player1: game.player1,
            player2: game.player2 ?? '',
            winner: game.winner ?? null,
            discountMAD: game.discountMAD ?? 0,
            status: game.status,
            paymentStatus: game.paymentStatus === PaymentStatus.PENDING ? PaymentStatus.PAID : game.paymentStatus,
            finalPriceMAD: game.finalPriceMAD ?? 0,
        });
    };

    const startEditing = () => {
        resetEditableGame();
        setIsEditing(true);
        setIsMenuOpen(false);
    };

    const handleTableChange = (tableId: string) => {
        const config = TABLES.find(t => t.id === tableId);
        if (config) {
             setEditableGame({
                 ...editableGame,
                 tableName: config.name,
                 hourlyRate: config.rate
             });
        }
    };

    const handleStatusChange = (newStatus: GameStatus) => {
        let newFinalPrice = editableGame.finalPriceMAD;
        if (game.status === GameStatus.RUNNING && newStatus === GameStatus.FINISHED) {
            const endTime = new Date().toISOString();
            const discount = isAdmin ? Number(editableGame.discountMAD) : game.discountMAD;
            const { finalPrice } = calculateFinalPrice(game.startTime, endTime, discount, editableGame.hourlyRate, editableGame.tableName);
            newFinalPrice = Number(finalPrice.toFixed(2));
        }

        setEditableGame({
            ...editableGame,
            status: newStatus,
            finalPriceMAD: newFinalPrice,
        });
    }

    const handleSaveChanges = () => {
      if (!updateGame || !currentUserId) return;

      const updates: Partial<Game> = {
          tableName: editableGame.tableName,
          hourlyRate: editableGame.hourlyRate,
          player1: editableGame.player1,
          player2: editableGame.player2 || null,
          winner: editableGame.winner,
          paymentStatus: editableGame.paymentStatus,
          modifiedBy: currentUserId,
      };

      if (game.status === GameStatus.RUNNING && editableGame.status === GameStatus.FINISHED) {
          const endTime = new Date().toISOString();
          const discount = isAdmin ? Number(editableGame.discountMAD) : game.discountMAD;
          const { durationSeconds, price, finalPrice } = calculateFinalPrice(game.startTime, endTime, discount, editableGame.hourlyRate, editableGame.tableName);

          updates.status = GameStatus.FINISHED;
          updates.endTime = endTime;
          updates.durationSeconds = durationSeconds;
          updates.priceMAD = price;
          updates.finalPriceMAD = Math.max(getMinPrice(editableGame.tableName), Number(editableGame.finalPriceMAD));
          updates.discountMAD = discount;
      } else if (game.status === GameStatus.FINISHED) {
        updates.finalPriceMAD = Number(editableGame.finalPriceMAD);
        if (isAdmin) {
          updates.discountMAD = Number(editableGame.discountMAD);
        }
      }

      updateGame(game.id, updates);
      setIsEditing(false);
      setIsMenuOpen(false);
    };

    const handleCancelEdit = () => {
      setIsEditing(false);
      resetEditableGame();
    };

    const priceToDisplay = game.status === GameStatus.RUNNING ? livePrice : (game.finalPriceMAD ?? 0);
    const durationToDisplay = game.status === GameStatus.RUNNING ? liveDuration : (game.durationSeconds ?? 0);

    const statusColors = {
        [PaymentStatus.PAID]: 'border-green-500 bg-green-500/10',
        [PaymentStatus.PENDING]: 'border-blue-500 bg-blue-500/10',
        [PaymentStatus.LOAN]: 'border-amber-500 bg-amber-500/10',
    };

    const paymentStatusBadge = {
        [PaymentStatus.PAID]: 'bg-green-600 text-white',
        [PaymentStatus.PENDING]: 'bg-blue-600 text-white',
        [PaymentStatus.LOAN]: 'bg-amber-500 text-white',
    };

    const canCurrentUserEdit = game.createdBy === currentUserId && !isAdmin;
    const showActions = isAdmin || canCurrentUserEdit;
    const currentTableConfig = TABLES.find(t => t.name === editableGame.tableName);
    const currentTableId = currentTableConfig ? currentTableConfig.id : '';

    if (isEditing) {
        return (
            <tr className="border-b">
                <td colSpan={8} className="p-4 bg-muted/20">
                    <div className="max-w-2xl mx-auto space-y-6 animate-in slide-in-from-top-2">
                        <h4 className="text-xs font-black uppercase tracking-[0.2em] border-b pb-2">Edit Game Record</h4>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                            <div className="space-y-1">
                                <label className="text-[10px] font-black uppercase opacity-60">Table</label>
                                <Select value={currentTableId} onChange={(e) => handleTableChange(e.target.value)} className="w-full h-11">
                                    <option value="" disabled>Select Table</option>
                                    {TABLES.map(t => (
                                        <option key={t.id} value={t.id}>{t.name}</option>
                                    ))}
                                </Select>
                            </div>
                             <div className="space-y-1">
                                <label className="text-[10px] font-black uppercase opacity-60">Player 1</label>
                                <Input type="text" value={editableGame.player1} onChange={(e) => setEditableGame({...editableGame, player1: e.target.value})} className="h-11 font-bold" />
                            </div>
                            <div className="space-y-1">
                                <label className="text-[10px] font-black uppercase opacity-60">Player 2</label>
                                <Input type="text" value={editableGame.player2} onChange={(e) => setEditableGame({...editableGame, player2: e.target.value})} className="h-11 font-bold" />
                            </div>
                            <div className="space-y-1">
                                <label className="text-[10px] font-black uppercase opacity-60">Status</label>
                                 <Select value={editableGame.status} onChange={(e) => handleStatusChange(e.target.value as GameStatus)} disabled={game.status === GameStatus.FINISHED} className="w-full h-11">
                                    <option value={GameStatus.RUNNING}>Running</option>
                                    <option value={GameStatus.FINISHED}>Finished</option>
                                </Select>
                            </div>
                            {editableGame.status === GameStatus.FINISHED && (
                                 <div className="space-y-1">
                                    <label className="text-[10px] font-black uppercase opacity-60">Final Price (MAD)</label>
                                    <Input type="number" value={editableGame.finalPriceMAD} onChange={(e) => setEditableGame({ ...editableGame, finalPriceMAD: Number(e.target.value) })} className="h-11 font-black text-primary" />
                                </div>
                            )}
                            <div className="space-y-1">
                                <label className="text-[10px] font-black uppercase opacity-60">Payment</label>
                                <Select 
                                    value={editableGame.paymentStatus} 
                                    onChange={(e) => setEditableGame({ ...editableGame, paymentStatus: e.target.value as PaymentStatus.PAID | PaymentStatus.LOAN })} 
                                    disabled={editableGame.status !== GameStatus.FINISHED}
                                    className="w-full h-11 font-bold"
                                >
                                    <option value={PaymentStatus.PAID}>Paid</option>
                                    <option value={PaymentStatus.LOAN}>Loan</option>
                                </Select>
                            </div>
                        </div>
                        <div className="flex items-center gap-2 pt-4">
                            <Button className="flex-1 h-12 font-black uppercase tracking-widest" onClick={handleSaveChanges}>Save Changes</Button>
                            <Button variant="ghost" className="h-12 px-6 font-bold" onClick={handleCancelEdit}>Cancel</Button>
                        </div>
                    </div>
                </td>
            </tr>
        );
    }

    return (
        <>
        {/* Desktop View Row */}
        <tr className="border-b transition-colors hover:bg-muted/50 hidden md:table-row">
            <td className="p-4 align-middle">{game.tableName ?? '-'}</td>
            <td className="p-4 align-middle font-bold">
                {`${game.player1}${game.player2 ? `, ${game.player2}` : ''}`}
                {game.winner && <div className="text-[10px] font-black text-green-500 uppercase tracking-tighter">Winner: {game.winner}</div>}
            </td>
            <td className="p-4 align-middle text-muted-foreground text-[10px] font-bold uppercase">
                <div>{new Date(game.startTime).toLocaleTimeString()}</div>
                {game.endTime && <div>{new Date(game.endTime).toLocaleTimeString()}</div>}
            </td>
            <td className="p-4 align-middle font-mono">{formatDuration(durationToDisplay)}</td>
            <td className="p-4 align-middle">
                <div className="font-black">{formatCurrency(priceToDisplay)}</div>
            </td>
            <td className="p-4 align-middle">
                <Badge variant={game.status === GameStatus.RUNNING ? "default" : "secondary"} className="uppercase font-black text-[9px]">{game.status}</Badge>
            </td>
            <td className="p-4 align-middle">
                <Badge className={`${paymentStatusBadge[game.paymentStatus]} uppercase font-black text-[9px] border-none`}>
                    {game.paymentStatus === PaymentStatus.PENDING ? 'Active' : game.paymentStatus}
                </Badge>
            </td>
            {showActions && (
                <td className="p-4 align-middle text-right">
                    <Button variant="ghost" size="icon" onClick={startEditing} className="rounded-full hover:bg-primary/10">
                        <MoreVerticalIcon className="h-4 w-4" />
                    </Button>
                </td>
            )}
        </tr>

        {/* 3D Professional Mobile View Card */}
        <tr className="md:hidden border-none bg-transparent">
            <td colSpan={8} className="p-3 border-none bg-transparent">
                <div className={`relative overflow-hidden rounded-2xl border-l-4 shadow-md transition-all active:scale-[0.98] ${statusColors[game.paymentStatus]} bg-card dark:bg-zinc-900 border-t border-r border-b border-border`}>
                    <div className="p-5 space-y-4">
                        {/* Top Section: Table & Action */}
                        <div className="flex justify-between items-start">
                            <div className="space-y-1">
                                <Badge className="bg-zinc-900 dark:bg-zinc-100 text-zinc-100 dark:text-zinc-900 uppercase font-black text-[9px] tracking-widest border-none px-2 py-0.5 rounded-sm">
                                    {game.tableName}
                                </Badge>
                                <div className="flex items-center gap-1.5 text-muted-foreground">
                                    <ClockIcon className="h-3 w-3" />
                                    <span className="text-[10px] font-bold uppercase tracking-tight">
                                        {new Date(game.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                        {game.endTime && ` — ${new Date(game.endTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}`}
                                    </span>
                                </div>
                            </div>
                            {showActions && (
                                <Button 
                                    size="sm" 
                                    variant="outline" 
                                    onClick={startEditing}
                                    className="h-8 rounded-full text-[10px] font-black uppercase tracking-widest px-4 border-zinc-300 dark:border-zinc-700 hover:bg-zinc-100"
                                >
                                    Edit
                                </Button>
                            )}
                        </div>

                        {/* Mid Section: Players */}
                        <div className="space-y-0.5">
                            <h3 className="text-lg font-black tracking-tight leading-tight uppercase truncate">
                                {game.player1}
                                {game.player2 && <span className="text-muted-foreground mx-1 text-sm font-bold opacity-50">VS</span>}
                                {game.player2 && game.player2}
                            </h3>
                            {game.winner && (
                                <div className="flex items-center gap-1 text-green-600">
                                    <div className="h-1.5 w-1.5 rounded-full bg-green-600 animate-pulse"></div>
                                    <span className="text-[9px] font-black uppercase tracking-widest">Winner: {game.winner}</span>
                                </div>
                            )}
                        </div>

                        {/* Bottom Section: Stats Grid */}
                        <div className="grid grid-cols-2 gap-4 pt-4 border-t border-zinc-200/50 dark:border-zinc-800/50">
                            <div className="space-y-1">
                                <p className="text-[9px] font-black uppercase tracking-widest opacity-50">Live Timer</p>
                                <div className={`font-mono text-sm font-black ${game.status === GameStatus.RUNNING ? 'text-primary' : 'text-muted-foreground'}`}>
                                    {formatDuration(durationToDisplay)}
                                </div>
                            </div>
                            <div className="text-right space-y-1">
                                <p className="text-[9px] font-black uppercase tracking-widest opacity-50">Current Total</p>
                                <div className={`text-xl font-black ${game.paymentStatus === PaymentStatus.LOAN ? 'text-amber-600' : 'text-foreground'}`}>
                                    {formatCurrency(priceToDisplay)}
                                </div>
                            </div>
                        </div>

                        {/* Status Bar Footer */}
                        <div className="flex items-center justify-between gap-3 pt-2">
                            <div className="flex items-center gap-2">
                                <Badge className={`${paymentStatusBadge[game.paymentStatus]} border-none uppercase font-black text-[9px] tracking-widest px-2`}>
                                    {game.paymentStatus === PaymentStatus.PENDING ? 'Active Session' : game.paymentStatus}
                                </Badge>
                                {game.status === GameStatus.RUNNING && (
                                    <div className="flex items-center gap-1">
                                        <div className="h-1 w-1 rounded-full bg-primary animate-ping"></div>
                                        <span className="text-[8px] font-black text-primary uppercase tracking-widest">In Progress</span>
                                    </div>
                                )}
                            </div>
                            {game.discountMAD > 0 && (
                                <span className="text-[10px] font-black text-red-500 uppercase">-{formatCurrency(game.discountMAD)} Disc.</span>
                            )}
                        </div>
                    </div>
                </div>
            </td>
        </tr>
        </>
    );
};

