            discountMAD: game.discountMAD ?? 0,
            status: game.status,
            paymentStatus: game.paymentStatus === PaymentStatus.PENDING ? PaymentStatus.PAID : game.paymentStatus,
            finalPriceMAD: game.finalPriceMAD ?? 0,
        });
    };

    const startEditing = () => {
        resetEditableGame();
        setIsEditing(true);
    };

    const handleTableChange = (tableId: string) => {
        const config = TABLES.find(t => t.id === tableId);
        if (config) {
             setEditableGame({
                 ...editableGame,
                 tableName: config.name,
                 hourlyRate: config.rate
             });
        }
    };

    const handleStatusChange = (newStatus: GameStatus) => {
        let newFinalPrice = editableGame.finalPriceMAD;
        if (game.status === GameStatus.RUNNING && newStatus === GameStatus.FINISHED) {
            const endTime = new Date().toISOString();
            const discount = isAdmin ? Number(editableGame.discountMAD) : game.discountMAD;
            const { finalPrice } = calculateFinalPrice(game.startTime, endTime, discount, editableGame.hourlyRate, editableGame.tableName);
            newFinalPrice = Number(finalPrice.toFixed(2));
        }

        setEditableGame({
            ...editableGame,
            status: newStatus,
            finalPriceMAD: newFinalPrice,
        });
    }

    const handleSaveChanges = () => {
      if (!updateGame || !currentUserId) return;

      const updates: Partial<Game> = {
          tableName: editableGame.tableName,
          hourlyRate: editableGame.hourlyRate,
          player1: editableGame.player1,
          player2: editableGame.player2 || null,
          winner: editableGame.winner,
          paymentStatus: editableGame.paymentStatus,
          modifiedBy: currentUserId,
      };

      if (game.status === GameStatus.RUNNING && editableGame.status === GameStatus.FINISHED) {
          const endTime = new Date().toISOString();
          const discount = isAdmin ? Number(editableGame.discountMAD) : game.discountMAD;
          const { durationSeconds, price, finalPrice } = calculateFinalPrice(game.startTime, endTime, discount, editableGame.hourlyRate, editableGame.tableName);

          updates.status = GameStatus.FINISHED;
          updates.endTime = endTime;
          updates.durationSeconds = durationSeconds;
          updates.priceMAD = price;
          updates.finalPriceMAD = Math.max(getMinPrice(editableGame.tableName), Number(editableGame.finalPriceMAD));
          updates.discountMAD = discount;
      } else if (game.status === GameStatus.FINISHED) {
        updates.finalPriceMAD = Number(editableGame.finalPriceMAD);
        if (isAdmin) {
          updates.discountMAD = Number(editableGame.discountMAD);
        }
      }

      updateGame(game.id, updates);
      setIsEditing(false);
    };

    const handleCancelEdit = () => {
      setIsEditing(false);
      resetEditableGame();
    };

    const priceToDisplay = game.status === GameStatus.RUNNING ? livePrice : (game.finalPriceMAD ?? 0);
    const durationToDisplay = game.status === GameStatus.RUNNING ? liveDuration : (game.durationSeconds ?? 0);

    const getDebtorName = () => {
        if (game.paymentStatus !== PaymentStatus.LOAN) return null;
        if (!game.player2) return game.player1;
        if (game.winner === game.player1) return game.player2;
        if (game.winner === game.player2) return game.player1;
        return game.player1; // Fallback
    };

    const statusColors = {
        [PaymentStatus.PAID]: 'border-green-500 bg-green-500/[0.03]',
        [PaymentStatus.PENDING]: 'border-blue-500 bg-blue-500/[0.03]',
        [PaymentStatus.LOAN]: 'border-amber-500 bg-amber-500/[0.03]',
    };

    const paymentStatusBadge = {
        [PaymentStatus.PAID]: 'bg-green-600 text-white',
        [PaymentStatus.PENDING]: 'bg-blue-600 text-white',
        [PaymentStatus.LOAN]: 'bg-amber-500 text-white',
    };

    const showActions = isAdmin || (game.createdBy === currentUserId && !isAdmin);
    const currentTableConfig = TABLES.find(t => t.name === editableGame.tableName);
    const currentTableId = currentTableConfig ? currentTableConfig.id : '';

    if (isEditing) {
        return (
            <tr className="border-b">
                <td colSpan={8} className="p-0 bg-background">
                    <div className="p-6 md:p-8 space-y-8 animate-in slide-in-from-bottom-4">
                        <div className="flex justify-between items-center border-b pb-4">
                            <h4 className="text-xl font-black uppercase tracking-tighter">Edit Game Details</h4>
                            <Badge variant="outline" className="text-[10px] font-black">{game.tableName}</Badge>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="space-y-4">
                                <div className="space-y-1.5">
                                    <label className="text-[10px] font-black uppercase opacity-60 ml-1">Assigned Table</label>
                                    <Select value={currentTableId} onChange={(e) => handleTableChange(e.target.value)} className="w-full h-12 text-base font-bold">
                                        {TABLES.map(t => (
                                            <option key={t.id} value={t.id}>{t.name}</option>
                                        ))}
                                    </Select>
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-1.5">
                                        <label className="text-[10px] font-black uppercase opacity-60 ml-1">Player 1</label>
                                        <Input type="text" value={editableGame.player1} onChange={(e) => setEditableGame({...editableGame, player1: e.target.value})} className="h-12 font-bold" />
                                    </div>
                                    <div className="space-y-1.5">
                                        <label className="text-[10px] font-black uppercase opacity-60 ml-1">Player 2</label>
                                        <Input type="text" value={editableGame.player2} onChange={(e) => setEditableGame({...editableGame, player2: e.target.value})} className="h-12 font-bold" />
                                    </div>
                                </div>
                                <div className="space-y-1.5">
                                    <label className="text-[10px] font-black uppercase opacity-60 ml-1">Game Session Status</label>
                                     <div className="flex p-1 bg-muted rounded-xl gap-1">
                                        <button 
                                            onClick={() => handleStatusChange(GameStatus.RUNNING)}
                                            disabled={game.status === GameStatus.FINISHED}
                                            className={`flex-1 py-3 rounded-lg text-xs font-black uppercase transition-all ${editableGame.status === GameStatus.RUNNING ? 'bg-background shadow text-primary' : 'text-muted-foreground'}`}
                                        >
                                            Running
                                        </button>
                                        <button 
                                            onClick={() => handleStatusChange(GameStatus.FINISHED)}
                                            className={`flex-1 py-3 rounded-lg text-xs font-black uppercase transition-all ${editableGame.status === GameStatus.FINISHED ? 'bg-background shadow text-primary' : 'text-muted-foreground'}`}
                                        >
                                            Finished
                                        </button>
                                     </div>
                                </div>
                            </div>

                            <div className="space-y-4">
                                {editableGame.status === GameStatus.FINISHED && (
                                    <>
                                    <div className="space-y-1.5">
                                        <label className="text-[10px] font-black uppercase opacity-60 ml-1">Total Billable Amount (MAD)</label>
                                        <div className="relative">
                                            <div className="absolute left-3 top-1/2 -translate-y-1/2 font-black text-muted-foreground">DH</div>
                                            <Input 
                                                type="number" 
                                                value={editableGame.finalPriceMAD} 
                                                onChange={(e) => setEditableGame({ ...editableGame, finalPriceMAD: Number(e.target.value) })} 
                                                className="h-14 pl-10 text-2xl font-black text-primary border-2 border-primary/20 focus:border-primary" 
                                            />
                                        </div>
                                    </div>
                                    <div className="space-y-1.5">
                                        <label className="text-[10px] font-black uppercase opacity-60 ml-1">Payment Method</label>
                                        <div className="grid grid-cols-2 gap-3">
                                            <button 
                                                onClick={() => setEditableGame({ ...editableGame, paymentStatus: PaymentStatus.PAID })}
                                                className={`flex flex-col items-center gap-2 p-4 rounded-2xl border-2 transition-all ${editableGame.paymentStatus === PaymentStatus.PAID ? 'bg-green-600 border-green-600 text-white shadow-lg scale-[1.02]' : 'bg-muted/50 border-transparent text-muted-foreground'}`}
                                            >
                                                <CheckCircle className="h-6 w-6" />
                                                <span className="text-xs font-black uppercase">Paid Cash</span>
                                            </button>
                                            <button 
                                                onClick={() => setEditableGame({ ...editableGame, paymentStatus: PaymentStatus.LOAN })}
                                                className={`flex flex-col items-center gap-2 p-4 rounded-2xl border-2 transition-all ${editableGame.paymentStatus === PaymentStatus.LOAN ? 'bg-amber-500 border-amber-500 text-white shadow-lg scale-[1.02]' : 'bg-muted/50 border-transparent text-muted-foreground'}`}
                                            >
                                                <AlertTriangle className="h-6 w-6" />
                                                <span className="text-xs font-black uppercase">Add to Loan</span>
                                            </button>
                                        </div>
                                    </div>
                                    </>
                                )}
                            </div>
                        </div>

                        <div className="flex gap-3 pt-6 border-t">
                            <Button className="flex-1 h-14 text-base font-black uppercase tracking-widest shadow-xl" onClick={handleSaveChanges}>Apply Changes</Button>
                            <Button variant="outline" className="h-14 px-8 font-black uppercase text-xs tracking-widest" onClick={handleCancelEdit}>Discard</Button>
                        </div>
                    </div>
                </td>
            </tr>
        );
    }

    return (
        <>
        {/* Desktop View Row */}
        <tr className="border-b transition-colors hover:bg-muted/50 hidden md:table-row">
            <td className="p-4 align-middle font-bold text-muted-foreground/60">{game.tableName}</td>
            <td className="p-4 align-middle">
                <div className="font-black text-base uppercase">{game.player1}{game.player2 ? ` vs ${game.player2}` : ''}</div>
                {game.winner && <div className="text-[10px] font-black text-green-600 uppercase">Winner: {game.winner}</div>}
            </td>
            <td className="p-4 align-middle text-[10px] font-bold uppercase text-muted-foreground">
                {new Date(game.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                {game.endTime && ` — ${new Date(game.endTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}`}
            </td>
            <td className="p-4 align-middle font-mono font-bold">{formatDuration(durationToDisplay)}</td>
            <td className="p-4 align-middle">
                <div className={`font-black text-lg ${game.paymentStatus === PaymentStatus.LOAN ? 'text-amber-600' : 'text-foreground'}`}>
                    {formatCurrency(priceToDisplay)}
                </div>
            </td>
            <td className="p-4 align-middle">
                <Badge variant={game.status === GameStatus.RUNNING ? "default" : "secondary"} className="uppercase font-black text-[9px]">{game.status}</Badge>
            </td>
            <td className="p-4 align-middle">
                <div className="flex items-center gap-2">
                    <Badge className={`${paymentStatusBadge[game.paymentStatus]} uppercase font-black text-[9px] border-none px-3`}>
                        {game.paymentStatus === PaymentStatus.PENDING ? 'Active' : game.paymentStatus}
                    </Badge>
                    {game.paymentStatus === PaymentStatus.LOAN && <AlertTriangle className="h-4 w-4 text-amber-500" />}
                    {game.paymentStatus === PaymentStatus.PAID && <CheckCircle className="h-4 w-4 text-green-500" />}
                </div>
            </td>
            {showActions && (
                <td className="p-4 align-middle text-right">
                    <Button variant="ghost" size="icon" onClick={startEditing} className="rounded-full hover:bg-primary/10">
                        <MoreVerticalIcon className="h-4 w-4" />
                    </Button>
                </td>
            )}
        </tr>

        {/* 3D Professional Mobile Card with Watermark Distinctions */}
        <tr className="md:hidden border-none bg-transparent">
            <td colSpan={8} className="p-3 border-none bg-transparent">
                <div className={`relative overflow-hidden rounded-3xl border-l-[6px] shadow-xl transition-all active:scale-[0.97] ${statusColors[game.paymentStatus]} bg-card dark:bg-zinc-900 border-t border-r border-b border-border`}>

                    {/* Visual Status Watermark (Hidden helper for recognition) */}
                    <div className="absolute -right-4 -top-4 opacity-[0.05] dark:opacity-[0.08] pointer-events-none">
                        {game.paymentStatus === PaymentStatus.PAID && <DollarSignIcon className="h-32 w-32 rotate-12" />}
                        {game.paymentStatus === PaymentStatus.LOAN && <AlertTriangle className="h-32 w-32 -rotate-12" />}
                        {game.paymentStatus === PaymentStatus.PENDING && <ClockIcon className="h-32 w-32" />}
                    </div>

                    <div className="p-6 space-y-5 relative z-10">
                        <div className="flex justify-between items-start">
                            <div className="space-y-1.5">
                                <span className="bg-zinc-900 dark:bg-zinc-100 text-zinc-100 dark:text-zinc-900 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest">
                                    {game.tableName}
                                </span>
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    <ClockIcon className="h-3.5 w-3.5" />
                                    <span className="text-[11px] font-black uppercase">
                                        {new Date(game.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                        {game.endTime && ` • ${new Date(game.endTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}`}
                                    </span>
                                </div>
                            </div>
                            {showActions && (
                                <Button 
                                    size="sm" 
                                    onClick={startEditing}
                                    className="h-10 rounded-2xl text-[10px] font-black uppercase px-5 bg-primary/5 hover:bg-primary/10 text-primary border border-primary/10"
                                >
                                    Edit
                                </Button>
                            )}
                        </div>

                        <div className="space-y-1">
                            <h3 className="text-xl font-black tracking-tighter leading-none uppercase truncate text-zinc-900 dark:text-zinc-50">
                                {game.player1}
                                {game.player2 && <span className="text-muted-foreground/30 mx-2 text-sm">vs</span>}
                                {game.player2}
                            </h3>
                            {getDebtorName() && (
                                <div className="inline-flex items-center gap-1.5 px-2 py-0.5 rounded bg-amber-500 text-white animate-pulse">
                                    <AlertTriangle className="h-3 w-3" />
                                    <span className="text-[9px] font-black uppercase">Owed by: {getDebtorName()}</span>
                                </div>
                            )}
                        </div>

                        <div className="grid grid-cols-2 gap-4 py-4 border-y border-dashed border-border/50">
                            <div className="space-y-0.5">
                                <p className="text-[9px] font-black uppercase tracking-widest text-muted-foreground">Duration</p>
                                <div className={`font-mono text-base font-black ${game.status === GameStatus.RUNNING ? 'text-blue-600' : 'text-zinc-500'}`}>
                                    {formatDuration(durationToDisplay)}
                                </div>
                            </div>
                            <div className="text-right space-y-0.5">
                                <p className="text-[9px] font-black uppercase tracking-widest text-muted-foreground">Total Charge</p>
                                <div className={`text-2xl font-black ${game.paymentStatus === PaymentStatus.LOAN ? 'text-amber-600' : 'text-zinc-900 dark:text-zinc-100'}`}>
                                    {formatCurrency(priceToDisplay)}
                                </div>
                            </div>
                        </div>

                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-2">
                                <Badge className={`${paymentStatusBadge[game.paymentStatus]} border-none uppercase font-black text-[10px] tracking-widest px-4 py-1 rounded-lg`}>
                                    {game.paymentStatus === PaymentStatus.PENDING ? 'Session Active' : game.paymentStatus}
                                </Badge>
                                {game.paymentStatus === PaymentStatus.PAID && <CheckCircle className="h-5 w-5 text-green-500" />}
                                {game.paymentStatus === PaymentStatus.LOAN && <AlertTriangle className="h-5 w-5 text-amber-500" />}
                            </div>
                            {game.status === GameStatus.RUNNING && (
                                <div className="flex items-center gap-2 bg-blue-500/10 text-blue-600 px-3 py-1 rounded-lg border border-blue-500/20">
                                    <div className="h-1.5 w-1.5 rounded-full bg-blue-600 animate-ping"></div>
                                    <span className="text-[9px] font-black uppercase">Live</span>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </td>
        </tr>
        </>
    );
};

export default GameRow;

import React, { useState, useMemo, useEffect } from 'react';
import { Game, PaymentStatus, GameStatus, DailySummary } from '../types';
import GamesTable from '../components/GamesTable';
import KpiCard from '../components/KpiCard';
import { formatCurrency } from '../lib/utils';
import { Input } from '../components/ui/Input';
import { DollarSignIcon, HashIcon, ClockIcon, AlertTriangle, TrophyIcon, UsersIcon, LoaderCircle, CheckCircle } from '../components/icons';
import PrintResumeButton from '../components/PrintResumeButton';
import { useAuth } from '../hooks/useAuth';
import { useGames } from '../hooks/useGames';
import { useBusinessDay } from '../hooks/useBusinessDay';
import UserManagement from '../components/UserManagement';
import AnalyticsCard from '../components/AnalyticsCard';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '../components/ui/Card';
import { Button } from '../components/ui/Button';
import { Badge } from '../components/ui/Badge';
import DailyClosureReport from '../components/DailyClosureReport';

const AdminPage: React.FC = () => {
  const { user } = useAuth();
  const { games, updateGame, deleteGame, saveDailySummary, error: gameError } = useGames();
  const { businessDate, advanceDay } = useBusinessDay();

  const [selectedDate, setSelectedDate] = useState(businessDate);
  const [isArchiving, setIsArchiving] = useState(false);
  const [showClosureReport, setShowClosureReport] = useState(false);
  const [closureDate, setClosureDate] = useState('');
  const [closureGames, setClosureGames] = useState<Game[]>([]);

  const [isConfirmingArchive, setIsConfirmingArchive] = useState(false);
  const [archiveError, setArchiveError] = useState<string | null>(null);

  useEffect(() => {
    setSelectedDate(businessDate);
  }, [businessDate]);

  const isLiveDay = selectedDate === businessDate;

  const filteredGames = useMemo(() => {
    return games
      .filter(game => game.date === selectedDate)
      .sort((a, b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime());
  }, [games, selectedDate]);

  const selectedDayStats = useMemo(() => {
    const incomePaid = filteredGames
      .filter(g => g.paymentStatus === PaymentStatus.PAID)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const dayLoans = filteredGames
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const discounts = filteredGames
      .reduce((sum, g) => sum + (g.discountMAD || 0), 0);

    return {
      totalGames: filteredGames.length,
      incomePaid,
      dayLoans,
      discounts,
      runningCount: filteredGames.filter(g => g.status === GameStatus.RUNNING).length
    };
  }, [filteredGames]);

  const globalOutstandingLoans = useMemo(() => {
      return games
        .filter(g => g.paymentStatus === PaymentStatus.LOAN)
        .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);
  }, [games]);

  const allLoansList = useMemo(() => {
    return games
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [games]);

  /**
   * Identifies exactly ONE debtor for a loan.
   * Logic: If a winner exists, the other player owes. 
   * Otherwise, Player 1 is responsible.
   */
  const getDebtorName = (loan: Game) => {
    if (!loan.player2) return loan.player1;
    if (loan.winner === loan.player1) return loan.player2; // Winner is P1, so P2 owes
    if (loan.winner === loan.player2) return loan.player1; // Winner is P2, so P1 owes
    return loan.player1; // Default fallback to opener of table
  };

  const analyticsData = useMemo(() => {
    const playerStats: { [key: string]: { paid: number; loan: number; wins: number } } = {};

    const addPlayerStat = (player: string | null, key: 'paid' | 'loan', value: number) => {
        if (!player || value <= 0) return;
        if (!playerStats[player]) {
            playerStats[player] = { paid: 0, loan: 0, wins: 0 };
        }
        playerStats[player][key] += value;
    };

    games.forEach(game => {
        if (game.status !== GameStatus.FINISHED || !game.finalPriceMAD) return;
        const { player1, player2, winner, finalPriceMAD, paymentStatus } = game;
        if (paymentStatus === PaymentStatus.PAID) {
            const amount = player2 ? finalPriceMAD / 2 : finalPriceMAD;
            addPlayerStat(player1, 'paid', amount);
            addPlayerStat(player2, 'paid', amount);
        } else if (paymentStatus === PaymentStatus.LOAN) {
            const loanee = getDebtorName(game);
            addPlayerStat(loanee, 'loan', finalPriceMAD);
        }
        if (winner) {
            if (!playerStats[winner]) playerStats[winner] = { paid: 0, loan: 0, wins: 0 };
            playerStats[winner].wins += 1;
        }
    });

    const allPlayers = Object.entries(playerStats).map(([name, stats]) => ({ name, ...stats }));
    const topWinners = [...allPlayers].sort((a, b) => b.wins - a.wins).filter(p => p.wins > 0).slice(0, 5);
    const topPaid = [...allPlayers].sort((a, b) => b.paid - a.paid).filter(p => p.paid > 0).slice(0, 5);
    const playersWithLoans = [...allPlayers].sort((a, b) => b.loan - a.loan).filter(p => p.loan > 0);
    return { topWinners, topPaid, playersWithLoans };
  }, [games]);

  const performArchive = async () => {
    if (isArchiving) return;

    setIsArchiving(true);
    setArchiveError(null);
    const reportDate = businessDate;
    const reportGames = [...filteredGames];

    try {
      const summary: DailySummary = {
        date: businessDate,
        totalPaid: selectedDayStats.incomePaid,
        totalLoan: selectedDayStats.dayLoans,
        totalDiscount: selectedDayStats.discounts,
        gameCount: selectedDayStats.totalGames,
      };

      await saveDailySummary(summary);
      await advanceDay(); 

      setIsConfirmingArchive(false);
      setClosureDate(reportDate);
      setClosureGames(reportGames);
      setShowClosureReport(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (e: any) {
      console.error("Critical Archive Failure:", e);
      setArchiveError(`DATABASE ERROR: Column "${e.message?.split("'")[1] || 'unknown'}" is missing. Please open Settings (gear icon) and run the repair SQL.`);
    } finally {
      setIsArchiving(false);
    }
  };

  const handleArchiveClick = () => {
    if (selectedDayStats.runningCount > 0) {
        alert(`CANNOT END SESSION: You have ${selectedDayStats.runningCount} table(s) active. Please finish all games first.`);
        return;
    }
    setIsConfirmingArchive(true);
    setArchiveError(null);
  };

  const settleLoan = async (gameId: string) => {
    if (!window.confirm("Mark this debt as settled?")) return;
    try {
        await updateGame(gameId, { paymentStatus: PaymentStatus.PAID });
    } catch (e) {
        console.error("Failed to settle loan", e);
    }
  };

  if (!user) return null;

  if (showClosureReport) {
      return (
        <DailyClosureReport 
            date={closureDate} 
            games={closureGames} 
            onBack={() => setShowClosureReport(false)} 
        />
      );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pt-6">
      <div className="flex flex-col gap-6 border-b pb-8 px-1">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div className="space-y-1">
            <h1 className="text-4xl font-black tracking-tighter uppercase leading-none">Admin Control</h1>
            <p className="text-muted-foreground font-medium text-xs uppercase tracking-widest opacity-70">Club Management & Analytics</p>
          </div>
          <div className="flex items-center gap-2">
             {isLiveDay ? (
                <Badge className="bg-green-600 hover:bg-green-600 animate-pulse border-none px-3 py-1 text-[10px] font-black">LIVE SESSION</Badge>
            ) : (
                <Badge variant="outline" className="text-muted-foreground border-muted-foreground px-3 py-1 text-[10px] font-black">HISTORY MODE</Badge>
            )}
          </div>
        </div>

        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 pt-2">
           <div className="flex items-center gap-2 text-sm">
             <span className="text-muted-foreground">Current Records for:</span>
             <span className="font-bold border-b-2 border-primary/20 pb-0.5">{new Date(selectedDate + 'T00:00:00').toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}</span>
