        <KpiCard title="Games Played" value={selectedDayStats.totalGames.toString()} icon={<HashIcon />} />
        <KpiCard title="Cash Income" value={`${selectedDayStats.incomePaid.toFixed(2)}`} icon={<DollarSignIcon />} />
        <KpiCard title="Total Loans" value={`${selectedDayStats.dayLoans.toFixed(2)}`} icon={<ClockIcon />} />
        <KpiCard title="Global Debt" value={`${globalOutstandingLoans.toFixed(2)}`} icon={<AlertTriangle className="text-amber-500" />} />
      </div>

      <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          <Card className="lg:col-span-1 shadow-sm border-dashed">
              <CardHeader className="bg-muted/10 pb-4">
                  <CardTitle className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Financial Recap</CardTitle>
              </CardHeader>
              <CardContent className="grid gap-4 pt-6">
                  <div className="flex items-center justify-between p-3 border-2 border-green-500/10 rounded-xl bg-green-50/30 dark:bg-green-950/10">
                      <span className="text-[10px] font-black uppercase text-green-600/70">Cash Received:</span>
                      <span className="font-black text-green-600">{formatCurrency(selectedDayStats.incomePaid)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border-2 border-amber-500/10 rounded-xl bg-amber-50/30 dark:bg-amber-950/10">
                      <span className="text-[10px] font-black uppercase text-amber-600/70">Loans Issued:</span>
                      <span className="font-black text-amber-600">{formatCurrency(selectedDayStats.dayLoans)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border border-dashed rounded-xl">
                      <span className="text-[10px] font-black uppercase text-muted-foreground">Discounts:</span>
                      <span className="font-bold text-muted-foreground">{formatCurrency(selectedDayStats.discounts)}</span>
                  </div>
                  <div className="pt-4 border-t-2 border-zinc-900 dark:border-white mt-2">
                      <div className="flex justify-between items-center px-1">
                          <span className="font-black text-xs uppercase tracking-widest">Gross Total:</span>
                          <span className="text-xl font-black">{formatCurrency(selectedDayStats.incomePaid + selectedDayStats.dayLoans)}</span>
                      </div>
                  </div>
              </CardContent>
          </Card>

          <Card className="lg:col-span-2 border-amber-200 dark:border-amber-900/50 shadow-md">
              <CardHeader className="flex flex-row items-center justify-between bg-amber-50/50 dark:bg-amber-950/10 pb-4">
                  <div>
                    <CardTitle className="flex items-center gap-2 text-amber-700 dark:text-amber-400 text-xs font-black uppercase tracking-widest">
                        <ClockIcon className="h-4 w-4" />
                        Live Debt Tracker
                    </CardTitle>
                  </div>
                  <Badge className="bg-amber-500 font-bold text-[10px]">{allLoansList.length} Active Loans</Badge>
              </CardHeader>
              <CardContent className="h-[280px] overflow-y-auto pt-4">
                  {allLoansList.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {allLoansList.map((loan) => (
                            <div key={loan.id} className="flex items-center justify-between p-3 rounded-xl bg-muted/30 border border-transparent hover:border-amber-500/30 transition-all">
                                <div className="grid gap-0.5">
                                    <span className="font-black text-xs text-foreground uppercase tracking-tight">
                                        {getDebtorName(loan)}
                                    </span>
                                    <div className="flex items-center gap-2 text-[10px] text-muted-foreground">
                                        <span className="font-bold text-amber-600/80">{loan.tableName}</span>
                                        <span>•</span>
                                        <span>{new Date(loan.date + 'T00:00:00').toLocaleDateString('en-GB')}</span>
                                    </div>
                                </div>
                                <div className="flex items-center gap-3">
                                    <span className="font-bold text-sm text-amber-600">{formatCurrency(loan.finalPriceMAD)}</span>
                                    <Button size="icon" variant="ghost" className="h-7 w-7 text-green-600 hover:bg-green-500/10 rounded-full" onClick={() => settleLoan(loan.id)}>
                                        <CheckCircle className="h-4 w-4" />
                                    </Button>
                                </div>
                            </div>
                        ))}
                    </div>
                  ) : (
                    <div className="flex flex-col items-center justify-center h-full text-muted-foreground gap-2 opacity-50">
                        <CheckCircle className="h-12 w-12" />
                        <p className="text-[10px] font-black uppercase tracking-widest">No outstanding debt</p>
                    </div>
                  )}
              </CardContent>
          </Card>
      </div>

      <div className="space-y-4">
        <h2 className="text-xl font-black uppercase tracking-tighter border-b pb-4">Performance Insights</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            <AnalyticsCard title="Top Winners" icon={<TrophyIcon className="text-yellow-500" />}>
                {analyticsData.topWinners.length > 0 ? (
                    analyticsData.topWinners.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-xs py-2 border-b border-dashed last:border-b-0">
                            <span className="font-bold uppercase">{player.name}</span>
                            <span className="bg-primary/10 px-2 py-0.5 rounded text-[10px] font-black">{player.wins} WINS</span>
                        </div>
                    ))
                ) : (
                    <p className="text-[10px] text-muted-foreground italic py-4">No data yet.</p>
                )}
            </AnalyticsCard>

            <AnalyticsCard title="Top Revenue" icon={<DollarSignIcon className="text-green-500" />}>
                    {analyticsData.topPaid.length > 0 ? (
                    analyticsData.topPaid.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-xs py-2 border-b border-dashed last:border-b-0">
                            <span className="font-bold uppercase">{player.name}</span>
                            <span className="font-black text-green-600">{formatCurrency(player.paid)}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-[10px] text-muted-foreground italic py-4">No data yet.</p>
                )}
            </AnalyticsCard>

            <AnalyticsCard title="Largest Debtors" icon={<UsersIcon className="text-red-500" />}>
                {analyticsData.playersWithLoans.length > 0 ? (
                    analyticsData.playersWithLoans.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-xs py-2 border-b border-dashed last:border-b-0">
                            <span className="font-bold uppercase">{player.name}</span>
                            <span className="font-black text-destructive">{formatCurrency(player.loan)}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-[10px] text-muted-foreground italic py-4">Records are clear.</p>
                )}
            </AnalyticsCard>
        </div>
      </div>

      <div className="space-y-4">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4 border-b pb-4">
            <h2 className="text-xl font-black uppercase tracking-tighter">Session Activity Log</h2>
            <div className="flex flex-wrap items-center gap-2">
                <PrintResumeButton games={filteredGames} selectedDate={selectedDate} />

                {isLiveDay && (
                    <div className="flex flex-col sm:flex-row items-center gap-2">
                        {isConfirmingArchive ? (
                            <div className="flex flex-col items-center gap-4 p-5 bg-primary text-primary-foreground rounded-2xl shadow-2xl animate-in fade-in zoom-in border-4 border-white dark:border-zinc-800">
                                <div className="text-center space-y-1">
                                    <p className="text-[10px] font-black uppercase tracking-[0.2em] mb-2 opacity-80">Final Confirmation</p>
                                    <p className="text-xs font-black uppercase leading-tight">All data will be saved and you will start a new game. Continue?</p>
                                </div>
                                <div className="flex gap-2 w-full mt-2">
                                    <Button 
                                        size="sm" 
                                        variant="secondary"
                                        className="flex-1 h-12 font-black uppercase tracking-wider text-[11px] shadow-sm active:scale-95" 
                                        onClick={performArchive}
                                        disabled={isArchiving}
                                    >
                                        {isArchiving ? <LoaderCircle className="h-3 w-3 animate-spin mr-1"/> : "Yes, End Day"}
                                    </Button>
                                    <Button 
                                        size="sm" 
                                        variant="outline" 
                                        className="flex-1 h-12 font-black uppercase tracking-wider text-[11px] bg-transparent border-white/20 text-white hover:bg-white/10"
                                        onClick={() => setIsConfirmingArchive(false)}
                                        disabled={isArchiving}
                                    >
                                        Cancel
                                    </Button>
                                </div>
                            </div>
                        ) : (
                            <Button 
                                type="button"
                                onClick={handleArchiveClick} 
                                className="bg-primary hover:bg-primary/90 font-black uppercase tracking-widest px-8 shadow-2xl transition-all active:scale-95 border-none h-12"
                            >
                                End Session & Archive
                            </Button>
                        )}
                    </div>
                )}
            </div>
        </div>
        <GamesTable 
            games={filteredGames} 
            isAdmin={true} 
            updateGame={updateGame} 
            deleteGame={deleteGame}
            currentUserId={user.id}
        />
      </div>

      <div className="pt-12 border-t">
        <h2 className="text-xl font-black uppercase tracking-tighter mb-6">User Management</h2>
        <UserManagement />
      </div>
    </div>
  );
};

export default AdminPage;

import React, { useState, useEffect } from 'react';
import { Game, GameStatus, PaymentStatus } from '../types';
import { formatCurrency, formatDuration, calculateLivePrice, calculateFinalPrice, getMinPrice } from '../lib/utils';
import { Badge } from './ui/Badge';
import { Button } from './ui/Button';
import { MoreVerticalIcon, ClockIcon, DollarSignIcon, AlertTriangle, CheckCircle, TrophyIcon } from './icons';
import { Input } from './ui/Input';
import { Select } from './ui/Select';
import { TABLES, DEFAULT_HOURLY_RATE } from '../constants';

interface GameRowProps {
  game: Game;
  isAdmin: boolean;
  updateGame?: (gameId: string, updates: Partial<Game>) => void;
  deleteGame?: (gameId:string) => void;
  currentUserId?: string;
}

const GameRow: React.FC<GameRowProps> = ({ game, isAdmin, updateGame, deleteGame, currentUserId }) => {
    const gameRate = game.hourlyRate || DEFAULT_HOURLY_RATE;

    const calculateCurrentDuration = () => {
        if (game.status === GameStatus.RUNNING) {
            const start = new Date(game.startTime).getTime();
            const now = Date.now();
            return Math.max(0, Math.floor((now - start) / 1000));
        }
        return 0;
    };

    const [liveDuration, setLiveDuration] = useState<number>(calculateCurrentDuration);

    const [livePrice, setLivePrice] = useState<number>(() => {
         if (game.status === GameStatus.RUNNING) {
             return calculateLivePrice(game.startTime, gameRate, game.tableName);
         }
         return 0;
    });

    const [isEditing, setIsEditing] = useState(false);

    const [editableGame, setEditableGame] = useState({
      tableName: game.tableName ?? '',
      hourlyRate: gameRate,
      player1: game.player1,
      player2: game.player2 ?? '',
      winner: game.winner ?? null,
      discountMAD: game.discountMAD ?? 0,
      status: game.status,
      paymentStatus: game.paymentStatus === PaymentStatus.PENDING ? PaymentStatus.PAID : game.paymentStatus,
      finalPriceMAD: game.finalPriceMAD ?? 0,
    });

    useEffect(() => {
        if (game.status === GameStatus.RUNNING && !isEditing) {
            const updateStats = () => {
                setLiveDuration(calculateCurrentDuration());
                setLivePrice(calculateLivePrice(game.startTime, gameRate, game.tableName));
            };

            updateStats();
            const interval = setInterval(updateStats, 1000);
            return () => clearInterval(interval);
        }
    }, [game.status, game.startTime, isEditing, gameRate, game.tableName]);

    const resetEditableGame = () => {
        setEditableGame({
            tableName: game.tableName ?? '',
            hourlyRate: gameRate,
            player1: game.player1,
            player2: game.player2 ?? '',
            winner: game.winner ?? null,
            discountMAD: game.discountMAD ?? 0,
            status: game.status,
            paymentStatus: game.paymentStatus === PaymentStatus.PENDING ? PaymentStatus.PAID : game.paymentStatus,
            finalPriceMAD: game.finalPriceMAD ?? 0,
        });
    };

    const startEditing = () => {
        resetEditableGame();
        setIsEditing(true);
    };

    const handleTableChange = (tableId: string) => {
        const config = TABLES.find(t => t.id === tableId);
        if (config) {
             setEditableGame({
                 ...editableGame,
                 tableName: config.name,
                 hourlyRate: config.rate
             });
        }
    };

    const handleStatusChange = (newStatus: GameStatus) => {
        let newFinalPrice = editableGame.finalPriceMAD;
        if (game.status === GameStatus.RUNNING && newStatus === GameStatus.FINISHED) {
            const endTime = new Date().toISOString();
            const discount = isAdmin ? Number(editableGame.discountMAD) : game.discountMAD;
            const { finalPrice } = calculateFinalPrice(game.startTime, endTime, discount, editableGame.hourlyRate, editableGame.tableName);
            newFinalPrice = Number(finalPrice.toFixed(2));
        }

        setEditableGame({
            ...editableGame,
            status: newStatus,
            finalPriceMAD: newFinalPrice,
        });
    }

    const handleSaveChanges = () => {
      if (!updateGame || !currentUserId) return;

      const updates: Partial<Game> = {
          tableName: editableGame.tableName,
          hourlyRate: editableGame.hourlyRate,
          player1: editableGame.player1,
          player2: editableGame.player2 || null,
          winner: editableGame.winner,
          paymentStatus: editableGame.paymentStatus,
          modifiedBy: currentUserId,
      };

      if (game.status === GameStatus.RUNNING && editableGame.status === GameStatus.FINISHED) {
          const endTime = new Date().toISOString();
          const discount = isAdmin ? Number(editableGame.discountMAD) : game.discountMAD;
          const { durationSeconds, price, finalPrice } = calculateFinalPrice(game.startTime, endTime, discount, editableGame.hourlyRate, editableGame.tableName);

          updates.status = GameStatus.FINISHED;
          updates.endTime = endTime;
          updates.durationSeconds = durationSeconds;
          updates.priceMAD = price;
          updates.finalPriceMAD = Math.max(getMinPrice(editableGame.tableName), Number(editableGame.finalPriceMAD));
          updates.discountMAD = discount;
      } else if (game.status === GameStatus.FINISHED) {
        updates.finalPriceMAD = Number(editableGame.finalPriceMAD);
        if (isAdmin) {
          updates.discountMAD = Number(editableGame.discountMAD);
        }
      }

      updateGame(game.id, updates);
      setIsEditing(false);
    };

    const handleCancelEdit = () => {
      setIsEditing(false);
      resetEditableGame();
    };

    const priceToDisplay = game.status === GameStatus.RUNNING ? livePrice : (game.finalPriceMAD ?? 0);
    const durationToDisplay = game.status === GameStatus.RUNNING ? liveDuration : (game.durationSeconds ?? 0);

    const getDebtorName = () => {
        if (game.paymentStatus !== PaymentStatus.LOAN) return null;
        if (!game.player2) return game.player1;
        // Logic: The non-winner (loser) owes the money
        if (game.winner === game.player1) return game.player2;
        if (game.winner === game.player2) return game.player1;
        return game.player1; // Default to table opener if no winner selected
    };

    const statusColors = {
        [PaymentStatus.PAID]: 'border-green-500 bg-green-500/[0.03]',
        [PaymentStatus.PENDING]: 'border-blue-500 bg-blue-500/[0.03]',
        [PaymentStatus.LOAN]: 'border-amber-500 bg-amber-500/[0.03]',
    };

    const paymentStatusBadge = {
        [PaymentStatus.PAID]: 'bg-green-600 text-white',
        [PaymentStatus.PENDING]: 'bg-blue-600 text-white',
        [PaymentStatus.LOAN]: 'bg-amber-500 text-white',
    };

    const showActions = isAdmin || (game.createdBy === currentUserId && !isAdmin);
    const currentTableConfig = TABLES.find(t => t.name === editableGame.tableName);
    const currentTableId = currentTableConfig ? currentTableConfig.id : '';

    if (isEditing) {
        return (
            <tr className="border-b">
                <td colSpan={8} className="p-0 bg-background">
                    <div className="p-6 md:p-8 space-y-8 animate-in slide-in-from-bottom-4">
                        <div className="flex justify-between items-center border-b pb-4">
                            <h4 className="text-xl font-black uppercase tracking-tighter">Edit Game Details</h4>
                            <Badge variant="outline" className="text-[10px] font-black">{game.tableName}</Badge>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            {/* Players & Table Column */}
                            <div className="space-y-6">
                                <div className="space-y-1.5">
                                    <label className="text-[10px] font-black uppercase opacity-60 ml-1">Assigned Table</label>
                                    <Select value={currentTableId} onChange={(e) => handleTableChange(e.target.value)} className="w-full h-12 text-base font-bold">
                                        {TABLES.map(t => (
                                            <option key={t.id} value={t.id}>{t.name}</option>
                                        ))}
                                    </Select>
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-1.5">
                                        <label className="text-[10px] font-black uppercase opacity-60 ml-1">Player 1</label>
                                        <Input type="text" value={editableGame.player1} onChange={(e) => setEditableGame({...editableGame, player1: e.target.value})} className="h-12 font-bold" />
                                    </div>
                                    <div className="space-y-1.5">
                                        <label className="text-[10px] font-black uppercase opacity-60 ml-1">Player 2</label>
                                        <Input type="text" value={editableGame.player2} onChange={(e) => setEditableGame({...editableGame, player2: e.target.value})} className="h-12 font-bold" />
                                    </div>
                                </div>

                                {editableGame.player2 && (
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black uppercase opacity-60 ml-1">Who Won? (Winner pays nothing, Loser owes)</label>
                                        <div className="grid grid-cols-2 gap-2 p-1 bg-muted rounded-2xl">
                                            <button 
                                                onClick={() => setEditableGame({...editableGame, winner: editableGame.player1})}
                                                className={`py-3 px-4 rounded-xl text-xs font-black uppercase flex items-center justify-center gap-2 transition-all ${editableGame.winner === editableGame.player1 ? 'bg-background shadow-lg text-green-600 scale-[1.02]' : 'text-muted-foreground opacity-50'}`}
                                            >
                                                {editableGame.winner === editableGame.player1 && <TrophyIcon className="h-3 w-3" />}
                                                {editableGame.player1 || 'P1'}
                                            </button>
                                            <button 
                                                onClick={() => setEditableGame({...editableGame, winner: editableGame.player2})}
                                                className={`py-3 px-4 rounded-xl text-xs font-black uppercase flex items-center justify-center gap-2 transition-all ${editableGame.winner === editableGame.player2 ? 'bg-background shadow-lg text-green-600 scale-[1.02]' : 'text-muted-foreground opacity-50'}`}
                                            >
                                                {editableGame.winner === editableGame.player2 && <TrophyIcon className="h-3 w-3" />}
                                                {editableGame.player2 || 'P2'}
                                            </button>
                                        </div>
                                        {editableGame.winner && (
                                            <p className="text-[10px] font-black text-amber-600 uppercase text-center">
                                                Loan will be assigned to {editableGame.winner === editableGame.player1 ? editableGame.player2 : editableGame.player1}
                                            </p>
                                        )}
                                    </div>
                                )}
                            </div>

                            {/* Status & Payment Column */}
                            <div className="space-y-6">
                                <div className="space-y-1.5">
                                    <label className="text-[10px] font-black uppercase opacity-60 ml-1">Session Status</label>
                                     <div className="flex p-1 bg-muted rounded-xl gap-1">
                                        <button 
                                            onClick={() => handleStatusChange(GameStatus.RUNNING)}
                                            disabled={game.status === GameStatus.FINISHED}
                                            className={`flex-1 py-3 rounded-lg text-xs font-black uppercase transition-all ${editableGame.status === GameStatus.RUNNING ? 'bg-background shadow text-primary' : 'text-muted-foreground'}`}
                                        >
                                            Running
                                        </button>
                                        <button 
                                            onClick={() => handleStatusChange(GameStatus.FINISHED)}
                                            className={`flex-1 py-3 rounded-lg text-xs font-black uppercase transition-all ${editableGame.status === GameStatus.FINISHED ? 'bg-background shadow text-primary' : 'text-muted-foreground'}`}
                                        >
                                            Finished
                                        </button>
                                     </div>
                                </div>

                                {editableGame.status === GameStatus.FINISHED && (
                                    <>
                                    <div className="space-y-1.5">
                                        <label className="text-[10px] font-black uppercase opacity-60 ml-1">Charge Amount (MAD)</label>
                                        <Input 
                                            type="number" 
                                            value={editableGame.finalPriceMAD} 
                                            onChange={(e) => setEditableGame({ ...editableGame, finalPriceMAD: Number(e.target.value) })} 
                                            className="h-14 text-2xl font-black text-primary border-2" 
                                        />
                                    </div>
                                    <div className="space-y-1.5">
                                        <label className="text-[10px] font-black uppercase opacity-60 ml-1">Payment Method</label>
                                        <div className="grid grid-cols-2 gap-3">
                                            <button 
                                                onClick={() => setEditableGame({ ...editableGame, paymentStatus: PaymentStatus.PAID })}
                                                className={`flex flex-col items-center gap-2 p-4 rounded-2xl border-2 transition-all ${editableGame.paymentStatus === PaymentStatus.PAID ? 'bg-green-600 border-green-600 text-white shadow-xl' : 'bg-muted/50 border-transparent text-muted-foreground'}`}
                                            >
                                                <CheckCircle className="h-6 w-6" />
                                                <span className="text-xs font-black uppercase">Paid Cash</span>
                                            </button>
                                            <button 
                                                onClick={() => setEditableGame({ ...editableGame, paymentStatus: PaymentStatus.LOAN })}
                                                className={`flex flex-col items-center gap-2 p-4 rounded-2xl border-2 transition-all ${editableGame.paymentStatus === PaymentStatus.LOAN ? 'bg-amber-500 border-amber-500 text-white shadow-xl' : 'bg-muted/50 border-transparent text-muted-foreground'}`}
                                            >
                                                <AlertTriangle className="h-6 w-6" />
                                                <span className="text-xs font-black uppercase">Mark as Loan</span>
                                            </button>
                                        </div>
                                    </div>
                                    </>
                                )}
                            </div>
                        </div>

                        <div className="flex gap-3 pt-6 border-t">
                            <Button className="flex-1 h-14 text-base font-black uppercase tracking-widest shadow-xl" onClick={handleSaveChanges}>Apply Changes</Button>
                            <Button variant="outline" className="h-14 px-8 font-black uppercase text-xs tracking-widest" onClick={handleCancelEdit}>Discard</Button>
                        </div>
                    </div>
                </td>
            </tr>
        );
    }

    return (
        <>
        {/* Desktop View Row */}
        <tr className="border-b transition-colors hover:bg-muted/50 hidden md:table-row">
            <td className="p-4 align-middle font-bold text-muted-foreground/60">{game.tableName}</td>
            <td className="p-4 align-middle">
                <div className="font-black text-base uppercase">{game.player1}{game.player2 ? ` vs ${game.player2}` : ''}</div>
                {game.winner && <div className="text-[10px] font-black text-green-600 uppercase">Winner: {game.winner}</div>}
            </td>
            <td className="p-4 align-middle text-[10px] font-bold uppercase text-muted-foreground">
                {new Date(game.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                {game.endTime && ` — ${new Date(game.endTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}`}
            </td>
            <td className="p-4 align-middle font-mono font-bold">{formatDuration(durationToDisplay)}</td>
            <td className="p-4 align-middle">
                <div className={`font-black text-lg ${game.paymentStatus === PaymentStatus.LOAN ? 'text-amber-600' : 'text-foreground'}`}>
                    {formatCurrency(priceToDisplay)}
                </div>
            </td>
            <td className="p-4 align-middle">
                <Badge variant={game.status === GameStatus.RUNNING ? "default" : "secondary"} className="uppercase font-black text-[9px]">{game.status}</Badge>
            </td>
            <td className="p-4 align-middle">
                <div className="flex items-center gap-2">
                    <Badge className={`${paymentStatusBadge[game.paymentStatus]} uppercase font-black text-[9px] border-none px-3`}>
                        {game.paymentStatus === PaymentStatus.PENDING ? 'Active' : game.paymentStatus}
                    </Badge>
                    {game.paymentStatus === PaymentStatus.LOAN && <AlertTriangle className="h-4 w-4 text-amber-500" />}
                </div>
            </td>
            {showActions && (
                <td className="p-4 align-middle text-right">
                    <Button variant="ghost" size="icon" onClick={startEditing} className="rounded-full hover:bg-primary/10">
                        <MoreVerticalIcon className="h-4 w-4" />
                    </Button>
                </td>
            )}
        </tr>

        {/* 3D Professional Mobile Card with Explicit Loan Tracking */}
        <tr className="md:hidden border-none bg-transparent">
            <td colSpan={8} className="p-3 border-none bg-transparent">
                <div className={`relative overflow-hidden rounded-3xl border-l-[6px] shadow-xl transition-all ${statusColors[game.paymentStatus]} bg-card dark:bg-zinc-900 border-t border-r border-b border-border`}>

                    <div className="absolute -right-4 -top-4 opacity-[0.05] dark:opacity-[0.08] pointer-events-none">
                        {game.paymentStatus === PaymentStatus.PAID && <DollarSignIcon className="h-32 w-32 rotate-12" />}
                        {game.paymentStatus === PaymentStatus.LOAN && <AlertTriangle className="h-32 w-32 -rotate-12" />}
                    </div>

                    <div className="p-6 space-y-5 relative z-10">
                        <div className="flex justify-between items-start">
                            <div className="space-y-1.5">
                                <span className="bg-zinc-900 dark:bg-zinc-100 text-zinc-100 dark:text-zinc-900 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest">
                                    {game.tableName}
                                </span>
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    <ClockIcon className="h-3.5 w-3.5" />
                                    <span className="text-[11px] font-black uppercase">
                                        {new Date(game.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                        {game.endTime && ` • ${new Date(game.endTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}`}
                                    </span>
                                </div>
                            </div>
                            {showActions && (
                                <Button 
                                    size="sm" 
                                    onClick={startEditing}
                                    className="h-10 rounded-2xl text-[10px] font-black uppercase px-5 bg-primary/5 hover:bg-primary/10 text-primary border border-primary/10 shadow-sm"
                                >
                                    Edit
                                </Button>
                            )}
                        </div>

                        <div className="space-y-1">
                            <h3 className="text-xl font-black tracking-tighter leading-none uppercase truncate text-zinc-900 dark:text-zinc-50">
                                {game.player1}
                                {game.player2 && <span className="text-muted-foreground/30 mx-2 text-sm">vs</span>}
                                {game.player2}
                            </h3>

                            {/* EXPLICIT LOAN TRACKER */}
                            {game.paymentStatus === PaymentStatus.LOAN && (
                                <div className="inline-flex items-center gap-2 px-3 py-1 rounded-xl bg-amber-500 text-white shadow-sm border border-amber-600/20">
                                    <AlertTriangle className="h-3.5 w-3.5" />
                                    <span className="text-[10px] font-black uppercase tracking-widest italic">
                                        Owed By: {getDebtorName()}
                                    </span>
                                </div>
                            )}

                            {game.paymentStatus === PaymentStatus.PAID && game.winner && (
                                <div className="flex items-center gap-1.5 text-green-600">
                                    <TrophyIcon className="h-3 w-3" />
                                    <span className="text-[9px] font-black uppercase tracking-widest">Winner: {game.winner}</span>
                                </div>
                            )}
                        </div>

                        <div className="grid grid-cols-2 gap-4 py-4 border-y border-dashed border-border/50">
                            <div className="space-y-0.5">
                                <p className="text-[9px] font-black uppercase tracking-widest text-muted-foreground">Duration</p>
                                <div className={`font-mono text-base font-black ${game.status === GameStatus.RUNNING ? 'text-blue-600' : 'text-zinc-500'}`}>
                                    {formatDuration(durationToDisplay)}
                                </div>
                            </div>
                            <div className="text-right space-y-0.5">
                                <p className="text-[9px] font-black uppercase tracking-widest text-muted-foreground">Total Bill</p>
                                <div className={`text-2xl font-black ${game.paymentStatus === PaymentStatus.LOAN ? 'text-amber-600' : 'text-zinc-900 dark:text-zinc-100'}`}>
                                    {formatCurrency(priceToDisplay)}
                                </div>
                            </div>
                        </div>

                        <div className="flex items-center justify-between">
                            <Badge className={`${paymentStatusBadge[game.paymentStatus]} border-none uppercase font-black text-[10px] tracking-widest px-4 py-1.5 rounded-xl shadow-sm`}>
                                {game.paymentStatus === PaymentStatus.PENDING ? 'Session Active' : game.paymentStatus}
                            </Badge>
                            {game.status === GameStatus.RUNNING && (
                                <div className="flex items-center gap-2 bg-blue-500/10 text-blue-600 px-3 py-1.5 rounded-xl border border-blue-500/20">
                                    <div className="h-2 w-2 rounded-full bg-blue-600 animate-pulse"></div>
                                    <span className="text-[9px] font-black uppercase">Playing</span>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </td>
        </tr>
        </>
    );
};

export default GameRow;

export * from './ClockIcon';
export * from './DollarSignIcon';
export * from './HashIcon';
export * from './MoreVerticalIcon';
export * from './SunIcon';
export * from './MoonIcon';
export * from './SettingsIcon';
export * from './CloseIcon';
export * from './CopyIcon';
export * from './CheckCircle';
export * from './AlertTriangle';
export * from './LoaderCircle';
export * from './TrophyIcon';
export * from './UsersIcon';
export * from './ExternalLinkIcon';
export * from './DatabaseIcon';
export * from './PrinterIcon';
export * from './ArrowLeftIcon';
export * from './LockIcon';

import React, { useState, useEffect } from 'react';
import { Game, GameStatus, PaymentStatus } from '../types';
import { formatCurrency, formatDuration, calculateLivePrice, calculateFinalPrice, getMinPrice } from '../lib/utils';
import { Badge } from './ui/Badge';
import { Button } from './ui/Button';
import { MoreVerticalIcon, ClockIcon, DollarSignIcon, AlertTriangle, CheckCircle, TrophyIcon, LockIcon } from './icons';
import { Input } from './ui/Input';
import { Select } from './ui/Select';
import { TABLES, DEFAULT_HOURLY_RATE } from '../constants';

interface GameRowProps {
  game: Game;
  isAdmin: boolean;
  updateGame?: (gameId: string, updates: Partial<Game>) => void;
  deleteGame?: (gameId:string) => void;
  currentUserId?: string;
}

const GameRow: React.FC<GameRowProps> = ({ game, isAdmin, updateGame, deleteGame, currentUserId }) => {
    const gameRate = game.hourlyRate || DEFAULT_HOURLY_RATE;

    const calculateCurrentDuration = () => {
        if (game.status === GameStatus.RUNNING) {
            const start = new Date(game.startTime).getTime();
            const now = Date.now();
            return Math.max(0, Math.floor((now - start) / 1000));
        }
        return 0;
    };

    const [liveDuration, setLiveDuration] = useState<number>(calculateCurrentDuration);

    const [livePrice, setLivePrice] = useState<number>(() => {
         if (game.status === GameStatus.RUNNING) {
             return calculateLivePrice(game.startTime, gameRate, game.tableName);
         }
         return 0;
    });

    const [isEditing, setIsEditing] = useState(false);

    const [editableGame, setEditableGame] = useState({
      tableName: game.tableName ?? '',
      hourlyRate: gameRate,
      player1: game.player1,
      player2: game.player2 ?? '',
      winner: game.winner ?? null,
      discountMAD: game.discountMAD ?? 0,
      status: game.status,
      paymentStatus: game.paymentStatus === PaymentStatus.PENDING ? PaymentStatus.PAID : game.paymentStatus,
      finalPriceMAD: game.finalPriceMAD ?? 0,
    });

    useEffect(() => {
        if (game.status === GameStatus.RUNNING && !isEditing) {
            const updateStats = () => {
                setLiveDuration(calculateCurrentDuration());
                setLivePrice(calculateLivePrice(game.startTime, gameRate, game.tableName));
            };

            updateStats();
            const interval = setInterval(updateStats, 1000);
            return () => clearInterval(interval);
        }
    }, [game.status, game.startTime, isEditing, gameRate, game.tableName]);

    const resetEditableGame = () => {
        setEditableGame({
            tableName: game.tableName ?? '',
            hourlyRate: gameRate,
            player1: game.player1,
            player2: game.player2 ?? '',
            winner: game.winner ?? null,
            discountMAD: game.discountMAD ?? 0,
            status: game.status,
            paymentStatus: game.paymentStatus === PaymentStatus.PENDING ? PaymentStatus.PAID : game.paymentStatus,
            finalPriceMAD: game.finalPriceMAD ?? 0,
        });
    };

    const startEditing = () => {
        resetEditableGame();
        setIsEditing(true);
    };

    const handleTableChange = (tableId: string) => {
        const config = TABLES.find(t => t.id === tableId);
        if (config) {
             setEditableGame({
                 ...editableGame,
                 tableName: config.name,
                 hourlyRate: config.rate
             });
        }
    };

    const handleStatusChange = (newStatus: GameStatus) => {
        let newFinalPrice = editableGame.finalPriceMAD;
        if (game.status === GameStatus.RUNNING && newStatus === GameStatus.FINISHED) {
            const endTime = new Date().toISOString();
            const discount = isAdmin ? Number(editableGame.discountMAD) : game.discountMAD;
            const { finalPrice } = calculateFinalPrice(game.startTime, endTime, discount, editableGame.hourlyRate, editableGame.tableName);
            newFinalPrice = Number(finalPrice.toFixed(2));
        }

        setEditableGame({
            ...editableGame,
            status: newStatus,
            finalPriceMAD: newFinalPrice,
        });
    }

    const handleSaveChanges = () => {
      if (!updateGame || !currentUserId) return;

      const updates: Partial<Game> = {
          tableName: editableGame.tableName,
          hourlyRate: editableGame.hourlyRate,
          player1: editableGame.player1,
          player2: editableGame.player2 || null,
          winner: editableGame.winner,
          paymentStatus: editableGame.paymentStatus,
          modifiedBy: currentUserId,
      };

      if (game.status === GameStatus.RUNNING && editableGame.status === GameStatus.FINISHED) {
          const endTime = new Date().toISOString();
          const discount = isAdmin ? Number(editableGame.discountMAD) : game.discountMAD;
          const { durationSeconds, price, finalPrice } = calculateFinalPrice(game.startTime, endTime, discount, editableGame.hourlyRate, editableGame.tableName);

          updates.status = GameStatus.FINISHED;
          updates.endTime = endTime;
          updates.durationSeconds = durationSeconds;
          updates.priceMAD = price;
          updates.finalPriceMAD = Math.max(getMinPrice(editableGame.tableName), Number(editableGame.finalPriceMAD));
          updates.discountMAD = discount;
      } else if (game.status === GameStatus.FINISHED) {
        updates.finalPriceMAD = Number(editableGame.finalPriceMAD);
        if (isAdmin) {
          updates.discountMAD = Number(editableGame.discountMAD);
        }
      }

      updateGame(game.id, updates);
      setIsEditing(false);
    };

    const handleCancelEdit = () => {
      setIsEditing(false);
      resetEditableGame();
    };

    const priceToDisplay = game.status === GameStatus.RUNNING ? livePrice : (game.finalPriceMAD ?? 0);
    const durationToDisplay = game.status === GameStatus.RUNNING ? liveDuration : (game.durationSeconds ?? 0);

    const getDebtorName = () => {
        if (game.paymentStatus !== PaymentStatus.LOAN) return null;
        if (!game.player2) return game.player1;
        // Logic: The non-winner (loser) owes the money
        if (game.winner === game.player1) return game.player2;
        if (game.winner === game.player2) return game.player1;
        return game.player1; // Default to table opener if no winner selected
    };

    const statusColors = {
        [PaymentStatus.PAID]: 'border-green-500 bg-green-500/[0.03]',
        [PaymentStatus.PENDING]: 'border-blue-500 bg-blue-500/[0.03]',
        [PaymentStatus.LOAN]: 'border-amber-500 bg-amber-500/[0.03]',
    };

    const paymentStatusBadge = {
        [PaymentStatus.PAID]: 'bg-green-600 text-white',
        [PaymentStatus.PENDING]: 'bg-blue-600 text-white',
        [PaymentStatus.LOAN]: 'bg-amber-500 text-white',
    };

    // LOCK LOGIC: Non-admins cannot edit Paid games.
    const isLocked = !isAdmin && game.paymentStatus === PaymentStatus.PAID;
    const showActions = (isAdmin || (game.createdBy === currentUserId)) && !isLocked;

    const currentTableConfig = TABLES.find(t => t.name === editableGame.tableName);
    const currentTableId = currentTableConfig ? currentTableConfig.id : '';

    if (isEditing) {
        return (
            <tr className="border-b">
                <td colSpan={8} className="p-0 bg-background">
                    <div className="p-6 md:p-8 space-y-8 animate-in slide-in-from-bottom-4">
                        <div className="flex justify-between items-center border-b pb-4">
                            <h4 className="text-xl font-black uppercase tracking-tighter">Edit Game Details</h4>
                            <Badge variant="outline" className="text-[10px] font-black">{game.tableName}</Badge>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            {/* Players & Table Column */}
                            <div className="space-y-6">
                                <div className="space-y-1.5">
                                    <label className="text-[10px] font-black uppercase opacity-60 ml-1">Assigned Table</label>
                                    <Select value={currentTableId} onChange={(e) => handleTableChange(e.target.value)} className="w-full h-12 text-base font-bold">
                                        {TABLES.map(t => (
                                            <option key={t.id} value={t.id}>{t.name}</option>
                                        ))}
                                    </Select>
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-1.5">
                                        <label className="text-[10px] font-black uppercase opacity-60 ml-1">Player 1</label>
                                        <Input type="text" value={editableGame.player1} onChange={(e) => setEditableGame({...editableGame, player1: e.target.value})} className="h-12 font-bold" />
                                    </div>
                                    <div className="space-y-1.5">
                                        <label className="text-[10px] font-black uppercase opacity-60 ml-1">Player 2</label>
                                        <Input type="text" value={editableGame.player2} onChange={(e) => setEditableGame({...editableGame, player2: e.target.value})} className="h-12 font-bold" />
                                    </div>
                                </div>

                                {editableGame.player2 && (
                                    <div className="space-y-3">
                                        <label className="text-[10px] font-black uppercase opacity-60 ml-1">Who Won? (Winner pays nothing, Loser owes)</label>
                                        <div className="grid grid-cols-2 gap-2 p-1 bg-muted rounded-2xl">
                                            <button 
                                                onClick={() => setEditableGame({...editableGame, winner: editableGame.player1})}
                                                className={`py-3 px-4 rounded-xl text-xs font-black uppercase flex items-center justify-center gap-2 transition-all ${editableGame.winner === editableGame.player1 ? 'bg-background shadow-lg text-green-600 scale-[1.02]' : 'text-muted-foreground opacity-50'}`}
                                            >
                                                {editableGame.winner === editableGame.player1 && <TrophyIcon className="h-3 w-3" />}
                                                {editableGame.player1 || 'P1'}
                                            </button>
                                            <button 
                                                onClick={() => setEditableGame({...editableGame, winner: editableGame.player2})}
                                                className={`py-3 px-4 rounded-xl text-xs font-black uppercase flex items-center justify-center gap-2 transition-all ${editableGame.winner === editableGame.player2 ? 'bg-background shadow-lg text-green-600 scale-[1.02]' : 'text-muted-foreground opacity-50'}`}
                                            >
                                                {editableGame.winner === editableGame.player2 && <TrophyIcon className="h-3 w-3" />}
                                                {editableGame.player2 || 'P2'}
                                            </button>
                                        </div>
                                        {editableGame.winner && (
                                            <p className="text-[10px] font-black text-amber-600 uppercase text-center">
                                                Loan will be assigned to {editableGame.winner === editableGame.player1 ? editableGame.player2 : editableGame.player1}
                                            </p>
                                        )}
                                    </div>
                                )}
                            </div>

                            {/* Status & Payment Column */}
                            <div className="space-y-6">
                                <div className="space-y-1.5">
                                    <label className="text-[10px] font-black uppercase opacity-60 ml-1">Session Status</label>
                                     <div className="flex p-1 bg-muted rounded-xl gap-1">
                                        <button 
                                            onClick={() => handleStatusChange(GameStatus.RUNNING)}
                                            disabled={game.status === GameStatus.FINISHED}
                                            className={`flex-1 py-3 rounded-lg text-xs font-black uppercase transition-all ${editableGame.status === GameStatus.RUNNING ? 'bg-background shadow text-primary' : 'text-muted-foreground'}`}
                                        >
                                            Running
                                        </button>
                                        <button 
                                            onClick={() => handleStatusChange(GameStatus.FINISHED)}
                                            className={`flex-1 py-3 rounded-lg text-xs font-black uppercase transition-all ${editableGame.status === GameStatus.FINISHED ? 'bg-background shadow text-primary' : 'text-muted-foreground'}`}
                                        >
                                            Finished
                                        </button>
                                     </div>
                                </div>

                                {editableGame.status === GameStatus.FINISHED && (
                                    <>
                                    <div className="space-y-1.5">
                                        <label className="text-[10px] font-black uppercase opacity-60 ml-1">Charge Amount (MAD)</label>
                                        <Input 
                                            type="number" 
                                            value={editableGame.finalPriceMAD} 
                                            onChange={(e) => setEditableGame({ ...editableGame, finalPriceMAD: Number(e.target.value) })} 
                                            className="h-14 text-2xl font-black text-primary border-2" 
                                        />
                                    </div>
                                    <div className="space-y-1.5">
                                        <label className="text-[10px] font-black uppercase opacity-60 ml-1">Payment Method</label>
                                        <div className="grid grid-cols-2 gap-3">
                                            <button 
                                                onClick={() => setEditableGame({ ...editableGame, paymentStatus: PaymentStatus.PAID })}
                                                className={`flex flex-col items-center gap-2 p-4 rounded-2xl border-2 transition-all ${editableGame.paymentStatus === PaymentStatus.PAID ? 'bg-green-600 border-green-600 text-white shadow-xl' : 'bg-muted/50 border-transparent text-muted-foreground'}`}
                                            >
                                                <CheckCircle className="h-6 w-6" />
                                                <span className="text-xs font-black uppercase">Paid Cash</span>
                                            </button>
                                            <button 
                                                onClick={() => setEditableGame({ ...editableGame, paymentStatus: PaymentStatus.LOAN })}
                                                className={`flex flex-col items-center gap-2 p-4 rounded-2xl border-2 transition-all ${editableGame.paymentStatus === PaymentStatus.LOAN ? 'bg-amber-500 border-amber-500 text-white shadow-xl' : 'bg-muted/50 border-transparent text-muted-foreground'}`}
                                            >
                                                <AlertTriangle className="h-6 w-6" />
                                                <span className="text-xs font-black uppercase">Mark as Loan</span>
                                            </button>
                                        </div>
                                    </div>
                                    </>
                                )}
                            </div>
                        </div>

                        <div className="flex gap-3 pt-6 border-t">
                            <Button className="flex-1 h-14 text-base font-black uppercase tracking-widest shadow-xl" onClick={handleSaveChanges}>Apply Changes</Button>
                            <Button variant="outline" className="h-14 px-8 font-black uppercase text-xs tracking-widest" onClick={handleCancelEdit}>Discard</Button>
                        </div>
                    </div>
                </td>
            </tr>
        );
    }

    return (
        <>
        {/* Desktop View Row */}
        <tr className="border-b transition-colors hover:bg-muted/50 hidden md:table-row">
            <td className="p-4 align-middle font-bold text-muted-foreground/60">{game.tableName}</td>
            <td className="p-4 align-middle">
                <div className="font-black text-base uppercase">{game.player1}{game.player2 ? ` vs ${game.player2}` : ''}</div>
                {game.winner && <div className="text-[10px] font-black text-green-600 uppercase">Winner: {game.winner}</div>}
            </td>
            <td className="p-4 align-middle text-[10px] font-bold uppercase text-muted-foreground">
                {new Date(game.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                {game.endTime && ` — ${new Date(game.endTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}`}
            </td>
            <td className="p-4 align-middle font-mono font-bold">{formatDuration(durationToDisplay)}</td>
            <td className="p-4 align-middle">
                <div className={`font-black text-lg ${game.paymentStatus === PaymentStatus.LOAN ? 'text-amber-600' : 'text-foreground'}`}>
                    {formatCurrency(priceToDisplay)}
                </div>
            </td>
            <td className="p-4 align-middle">
                <Badge variant={game.status === GameStatus.RUNNING ? "default" : "secondary"} className="uppercase font-black text-[9px]">{game.status}</Badge>
            </td>
            <td className="p-4 align-middle">
                <div className="flex items-center gap-2">
                    <Badge className={`${paymentStatusBadge[game.paymentStatus]} uppercase font-black text-[9px] border-none px-3`}>
                        {game.paymentStatus === PaymentStatus.PENDING ? 'Active' : game.paymentStatus}
                    </Badge>
                    {game.paymentStatus === PaymentStatus.LOAN && <AlertTriangle className="h-4 w-4 text-amber-500" />}
                </div>
            </td>
            <td className="p-4 align-middle text-right">
                {showActions ? (
                    <Button variant="ghost" size="icon" onClick={startEditing} className="rounded-full hover:bg-primary/10">
                        <MoreVerticalIcon className="h-4 w-4" />
                    </Button>
                ) : isLocked && (
                    <div className="flex justify-end pr-2 text-muted-foreground/40" title="Locked: Paid records cannot be modified.">
                        <LockIcon className="h-4 w-4" />
                    </div>
                )}
            </td>
        </tr>

        {/* 3D Professional Mobile Card with Explicit Loan Tracking */}
        <tr className="md:hidden border-none bg-transparent">
            <td colSpan={8} className="p-3 border-none bg-transparent">
                <div className={`relative overflow-hidden rounded-3xl border-l-[6px] shadow-xl transition-all ${statusColors[game.paymentStatus]} bg-card dark:bg-zinc-900 border-t border-r border-b border-border`}>

                    <div className="absolute -right-4 -top-4 opacity-[0.05] dark:opacity-[0.08] pointer-events-none">
                        {game.paymentStatus === PaymentStatus.PAID && <DollarSignIcon className="h-32 w-32 rotate-12" />}
                        {game.paymentStatus === PaymentStatus.LOAN && <AlertTriangle className="h-32 w-32 -rotate-12" />}
                    </div>

                    <div className="p-6 space-y-5 relative z-10">
                        <div className="flex justify-between items-start">
                            <div className="space-y-1.5">
                                <span className="bg-zinc-900 dark:bg-zinc-100 text-zinc-100 dark:text-zinc-900 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest">
                                    {game.tableName}
                                </span>
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    <ClockIcon className="h-3.5 w-3.5" />
