                    {formatCurrency(priceToDisplay)}
                </div>
            </td>
            <td className="p-4 align-middle">
                <Badge variant={game.status === GameStatus.RUNNING ? "default" : "secondary"} className="uppercase font-black text-[9px]">
                    {game.status === GameStatus.RUNNING ? 'En cours' : 'Terminée'}
