  const [closureDate, setClosureDate] = useState('');
  const [closureGames, setClosureGames] = useState<Game[]>([]);

  const [isConfirmingArchive, setIsConfirmingArchive] = useState(false);
  const [archiveError, setArchiveError] = useState<string | null>(null);

  // États pour la réinitialisation du système
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [resetLoading, setResetLoading] = useState(false);
  const [resetPassword, setResetPassword] = useState('');
  const [resetPasswordError, setResetPasswordError] = useState(false);

  const REQUIRED_RESET_PASSWORD = '753159';

  useEffect(() => {
    setSelectedDate(businessDate);
  }, [businessDate]);

  const isLiveDay = selectedDate === businessDate;

  const filteredGames = useMemo(() => {
    return games
      .filter(game => game.date === selectedDate)
      .sort((a, b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime());
  }, [games, selectedDate]);

  const selectedDayStats = useMemo(() => {
    const incomePaid = filteredGames
      .filter(g => g.paymentStatus === PaymentStatus.PAID)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const dayLoans = filteredGames
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);

    const discounts = filteredGames
      .reduce((sum, g) => sum + (g.discountMAD || 0), 0);

    return {
      totalGames: filteredGames.length,
      incomePaid,
      dayLoans,
      discounts,
      runningCount: filteredGames.filter(g => g.status === GameStatus.RUNNING).length
    };
  }, [filteredGames]);

  const globalOutstandingLoans = useMemo(() => {
      return games
        .filter(g => g.paymentStatus === PaymentStatus.LOAN)
        .reduce((sum, g) => sum + (g.finalPriceMAD || 0), 0);
  }, [games]);

  const allLoansList = useMemo(() => {
    return games
      .filter(g => g.paymentStatus === PaymentStatus.LOAN)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [games]);

  const getDebtorName = (loan: Game) => {
    if (!loan.player2) return loan.player1;
    if (loan.winner === loan.player1) return loan.player2;
    if (loan.winner === loan.player2) return loan.player1;
    return loan.player1;
  };

  const analyticsData = useMemo(() => {
    const playerStats: { [key: string]: { paid: number; loan: number; wins: number } } = {};

    const addPlayerStat = (player: string | null, key: 'paid' | 'loan', value: number) => {
        if (!player || value <= 0) return;
        if (!playerStats[player]) {
            playerStats[player] = { paid: 0, loan: 0, wins: 0 };
        }
        playerStats[player][key] += value;
    };

    games.forEach(game => {
        if (game.status !== GameStatus.FINISHED || !game.finalPriceMAD) return;
        const { player1, player2, winner, finalPriceMAD, paymentStatus } = game;
        if (paymentStatus === PaymentStatus.PAID) {
            const amount = player2 ? finalPriceMAD / 2 : finalPriceMAD;
            addPlayerStat(player1, 'paid', amount);
            addPlayerStat(player2, 'paid', amount);
        } else if (paymentStatus === PaymentStatus.LOAN) {
            const loanee = getDebtorName(game);
            addPlayerStat(loanee, 'loan', finalPriceMAD);
        }
        if (winner) {
            if (!playerStats[winner]) playerStats[winner] = { paid: 0, loan: 0, wins: 0 };
            playerStats[winner].wins += 1;
        }
    });

    const allPlayers = Object.entries(playerStats).map(([name, stats]) => ({ name, ...stats }));
    const topWinners = [...allPlayers].sort((a, b) => b.wins - a.wins).filter(p => p.wins > 0).slice(0, 5);
    const topPaid = [...allPlayers].sort((a, b) => b.paid - a.paid).filter(p => p.paid > 0).slice(0, 5);
    const playersWithLoans = [...allPlayers].sort((a, b) => b.loan - a.loan).filter(p => p.loan > 0);
    return { topWinners, topPaid, playersWithLoans };
  }, [games]);

  const performArchive = async () => {
    if (isArchiving) return;

    setIsArchiving(true);
    setArchiveError(null);
    const reportDate = businessDate;
    const reportGames = [...filteredGames];

    try {
      const summary: DailySummary = {
        date: businessDate,
        totalPaid: selectedDayStats.incomePaid,
        totalLoan: selectedDayStats.dayLoans,
        totalDiscount: selectedDayStats.discounts,
        gameCount: selectedDayStats.totalGames,
      };

      await saveDailySummary(summary);
      await advanceDay(); 

      setIsConfirmingArchive(false);
      setClosureDate(reportDate);
      setClosureGames(reportGames);
      setShowClosureReport(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (e: any) {
      console.error("Échec critique de l'archivage :", e);
      setArchiveError(`ERREUR BASE DE DONNÉES : La colonne "${e.message?.split("'")[1] || 'inconnue'}" est manquante. Veuillez ouvrir les Paramètres (icône engrenage) et exécuter le script de réparation SQL.`);
    } finally {
      setIsArchiving(false);
    }
  };

  const handleArchiveClick = () => {
    if (selectedDayStats.runningCount > 0) {
        alert(`IMPOSSIBLE DE TERMINER : Il reste ${selectedDayStats.runningCount} table(s) active(s). Veuillez terminer toutes les parties d'abord.`);
        return;
    }
    setIsConfirmingArchive(true);
    setArchiveError(null);
  };

  const settleLoan = async (gameId: string) => {
    if (!window.confirm("Marquer cette dette comme réglée ?")) return;
    try {
        await updateGame(gameId, { paymentStatus: PaymentStatus.PAID });
    } catch (e) {
        console.error("Échec du règlement du crédit", e);
    }
  };

  const handleFactoryReset = async () => {
    if (resetPassword !== REQUIRED_RESET_PASSWORD) {
        setResetPasswordError(true);
        return;
    }

    setResetLoading(true);
    try {
        await resetDatabase();
        setShowResetConfirm(false);
        setResetPassword('');
        window.location.reload();
    } finally {
        setResetLoading(false);
    }
  };

  const cancelReset = () => {
    setShowResetConfirm(false);
    setResetPassword('');
    setResetPasswordError(false);
  };

  if (!user) return null;

  if (showClosureReport) {
      return (
        <DailyClosureReport 
            date={closureDate} 
            games={closureGames} 
            onBack={() => setShowClosureReport(false)} 
        />
      );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pt-6">
      <div className="flex flex-col gap-6 border-b pb-8 px-1">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div className="space-y-1">
            <h1 className="text-4xl font-black tracking-tighter uppercase leading-none">Contrôle Admin</h1>
            <p className="text-muted-foreground font-medium text-xs uppercase tracking-widest opacity-70">Gestion du Club & Analyses</p>
          </div>
          <div className="flex items-center gap-2">
             {isLiveDay ? (
                <Badge className="bg-green-600 hover:bg-green-600 animate-pulse border-none px-3 py-1 text-[10px] font-black">SESSION EN DIRECT</Badge>
            ) : (
                <Badge variant="outline" className="text-muted-foreground border-muted-foreground px-3 py-1 text-[10px] font-black">MODE HISTORIQUE</Badge>
            )}
          </div>
        </div>

        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 pt-2">
           <div className="flex items-center gap-2 text-sm">
             <span className="text-muted-foreground">Enregistrements pour :</span>
             <span className="font-bold border-b-2 border-primary/20 pb-0.5">{new Date(selectedDate + 'T00:00:00').toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', year: 'numeric' })}</span>
           </div>

           <div className="flex items-center gap-2 bg-muted/40 p-2 rounded-xl border self-start">
              <span className="text-[10px] font-black uppercase text-muted-foreground px-2">Aller à la date :</span>
              <Input
                  type="date"
                  value={selectedDate}
                  onChange={e => setSelectedDate(e.target.value)}
                  className="w-[160px] bg-background h-8 text-xs font-bold border-none shadow-none focus-visible:ring-0"
              />
           </div>
        </div>
      </div>

      {(gameError || archiveError) && (
        <div className="p-4 bg-destructive/10 border border-destructive/20 rounded-xl text-destructive flex flex-col gap-2 animate-in slide-in-from-top-4">
            <div className="flex items-center gap-3">
                <AlertTriangle className="h-5 w-5 flex-shrink-0"/>
                <span className="text-xs font-black uppercase">Échec de l'opération</span>
            </div>
            <p className="text-xs font-bold pl-8">{archiveError || `Alerte Sync : ${gameError}`}</p>
        </div>
      )}

      <div className="grid gap-4 md:grid-cols-4">
        <KpiCard title="Parties Jouées" value={selectedDayStats.totalGames.toString()} icon={<HashIcon />} />
        <KpiCard title="Revenus Espèces" value={`${selectedDayStats.incomePaid.toFixed(2)}`} icon={<DollarSignIcon />} />
        <KpiCard title="Total Crédits" value={`${selectedDayStats.dayLoans.toFixed(2)}`} icon={<ClockIcon />} />
        <KpiCard title="Dette Globale" value={`${globalOutstandingLoans.toFixed(2)}`} icon={<AlertTriangle className="text-amber-500" />} />
      </div>

      <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          <Card className="lg:col-span-1 shadow-sm border-dashed">
              <CardHeader className="bg-muted/10 pb-4">
                  <CardTitle className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Récapitulatif Financier</CardTitle>
              </CardHeader>
              <CardContent className="grid gap-4 pt-6">
                  <div className="flex items-center justify-between p-3 border-2 border-green-500/10 rounded-xl bg-green-50/30 dark:bg-green-950/10">
                      <span className="text-[10px] font-black uppercase text-green-600/70">Espèces Reçues :</span>
                      <span className="font-black text-green-600">{formatCurrency(selectedDayStats.incomePaid)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border-2 border-amber-500/10 rounded-xl bg-amber-50/30 dark:bg-amber-950/10">
                      <span className="text-[10px] font-black uppercase text-amber-600/70">Crédits Émis :</span>
                      <span className="font-black text-amber-600">{formatCurrency(selectedDayStats.dayLoans)}</span>
                  </div>
                  <div className="flex items-center justify-between p-3 border border-dashed rounded-xl">
                      <span className="text-[10px] font-black uppercase text-muted-foreground">Remises :</span>
                      <span className="font-bold text-muted-foreground">{formatCurrency(selectedDayStats.discounts)}</span>
                  </div>
                  <div className="pt-4 border-t-2 border-zinc-900 dark:border-white mt-2">
                      <div className="flex justify-between items-center px-1">
                          <span className="font-black text-xs uppercase tracking-widest">Total Brut :</span>
                          <span className="text-xl font-black">{formatCurrency(selectedDayStats.incomePaid + selectedDayStats.dayLoans)}</span>
                      </div>
                  </div>
              </CardContent>
          </Card>

          <Card className="lg:col-span-2 border-amber-200 dark:border-amber-900/50 shadow-md">
              <CardHeader className="flex flex-row items-center justify-between bg-amber-50/50 dark:bg-amber-950/10 pb-4">
                  <div>
                    <CardTitle className="flex items-center gap-2 text-amber-700 dark:text-amber-400 text-xs font-black uppercase tracking-widest">
                        <ClockIcon className="h-4 w-4" />
                        Suivi des Dettes
                    </CardTitle>
                  </div>
                  <Badge className="bg-amber-500 font-bold text-[10px]">{allLoansList.length} Crédits Actifs</Badge>
              </CardHeader>
              <CardContent className="h-[280px] overflow-y-auto pt-4">
                  {allLoansList.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {allLoansList.map((loan) => (
                            <div key={loan.id} className="flex items-center justify-between p-3 rounded-xl bg-muted/30 border border-transparent hover:border-amber-500/30 transition-all">
                                <div className="grid gap-0.5">
                                    <span className="font-black text-xs text-foreground uppercase tracking-tight">
                                        {getDebtorName(loan)}
                                    </span>
                                    <div className="flex items-center gap-2 text-[10px] text-muted-foreground">
                                        <span className="font-bold text-amber-600/80">{loan.tableName}</span>
                                        <span>•</span>
                                        <span>{new Date(loan.date + 'T00:00:00').toLocaleDateString('fr-FR')}</span>
                                    </div>
                                </div>
                                <div className="flex items-center gap-3">
                                    <span className="font-bold text-sm text-amber-600">{formatCurrency(loan.finalPriceMAD)}</span>
                                    <Button size="icon" variant="ghost" className="h-7 w-7 text-green-600 hover:bg-green-500/10 rounded-full" onClick={() => settleLoan(loan.id)}>
                                        <CheckCircle className="h-4 w-4" />
                                    </Button>
                                </div>
                            </div>
                        ))}
                    </div>
                  ) : (
                    <div className="flex flex-col items-center justify-center h-full text-muted-foreground gap-2 opacity-50">
                        <CheckCircle className="h-12 w-12" />
                        <p className="text-[10px] font-black uppercase tracking-widest">Aucune dette en cours</p>
                    </div>
                  )}
              </CardContent>
          </Card>
      </div>

      <div className="space-y-4">
        <h2 className="text-xl font-black uppercase tracking-tighter border-b pb-4">Aperçu des Performances</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            <AnalyticsCard title="Meilleurs Gagnants" icon={<TrophyIcon className="text-yellow-500" />}>
                {analyticsData.topWinners.length > 0 ? (
                    analyticsData.topWinners.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-xs py-2 border-b border-dashed last:border-b-0">
                            <span className="font-bold uppercase">{player.name}</span>
                            <span className="bg-primary/10 px-2 py-0.5 rounded text-[10px] font-black">{player.wins} VICTOIRES</span>
                        </div>
                    ))
                ) : (
                    <p className="text-[10px] text-muted-foreground italic py-4">Pas encore de données.</p>
                )}
            </AnalyticsCard>

            <AnalyticsCard title="Top Revenus" icon={<DollarSignIcon className="text-green-500" />}>
                    {analyticsData.topPaid.length > 0 ? (
                    analyticsData.topPaid.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-xs py-2 border-b border-dashed last:border-b-0">
                            <span className="font-bold uppercase">{player.name}</span>
                            <span className="font-black text-green-600">{formatCurrency(player.paid)}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-[10px] text-muted-foreground italic py-4">Pas encore de données.</p>
                )}
            </AnalyticsCard>

            <AnalyticsCard title="Plus Gros Débiteurs" icon={<UsersIcon className="text-red-500" />}>
                {analyticsData.playersWithLoans.length > 0 ? (
                    analyticsData.playersWithLoans.map((player, index) => (
                        <div key={index} className="flex justify-between items-center text-xs py-2 border-b border-dashed last:border-b-0">
                            <span className="font-bold uppercase">{player.name}</span>
                            <span className="font-black text-destructive">{formatCurrency(player.loan)}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-[10px] text-muted-foreground italic py-4">Les comptes sont à jour.</p>
                )}
            </AnalyticsCard>
        </div>
      </div>

      <div className="space-y-4">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4 border-b pb-4">
            <h2 className="text-xl font-black uppercase tracking-tighter">Journal d'Activité</h2>
            <div className="flex flex-wrap items-center gap-2">
                <PrintResumeButton games={filteredGames} selectedDate={selectedDate} />

                {isLiveDay && (
                    <div className="flex flex-col sm:flex-row items-center gap-2">
                        {isConfirmingArchive ? (
                            <div className="flex flex-col items-center gap-4 p-5 bg-primary text-primary-foreground rounded-2xl shadow-2xl animate-in fade-in zoom-in border-4 border-white dark:border-zinc-800">
                                <div className="text-center space-y-1">
                                    <p className="text-[10px] font-black uppercase tracking-[0.2em] mb-2 opacity-80">Confirmation Finale</p>
                                    <p className="text-xs font-black uppercase leading-tight">Toutes les données seront archivées. Continuer ?</p>
                                </div>
                                <div className="flex gap-2 w-full mt-2">
                                    <Button 
                                        size="sm" 
                                        variant="secondary"
                                        className="flex-1 h-12 font-black uppercase tracking-wider text-[11px] shadow-sm active:scale-95" 
                                        onClick={performArchive}
                                        disabled={isArchiving}
                                    >
                                        {isArchiving ? <LoaderCircle className="h-3 w-3 animate-spin mr-1"/> : "Oui, Terminer"}
                                    </Button>
                                    <Button 
                                        size="sm" 
                                        variant="outline" 
                                        className="flex-1 h-12 font-black uppercase tracking-wider text-[11px] bg-transparent border-white/20 text-white hover:bg-white/10"
                                        onClick={() => setIsConfirmingArchive(false)}
                                        disabled={isArchiving}
                                    >
                                        Annuler
                                    </Button>
                                </div>
                            </div>
                        ) : (
                            <Button 
                                type="button"
                                onClick={handleArchiveClick} 
                                className="bg-primary hover:bg-primary/90 font-black uppercase tracking-widest px-8 shadow-2xl transition-all active:scale-95 border-none h-12"
                            >
                                Fin de Session & Archiver
                            </Button>
                        )}
                    </div>
                )}
            </div>
        </div>
        <GamesTable 
            games={filteredGames} 
            isAdmin={true} 
            updateGame={updateGame} 
            deleteGame={deleteGame}
            currentUserId={user.id}
        />
      </div>

      <div className="pt-12 border-t">
        <h2 className="text-xl font-black uppercase tracking-tighter mb-6">Gestion des Utilisateurs</h2>
        <UserManagement />
      </div>

      {/* ZONE DE DANGER : Réinitialisation */}
      <div className="pt-16">
        <div className="bg-destructive/5 border-2 border-destructive/20 rounded-3xl p-8 space-y-6">
            <div className="flex items-center gap-4">
                <div className="h-12 w-12 rounded-full bg-destructive flex items-center justify-center text-white shadow-lg">
                    <AlertTriangle className="h-6 w-6" />
                </div>
                <div>
                    <h3 className="text-xl font-black uppercase tracking-tight text-destructive">Zone de Danger</h3>
                    <p className="text-xs font-bold text-muted-foreground uppercase opacity-80">Actions critiques du système</p>
                </div>
            </div>

            <div className="flex flex-col md:flex-row items-center justify-between gap-6 p-6 bg-background rounded-2xl border border-destructive/10">
                <div className="space-y-1">
                    <p className="font-black text-sm uppercase">Réinitialisation d'usine (Garder utilisateurs)</p>
                    <p className="text-xs text-muted-foreground leading-relaxed">
                        Ceci supprimera définitivement <span className="text-destructive font-black">TOUT L'HISTORIQUE DES JEUX</span> et <span className="text-destructive font-black">TOUS LES RÉSUMÉS QUOTIDIENS</span>. 
                        Vos comptes utilisateurs et le personnel du club seront préservés.
                    </p>
                </div>

                {showResetConfirm ? (
                    <div className="flex flex-col gap-3 w-full md:w-auto min-w-[280px] animate-in slide-in-from-right-4">
                        <div className="space-y-1">
                            <label className="text-[10px] font-black uppercase tracking-widest text-destructive ml-1">Code de sécurité requis</label>
                            <Input 
                                type="password" 
                                placeholder="Entrez le code" 
                                value={resetPassword}
                                onChange={(e) => {
                                    setResetPassword(e.target.value);
                                    setResetPasswordError(false);
                                }}
                                className={`h-11 font-black text-center ${resetPasswordError ? 'border-destructive ring-destructive text-destructive' : ''}`}
                            />
                            {resetPasswordError && <p className="text-[9px] font-bold text-destructive uppercase text-center mt-1 animate-bounce">Code incorrect</p>}
                        </div>
                        <div className="flex flex-col gap-2">
                            <Button 
                                variant="destructive" 
                                className="font-black uppercase tracking-widest h-12 shadow-xl"
                                disabled={resetLoading || resetPassword !== REQUIRED_RESET_PASSWORD}
                                onClick={handleFactoryReset}
                            >
                                {resetLoading ? <LoaderCircle className="h-4 w-4 animate-spin mr-2" /> : "OUI, TOUT SUPPRIMER"}
                            </Button>
                            <Button 
                                variant="outline" 
                                className="text-[10px] font-black uppercase h-10"
                                onClick={cancelReset}
                                disabled={resetLoading}
                            >
                                Annuler
                            </Button>
                        </div>
                    </div>
                ) : (
                    <Button 
                        variant="outline" 
                        className="border-destructive text-destructive hover:bg-destructive hover:text-white font-black uppercase tracking-widest px-8 h-12 transition-all"
                        onClick={() => setShowResetConfirm(true)}
                    >
                        Réinitialiser les données
                    </Button>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

export default AdminPage;

import React, { useState, useMemo } from 'react';
import { useAuth } from '../hooks/useAuth';
import { useGames } from '../hooks/useGames';
import { useBusinessDay } from '../hooks/useBusinessDay';
import GamesTable from '../components/GamesTable';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';
import { Select } from '../components/ui/Select';
import { Card, CardContent, CardHeader, CardTitle } from '../components/ui/Card';
import { TABLES, DEFAULT_HOURLY_RATE } from '../constants';
import { GameStatus, PaymentStatus, Game } from '../types';
import { AlertTriangle, ClockIcon, CheckCircle, UsersIcon } from '../components/icons';
import { Badge } from '../components/ui/Badge';
import { formatCurrency } from '../lib/utils';

const DashboardPage: React.FC = () => {
  const { user } = useAuth();
  const { games, addGame, updateGame, isTableMissing } = useGames();
  const { businessDate } = useBusinessDay();
  const [player1, setPlayer1] = useState('');
  const [player2, setPlayer2] = useState('');
  const [selectedTableId, setSelectedTableId] = useState('');

  const busyTableNames = useMemo(() => {
    return games
      .filter(g => g.status === GameStatus.RUNNING)
      .map(g => g.tableName);
  }, [games]);

  const handleStartGame = () => {
    if (!player1 || !user) {
      alert('Le nom du joueur 1 est requis.');
      return;
    }

    if (!selectedTableId) {
      alert('Veuillez sélectionner une table.');
      return;
    }

    const tableConfig = TABLES.find(t => t.id === selectedTableId);
    const tableName = tableConfig ? tableConfig.name : 'Inconnue';
    const hourlyRate = tableConfig ? tableConfig.rate : DEFAULT_HOURLY_RATE;

    const isTableBusy = games.some(g => g.tableName === tableName && g.status === GameStatus.RUNNING);

    if (isTableBusy) {
      alert(`La table "${tableName}" est déjà occupée.`);
      return;
    }

    addGame({
      date: businessDate,
      tableName: tableName,
      hourlyRate: hourlyRate,
      startTime: new Date().toISOString(),
      endTime: null,
      player1,
      player2: player2 || null,
      winner: null,
      status: GameStatus.RUNNING,
      durationSeconds: null,
      priceMAD: null,
      discountMAD: 0,
      finalPriceMAD: null,
      paymentStatus: PaymentStatus.PENDING,
      notes: null,
      createdBy: user.id,
      modifiedBy: null,
    });

    setPlayer1('');
    setPlayer2('');
    setSelectedTableId('');
  };

  const getDebtorName = (loan: Game) => {
    if (!loan.player2) return loan.player1;
    if (loan.winner === loan.player1) return loan.player2;
    if (loan.winner === loan.player2) return loan.player1;
    return loan.player1;
  };

  const allLoansList = useMemo(() => {
    return games
