import { useCallback, useState, useEffect } from 'react';

export const useNotifications = () => {
  const [permission, setPermission] = useState<NotificationPermission>('default');

  useEffect(() => {
    if ('Notification' in window) {
      setPermission(Notification.permission);
    }
  }, []);

  const requestPermission = useCallback(async () => {
    if (!('Notification' in window)) {
      console.warn("Ce navigateur ne supporte pas les notifications de bureau.");
      return false;
    }

    const result = await Notification.requestPermission();
    setPermission(result);
    return result === 'granted';
  }, []);

  const sendNotification = useCallback((title: string, body: string) => {
    if (Notification.permission === 'granted') {
      try {
        const n = new Notification(title, {
          body,
          icon: '/vite.svg', // Fallback icon
          badge: '/vite.svg',
          vibrate: [200, 100, 200]
        });

        // Mobile browsers often require the app to be in background or a service worker
        // but modern browsers will show this if the tab is open or recently active.
        n.onclick = () => {
          window.focus();
          n.close();
        };
      } catch (e) {
        console.error("Erreur lors de l'envoi de la notification:", e);
      }
    }
  }, []);

  return { permission, requestPermission, sendNotification };
};

import React, { useEffect, useRef } from 'react';
import { useGames } from '../hooks/useGames';
import { useNotifications } from '../hooks/useNotifications';
import { GameStatus } from '../types';

const THRESHOLD_SECONDS = 20 * 60; // 20 minutes

const NotificationWatcher: React.FC = () => {
  const { games } = useGames();
  const { sendNotification, requestPermission } = useNotifications();
  const notifiedGames = useRef<Set<string>>(new Set());

  // Request permission on mount
  useEffect(() => {
    requestPermission();
  }, [requestPermission]);

  useEffect(() => {
    const checkGames = () => {
      const now = Date.now();

      games.forEach(game => {
        if (game.status === GameStatus.RUNNING) {
          const startTime = new Date(game.startTime).getTime();
          const elapsedSeconds = Math.floor((now - startTime) / 1000);

          if (elapsedSeconds >= THRESHOLD_SECONDS && !notifiedGames.current.has(game.id)) {
            // Trigger notification
            sendNotification(
              "Alerte Temps Snooker", 
              `La partie sur la table "${game.tableName}" (${game.player1}) a dépassé 20 minutes !`
            );

            // Mark as notified so we don't spam
            notifiedGames.current.add(game.id);
          }
        } else {
          // If game is finished, remove from tracking set to free memory
          if (notifiedGames.current.has(game.id)) {
            notifiedGames.current.delete(game.id);
          }
        }
      });
    };

    // Check every 30 seconds
    const interval = setInterval(checkGames, 30000);
    return () => clearInterval(interval);
  }, [games, sendNotification]);

  return null; // Silent background component
};

export default NotificationWatcher;

